// Permissions bootstrap — migrate existing team to bundles on first load
(function migrateUsersToBundles() {
  // Detect stale bundles (old permission keys) and refresh to new DEFAULT_BUNDLES
  // Check Master Admin bundle for the presence of old 'admin.edit_users' (without suffix)
  const stale = state.bundles?.master_admin?.permissions?.includes('admin.edit_users');
  if (stale) {
    state.bundles = JSON.parse(JSON.stringify(DEFAULT_BUNDLES));
    save('vi_bundles', state.bundles);
  }
  // Ensure the Install Manager can assign every role slot (sales/design/pm added later).
  if (state.bundles?.install_admin?.permissions) {
    const needAssign = ['projects.assign_team.sales','projects.assign_team.design','projects.assign_team.pm'];
    const iaPerms = state.bundles.install_admin.permissions;
    let addedAssign = false;
    needAssign.forEach(pk => { if (!iaPerms.includes(pk)) { iaPerms.push(pk); addedAssign = true; } });
    if (addedAssign) save('vi_bundles', state.bundles);
  }
  // One-time cleanup of calendar.view_all (introduced and removed in v1.43)
  // Strip from all bundles + user perms if present
  let cleanedCalendarPerm = false;
  Object.keys(state.bundles || {}).forEach(bk => {
    const perms = state.bundles[bk]?.permissions;
    if (Array.isArray(perms)) {
      const before = perms.length;
      state.bundles[bk].permissions = perms.filter(p => p !== 'calendar.view_all');
      if (state.bundles[bk].permissions.length !== before) cleanedCalendarPerm = true;
    }
  });
  if (cleanedCalendarPerm) save('vi_bundles', state.bundles);
  Object.keys(state.userPermissions || {}).forEach(uid => {
    const up = state.userPermissions[uid];
    if (up?.add?.includes('calendar.view_all')) {
      up.add = up.add.filter(p => p !== 'calendar.view_all');
      cleanedCalendarPerm = true;
    }
    if (up?.remove?.includes('calendar.view_all')) {
      up.remove = up.remove.filter(p => p !== 'calendar.view_all');
      cleanedCalendarPerm = true;
    }
  });
  if (cleanedCalendarPerm) save('vi_user_perms', state.userPermissions);

  let changed = false;
  const roleToBundle = {
    'admin': 'master_admin',
    'sales': 'sales',
    'design': 'designer',
    'project_manager': 'project_manager',
    'installer': 'installer'
  };
  state.team.forEach(m => {
    if (!state.userPermissions[m.id]) {
      if (m.id === 1 || m.name === 'Jacob') {
        state.userPermissions[m.id] = { bundle: 'master_admin', overrides: {} };
      } else {
        const bundleKey = roleToBundle[m.primaryRole] || 'installer';
        state.userPermissions[m.id] = { bundle: bundleKey, overrides: {} };
      }
      changed = true;
    }
    // Clear stale permission overrides using old keys
    if (state.userPermissions[m.id].overrides) {
      const oldKeys = ['admin.edit_users','projects.assign_team'];
      oldKeys.forEach(k => {
        if (k in state.userPermissions[m.id].overrides) {
          delete state.userPermissions[m.id].overrides[k];
          changed = true;
        }
      });
    }
  });
  if (changed) save('vi_user_perms', state.userPermissions);
})();

function getTeamMember(id) {
  return state.team.find(m => m.id === id);
}

function getTeamByAccess(accessKey) {
  return state.team.filter(m => m.access.includes(accessKey) || m.access.includes('admin'));
}

function getInitials(name) {
  if (!name) return '';
  const words = name.trim().split(/\s+/).filter(Boolean);
  if (words.length === 0) return '';
  if (words.length === 1) {
    // Single-word name (e.g. "Jacob") — use its first two letters ("Ja")
    return words[0].slice(0, 2).toUpperCase();
  }
  // Multi-word — first letter of the first two words ("Clint Cowley" -> "CC")
  return (words[0][0] + words[1][0]).toUpperCase();
}

function hasAccess(memberId, accessKey) {
  const m = getTeamMember(memberId);
  if (!m) return false;
  return m.access.includes('admin') || m.access.includes(accessKey);
}

function addTeamMember(name, access, primaryRole, email, phone) {
  const id = state.team.length > 0 ? Math.max(...state.team.map(m => m.id)) + 1 : 1;
  state.team.push({
    id, name, access: access || ['installer'], primaryRole: primaryRole || access[0] || 'installer',
    email: email || '', phone: phone || '', initials: getInitials(name), status: 'pending'
  });
  save('vi_team', state.team);
}

function removeTeamMember(id) {
  const member = getTeamMember(id);
  if (member && member.name === currentUserName) {
    alert('Cannot remove the currently active user. Switch to another user first.');
    return;
  }
  state.team = state.team.filter(m => m.id !== id);
  save('vi_team', state.team);
  _syncTeamNow({ toast: true });
}

function switchUser(memberId) {
  if (!canSwitchUsers()) return; // only a master-admin login may switch users
  const member = getTeamMember(memberId);
  if (!member) return;
  currentUserName = member.name;
  currentUserRole = member.primaryRole || member.access[0] || 'installer';
  localStorage.setItem('vi_user', member.name);
  localStorage.setItem('vi_role', currentUserRole);
  sessionStorage.setItem('vi_active_member', memberId); // device + session local — the "viewing as" switch must NOT sync across devices

  const userAvatar = document.querySelector('.user-avatar');
  const userName = document.querySelector('.user-name');
  const userRole = document.querySelector('.user-role');
  if (userAvatar) userAvatar.textContent = member.initials || getInitials(member.name);
  if (userName) userName.textContent = member.name;
  if (userRole) {
    const da = DASHBOARD_ACCESS.find(r => r.key === currentUserRole);
    userRole.textContent = da?.label || currentUserRole;
  }

  const sel = document.getElementById('role-select');
  if (sel) sel.value = memberId;

  state.dashboardView = member.primaryRole || member.access[0];

  // Re-evaluate nav visibility (Team/Admin show/hide based on new user)
  document.querySelector('[data-page="team"]')?.remove();
  document.querySelector('[data-page="admin"]')?.remove();
  if (typeof refreshAdminNav === 'function') refreshAdminNav();

  renderCurrentPage();
}

// ── Logged-in identity → team member binding ──
// Maps the Supabase auth email (set by the bootstrap as window.VI_AUTH_EMAIL)
// to a team member via the member's email field. Normal users are pinned to
// their own member; only a master-admin login may switch/impersonate.
function getAuthMemberId() {
  const email = (window.VI_AUTH_EMAIL || '').trim().toLowerCase();
  if (!email) return null;
  const m = (state.team || []).find(t => (t.email || '').trim().toLowerCase() === email);
  return m ? m.id : null;
}
function isMasterAdminLogin() {
  const id = getAuthMemberId();
  if (id == null) return false;
  const up = state.userPermissions[id];
  if (up && up.bundle === 'master_admin') return true;
  return hasPermission(id, 'admin.system');
}
// May this login switch users? Master admins can. Logins not yet linked to a
// team member (no matching email) also can, so the owner isn't locked out
// while setting up email mappings.
function canSwitchUsers() {
  return isMasterAdminLogin(); // strictly master-admin; unlinked logins do NOT get the switcher
}
function getActiveTeamMemberId() {
  const authId = getAuthMemberId();
  if (authId != null) {
    if (!canSwitchUsers()) return authId;             // non-admin: pinned to their own member
    const stored = parseInt(sessionStorage.getItem('vi_active_member'));
    return stored || authId;                           // master admin may sandbox another member
  }
  // No team member matches this login.
  if ((window.VI_AUTH_EMAIL || '').trim()) return null; // SECURITY: unlinked login gets NO identity (locked out) — never fall back to the owner
  // No login email at all (local/offline dev) → legacy fallback so the owner isn't bricked.
  const stored = parseInt(sessionStorage.getItem('vi_active_member'));
  return stored || state.team[0]?.id || 1;
}

// True when someone is logged in but their email matches no team member.
function _isUnlinkedLogin() {
  if (!Array.isArray(state.team) || state.team.length === 0) return false; // team not loaded yet — don't lock
  return getAuthMemberId() == null && !!(window.VI_AUTH_EMAIL || '').trim();
}

// Full-screen lock for an unlinked login — shows instead of any account data.
function _renderUnlinkedLock() {
  const email = (window.VI_AUTH_EMAIL || '').trim();
  let el = document.getElementById('vi-unlinked-lock');
  if (!el) { el = document.createElement('div'); el.id = 'vi-unlinked-lock'; document.body.appendChild(el); }
  el.setAttribute('style', 'position:fixed;inset:0;z-index:99999;background:#0D1117;display:flex;align-items:center;justify-content:center;padding:24px;text-align:center');
  el.innerHTML = `
    <div style="max-width:420px">
      <div style="width:54px;height:54px;border-radius:50%;background:#21262D;border:1px solid #30363D;display:flex;align-items:center;justify-content:center;margin:0 auto 16px">
        <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="#8B949E" stroke-width="1.8"><rect x="4" y="10" width="16" height="11" rx="2"/><path d="M8 10V7a4 4 0 0 1 8 0v3"/></svg>
      </div>
      <div style="font-size:18px;font-weight:600;color:#E6EDF3;margin-bottom:8px">Account not set up</div>
      <div style="font-size:14px;color:#8B949E;line-height:1.5;margin-bottom:6px">This login isn't linked to a team member yet, so there's nothing to show here.</div>
      <div style="font-size:13px;color:#6E7681;margin-bottom:20px">Ask your administrator to add <span style="color:#C9D1D9">${esc(email)}</span> as a team member with this exact email.</div>
      <button onclick="(window.viSignOut ? window.viSignOut() : location.reload())" style="background:#21262D;border:1px solid #30363D;color:#E6EDF3;font-size:14px;font-family:'DM Sans',sans-serif;padding:10px 22px;border-radius:8px;cursor:pointer;-webkit-tap-highlight-color:transparent">Log out</button>
    </div>`;
}

// Diagnostic: explains how the current device resolved "who am I". Temporary aid
// for debugging DM delivery / unread issues. Also on window as viWhoAmI().
function _identityDiag() {
  const authEmail = (window.VI_AUTH_EMAIL || '').trim().toLowerCase();
  const authId = getAuthMemberId();
  const resolvedId = getActiveTeamMemberId();
  const m = getTeamMember(resolvedId);
  let via, warn = false;
  if (authId != null && resolvedId === authId) via = 'matched by email';
  else if (authId != null && resolvedId !== authId) via = 'viewing as (switched)';
  else if (authEmail) { via = 'NO email match — fell back to list'; warn = true; }
  else { via = 'no login email — fell back to list'; warn = true; }
  return { authEmail, authId, resolvedId, name: (m && m.name) || '(unknown)', via, warn };
}
window.viWhoAmI = function () { const d = _identityDiag(); console.log(d); return d; };

// ── Admin sandbox ──
// The "Admin" dropdown entry shows EVERY dashboard tab (a holding area for
// work-in-progress views). Normal selections show the clean day-to-day set.
let _adminSandbox = localStorage.getItem('vi_admin_sandbox') === '1';
function isAdminSandbox() { return _adminSandbox; }
function setAdminSandbox(on, render) {
  _adminSandbox = !!on;
  localStorage.setItem('vi_admin_sandbox', on ? '1' : '0');
  if (!on && !['mine', 'project_health'].includes(state.dashboardMode)) {
    state.dashboardMode = 'mine';
    localStorage.setItem('vi_dashboard_mode', 'mine');
  }
  if (render !== false) renderCurrentPage();
}

