// ── Auto-detect systems from scope text ──
function detectSystems(text) {
  if (!text) return [];
  const t = text.toLowerCase();
  const systems = [];
  if (t.includes('led') || t.includes('video wall') || t.includes('led wall') || t.includes('display wall')) systems.push('led_wall');
  if (t.includes('pa ') || t.includes('audio') || t.includes('speaker') || t.includes('microphone') || t.includes('sound system') || t.includes('amp') || t.includes('dsp')) systems.push('pa_install');
  if (t.includes('light') || t.includes('fixture') || t.includes('dmx') || t.includes('stage light') || t.includes('key light')) systems.push('lighting');
  if (t.includes('control') || t.includes('qsys') || t.includes('q-sys') || t.includes('crestron') || t.includes('extron') || t.includes('amx') || t.includes('automation')) systems.push('control');
  if (t.includes('stream') || t.includes('broadcast') || t.includes('encoder') || t.includes('vmix') || t.includes('tricaster') || t.includes('switcher') || t.includes('video produc')) systems.push('streaming');
  if (t.includes('camera') || t.includes('ptz') || t.includes('cam ') || t.includes('video camera') || t.includes('imag')) systems.push('camera');
  return systems;
}

// ── Helpers ──
function fmt(n) {
  if (n == null || isNaN(n)) return '$0';
  return '$' + Number(n).toLocaleString('en-US', { minimumFractionDigits: 0, maximumFractionDigits: 0 });
}

function fmtDate(d) {
  if (!d) return '—';
  // Parse date-only / date-prefixed strings as LOCAL (avoids the UTC day-shift).
  let dt;
  if (typeof d === 'string' && /^\d{4}-\d{2}-\d{2}/.test(d.trim())) {
    dt = _parseLocalYmd(d);
  } else {
    dt = new Date(d);
  }
  if (!dt || isNaN(dt)) return '—';
  return dt.toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' });
}

function shortDate(d) {
  if (!d) return '';
  // Date-only YYYY-MM-DD strings must be parsed as LOCAL, not UTC — otherwise a
  // booked window shows a day early in timezones west of UTC (e.g. Mountain).
  let dt;
  if (typeof d === 'string' && /^\d{4}-\d{2}-\d{2}/.test(d.trim())) {
    dt = _parseLocalYmd(d);
  } else {
    dt = new Date(d);
  }
  if (!dt || isNaN(dt)) return '';
  return dt.toLocaleDateString('en-US', { month: 'short', day: 'numeric' });
}

function systemTagHTML(sys) {
  const map = {
    led_wall:   ['LED Wall',   'tag-led'],
    pa_install: ['Audio/PA',   'tag-audio'],
    lighting:   ['Lighting',   'tag-lighting'],
    control:    ['Control',    'tag-control'],
    streaming:  ['Streaming',  'tag-streaming'],
    video:      ['Video',      'tag-video'],
    camera:     ['Camera',     'tag-camera']
  };
  const [label, cls] = map[sys] || [sys, 'tag-audio'];
  return `<span class="tag ${cls}">${label}</span>`;
}

function save(key, val) {
  localStorage.setItem(key, JSON.stringify(val));
}

function esc(s) {
  if (!s) return '';
  const d = document.createElement('div');
  d.textContent = s;
  return d.innerHTML;
}

// ── Timeline Helpers (Estimated vs. Booked) ──
function getProjectDates(project) {
  if (state.timelineMode === 'booked') {
    const booked = state.bookedDates[project.id];
    if (booked?.start) return { start: booked.start, end: booked.end || null, source: 'booked' };
  }
  return { start: project.start_date || null, end: project.end_date || null, source: 'estimated' };
}

function setBookedDates(projectId, start, end, opts) {
  if (!start) {
    delete state.bookedDates[projectId];
  } else {
    const entry = { start, end: end || '' };
    if (opts) {
      if (opts.excludeWeekends !== undefined) entry.excludeWeekends = !!opts.excludeWeekends;
      if (Array.isArray(opts.weekendIncludes)) entry.weekendIncludes = [...opts.weekendIncludes];
    }
    state.bookedDates[projectId] = entry;
  }
  _syncKeyNow('vi_booked_dates', state.bookedDates).then(r => {
    if (!r.ok) showToast('Install window didn\u2019t save: ' + r.err + ' \u2014 try again', 'error');
  });
}

function toggleTimelineMode() {
  state.timelineMode = state.timelineMode === 'estimated' ? 'booked' : 'estimated';
  localStorage.setItem('vi_timeline_mode', state.timelineMode);
  renderCurrentPage();
}

function hasBookedDates(projectId) {
  return !!(state.bookedDates[projectId]?.start);
}

function fmtDateRange(start, end) {
  if (!start) return '—';
  const s = shortDate(start);
  const e = end ? shortDate(end) : null;
  return e ? `${s} – ${e}` : s;
}

function getBookedTimeline(projectId) {
  const b = state.bookedDates[projectId];
  return (b && b.start) ? b : null;
}

function getInstallDateDisplay(project) {
  const booked = getBookedTimeline(project.id);
  if (state.timelineMode === 'booked') {
    if (booked) {
      const end = booked.end && booked.end !== booked.start ? ' – ' + shortDate(booked.end) : '';
      return { label: 'Booked', value: shortDate(booked.start) + end, color: '#3FB950' };
    }
    if (project.start_date) {
      return { label: 'Est.', value: shortDate(project.start_date), color: '#6E7681' };
    }
    return { label: 'Booked', value: 'Not set', color: '#6E7681' };
  }
  if (project.start_date) {
    const end = project.end_date ? ' – ' + shortDate(project.end_date) : '';
    return { label: 'Est.', value: shortDate(project.start_date) + end, color: '#8B949E' };
  }
  return { label: 'Est.', value: 'Not set', color: '#6E7681' };
}

// Edit permission for install window (booked + estimated dates).
// As of v1.43:
//   - PM lead of THIS project can edit
//   - Master Admin / admin.system can edit
//   - Lead Installer can REQUEST changes (Round 2 — pending approval flow)
//   - Anyone else: read-only
// During mobilization (project still in Sales' mobilization queue), members
// with assign_team perms can also set the initial estimated window.
function canEditInstallWindow(projectId) {
  // Master Admin / system override
  if (currentUserHasPermission('admin.system')) return true;
  // Logistics override — can edit anyone's install windows directly
  if (currentUserHasPermission('calendar.edit_all_events')) return true;
  const viewerId = getActiveTeamMemberId();
  const a = getProjectAssignment(projectId);
  // PM lead of this project
  const pmLead = (a.pm || []).find(x => x.lead);
  if (pmLead && pmLead.id === viewerId) return true;
  // During mobilization — anyone with assign_team perms can finalize the
  // initial estimated install window (they're getting the project off the ground)
  const p = state.projects.find(x => x.id === projectId);
  if (p && p.stage === 'contract' && !isMobilizationComplete(projectId)) {
    if (currentUserHasPermission('assign_team.pm')) return true;
    if (currentUserHasPermission('assign_team.sales')) return true;
  }
  return false;
}

// Any assigned install crew member (lead or not) can REQUEST a change to a
// booked install window. The PM lead (or Master Admin) approves. This is the
// gate for the request-and-approval flow (Part C). People who can edit directly
// (PM lead, Master Admin) don't go through here — they edit outright.
function canRequestInstallWindowChange(projectId) {
  const viewerId = getActiveTeamMemberId();
  const a = getProjectAssignment(projectId);
  return (a.install || []).some(x => x.id === viewerId);
}

// ── Install window change requests (Part C) ──
// When an installer (not PM lead / Master Admin) wants to move a booked
// install window, the change is captured as a pending request keyed by project
// id rather than applied immediately. The PM lead (or Master Admin) approves or
// denies via the Pending Approvals widget. One pending request per project — a
// new request replaces any prior unresolved one.
//
// Shape: state.installChangeRequests[projectId] = {
//   projectId, requestedStart, requestedEnd, requestedExcludeWeekends,
//   requestedWeekendIncludes, currentStart, currentEnd,
//   requestedBy (memberId), requestedAt (ISO), note
// }

function getInstallChangeRequest(projectId) {
  return state.installChangeRequests?.[projectId] || null;
}

function hasPendingInstallChange(projectId) {
  return !!getInstallChangeRequest(projectId);
}

function createInstallChangeRequest(projectId, requested) {
  if (!state.installChangeRequests) state.installChangeRequests = {};
  const p = state.projects.find(x => x.id === projectId);
  const current = getInstallWindow(p) || {};
  state.installChangeRequests[projectId] = {
    projectId,
    requestedStart: requested.start,
    requestedEnd: requested.end || requested.start,
    requestedExcludeWeekends: requested.excludeWeekends !== false,
    requestedWeekendIncludes: Array.isArray(requested.weekendIncludes) ? [...requested.weekendIncludes] : [],
    currentStart: current.start || null,
    currentEnd: current.end || null,
    requestedBy: getActiveTeamMemberId(),
    requestedAt: new Date().toISOString(),
    note: requested.note || ''
  };
  save('vi_install_change_requests', state.installChangeRequests);
  _pushNotifyInstallApproval(projectId);
}

// Who can approve a given project's pending install change: PM lead or Master Admin.
function canApproveInstallChange(projectId) {
  if (currentUserHasPermission('admin.system')) return true;
  const viewerId = getActiveTeamMemberId();
  const a = getProjectAssignment(projectId);
  const pmLead = (a.pm || []).find(x => x.lead);
  return !!(pmLead && pmLead.id === viewerId);
}

function approveInstallChangeRequest(projectId) {
  const req = getInstallChangeRequest(projectId);
  if (!req) return;
  if (!canApproveInstallChange(projectId)) {
    showToast('Only the project PM can approve schedule changes', 'info');
    return;
  }
  // Apply the requested dates to the booked window.
  setBookedDates(projectId, req.requestedStart, req.requestedEnd, {
    excludeWeekends: req.requestedExcludeWeekends,
    weekendIncludes: req.requestedWeekendIncludes
  });
  delete state.installChangeRequests[projectId];
  save('vi_install_change_requests', state.installChangeRequests);
  showToast('Schedule change approved — install window updated', 'success');
  renderCurrentPage();
}

function denyInstallChangeRequest(projectId) {
  if (!canApproveInstallChange(projectId)) {
    showToast('Only the project PM can deny schedule changes', 'info');
    return;
  }
  if (!state.installChangeRequests?.[projectId]) return;
  delete state.installChangeRequests[projectId];
  save('vi_install_change_requests', state.installChangeRequests);
  showToast('Schedule change denied', 'info');
  renderCurrentPage();
}

// All pending install-change requests the current user is allowed to approve.
function getInstallChangesAwaitingMyApproval() {
  const out = [];
  Object.keys(state.installChangeRequests || {}).forEach(pidStr => {
    const pid = Number(pidStr);
    if (canApproveInstallChange(pid)) {
      const req = state.installChangeRequests[pidStr];
      if (req) out.push(req);
    }
  });
  return out;
}

// ════════════════════════════════════════════════════════════════════════════
// INSTALL TASKS — unified task + template system
// ────────────────────────────────────────────────────────────────────────────
// A task belongs to a job (projectId) OR shop work (shopWork:true). It may be
// linked to a system (scope tag) and is either an assigned work task or a
// milestone reminder (no assignee, due date). A master task's date range is
// DERIVED from its subtasks' dates (not stored). Subtasks can be assigned to
// multiple people and are pinned to a specific day.
//
// Shape: {
//   id, projectId|null, shopWork:bool, system|null, title,
//   assigneeIds:[], isMilestone:bool, dueDate:string|null, done:bool,
//   subtasks: [ { id, title, date, assigneeIds:[], notes, done } ],
//   templateKey|null, createdAt
// }
// ════════════════════════════════════════════════════════════════════════════

function _nextTaskId() {
  const all = [...(state.installTasks || []), ...(state.designTasks || [])];
  let max = 0;
  all.forEach(t => {
    if (t.id > max) max = t.id;
    (t.subtasks || []).forEach(s => { if (s.id > max) max = s.id; });
  });
  return max + 1;
}

// ── Role bundle migration ──
// Ensures the three new bundles (system_architect, project_coordinator,
// install_assistant) exist in state.bundles even when the user already has a
// saved bundles map from a previous version. Also retires the design_admin
// label to "System Architect (legacy alias)" by mapping any user on
// design_admin → system_architect. Idempotent.
function _migrateRoles() {
  let changed = false;
  if (!state.bundles) state.bundles = {};

  // Ensure new bundles exist by copying from DEFAULT_BUNDLES when missing
  ['system_architect','project_coordinator','install_assistant','install_admin','design_admin','contractor'].forEach(k => {
    if (!state.bundles[k]) {
      state.bundles[k] = JSON.parse(JSON.stringify(DEFAULT_BUNDLES[k]));
      changed = true;
    }
  });
  // Refresh the install_admin label/desc on existing installs (renamed from
  // "Install Admin" → "Install Manager") so the UI matches the new vocabulary.
  if (state.bundles.install_admin && state.bundles.install_admin.label !== DEFAULT_BUNDLES.install_admin.label) {
    state.bundles.install_admin.label = DEFAULT_BUNDLES.install_admin.label;
    state.bundles.install_admin.desc = DEFAULT_BUNDLES.install_admin.desc;
    changed = true;
  }

  if (changed) save('vi_bundles', state.bundles);

  // Migrate users on design_admin → system_architect. Keep design_admin around
  // as an alias bundle but move active users off it.
  let userChanged = false;
  Object.keys(state.userPermissions || {}).forEach(memberId => {
    const up = state.userPermissions[memberId];
    if (up && up.bundle === 'design_admin') {
      up.bundle = 'system_architect';
      userChanged = true;
    }
  });
  if (userChanged) save('vi_user_perms', state.userPermissions);
}

function _fixDesignTaskIdCollisions() {
  const seen = new Set();
  // Reserve all install ids first — they keep theirs
  (state.installTasks || []).forEach(t => {
    seen.add(t.id);
    (t.subtasks || []).forEach(s => seen.add(s.id));
  });
  // Find current max across both stores
  let nextId = 0;
  seen.forEach(id => { if (id > nextId) nextId = id; });
  (state.designTasks || []).forEach(t => {
    if (t.id > nextId) nextId = t.id;
    (t.subtasks || []).forEach(s => { if (s.id > nextId) nextId = s.id; });
  });

  let changed = false;
  (state.designTasks || []).forEach(t => {
    if (seen.has(t.id) || t.id == null) {
      nextId++;
      t.id = nextId;
      changed = true;
    }
    seen.add(t.id);
    (t.subtasks || []).forEach(s => {
      if (seen.has(s.id) || s.id == null) {
        nextId++;
        s.id = nextId;
        changed = true;
      }
      seen.add(s.id);
    });
  });
  if (changed) save('vi_design_tasks', state.designTasks);
}

// Migrate old task shape (single assignee, manual start/end) to new shape.
// Called once on load — idempotent.
// One-time migration: install-phase sub-tasks (old simple flat to-do system
// under state.subtasks[projectId]['install']) become Install Tasks (new system).
// Each becomes a master task with no subtasks. Marked migrated=true and
// removed from state.subtasks to prevent duplication. Idempotent.
function _migrateInstallSubtasksToTasks() {
  const src = state.subtasks || {};
  let migratedAny = false;
  Object.keys(src).forEach(pidStr => {
    const pid = parseInt(pidStr, 10);
    if (isNaN(pid)) return;
    const bucket = src[pidStr] || {};
    const oldList = bucket.install || [];
    if (oldList.length === 0) return;
    oldList.forEach(old => {
      // Skip already-migrated (shouldn't happen since we delete them, but defensive)
      if (old._migrated) return;
      const assignees = (old.assignee_id != null) ? [old.assignee_id] : [];
      // Map to install task: if it has a due_date, treat as milestone; otherwise as a
      // work task with one subtask carrying its own date (or no date if none).
      const isMilestone = !!old.due_date && assignees.length === 0;
      if (isMilestone) {
        addInstallTask({
          projectId: pid,
          system: null,
          title: old.text || 'Task',
          assigneeIds: [],
          isMilestone: true,
          dueDate: old.due_date
        });
      } else {
        const master = addInstallTask({
          projectId: pid,
          system: null,
          title: old.text || 'Task',
          assigneeIds: assignees,
          isMilestone: false
        });
        if (old.status === 'done') {
          master.done = true;
        }
        // If it had a due date, model as a single dated subtask
        if (old.due_date) {
          addInstallSubtask(master.id, {
            title: old.text || 'Task',
            date: old.due_date,
            assigneeIds: assignees,
            notes: ''
          });
        }
      }
      migratedAny = true;
    });
    // Clear the install bucket — design stays
    delete bucket.install;
  });
  if (migratedAny) {
    save('vi_subtasks', state.subtasks);
    save('vi_install_tasks', state.installTasks);
  }
}

// ── Migrate legacy design sub-tasks → new design tasks (idempotent) ──
// state.subtasks[pid]['design'] is the legacy bucket. Each becomes a master
// design task. Removes the design bucket after migration to prevent duplicates.
function _migrateDesignSubtasksToTasks() {
  const src = state.subtasks || {};
  let migratedAny = false;
  Object.keys(src).forEach(pidStr => {
    const pid = parseInt(pidStr, 10);
    if (isNaN(pid)) return;
    const bucket = src[pidStr] || {};
    const oldList = bucket.design || [];
    if (oldList.length === 0) return;
    oldList.forEach(old => {
      if (old._migrated) return;
      const assignees = (old.assignee_id != null) ? [old.assignee_id] : [];
      const isMilestone = !!old.due_date && assignees.length === 0;
      if (isMilestone) {
        addDesignTask({
          projectId: pid,
          system: null,
          title: old.text || 'Task',
          assigneeIds: [],
          isMilestone: true,
          dueDate: old.due_date
        });
      } else {
        const master = addDesignTask({
          projectId: pid,
          system: null,
          title: old.text || 'Task',
          assigneeIds: assignees,
          isMilestone: false
        });
        if (old.status === 'done') {
          master.done = true;
        }
        if (old.due_date) {
          addDesignSubtask(master.id, {
            title: old.text || 'Task',
            date: old.due_date,
            assigneeIds: assignees,
            notes: ''
          });
        }
      }
      migratedAny = true;
    });
    delete bucket.design;
  });
  if (migratedAny) {
    save('vi_subtasks', state.subtasks);
    save('vi_design_tasks', state.designTasks);
  }
}


function _migrateInstallTaskShape() {
  const all = state.installTasks || [];
  let changed = false;
  all.forEach(t => {
    if (!Array.isArray(t.assigneeIds)) {
      t.assigneeIds = (t.assigneeId != null) ? [t.assigneeId] : [];
      delete t.assigneeId;
      changed = true;
    }
    if (t.isMilestone && !t.dueDate && t.startDate) { t.dueDate = t.startDate; changed = true; }
    if ('startDate' in t || 'endDate' in t) {
      if (t.isMilestone && !t.dueDate && t.startDate) t.dueDate = t.startDate;
      delete t.startDate; delete t.endDate; changed = true;
    }
    (t.subtasks || []).forEach(s => {
      if (!Array.isArray(s.assigneeIds)) {
        s.assigneeIds = (s.assigneeId != null) ? [s.assigneeId] : [];
        delete s.assigneeId;
        changed = true;
      }
      if (typeof s.notes !== 'string') { s.notes = ''; changed = true; }
    });
  });
  if (changed) save('vi_install_tasks', state.installTasks);

  // Backfill crew membership from existing task assignments. Runs every load —
  // cheap and idempotent. Ensures anyone assigned to a task or subtask is on
  // the project crew (so they see it on their dashboard).
  all.forEach(t => {
    if (t.projectId == null) return;
    const ids = new Set();
    (t.assigneeIds || []).forEach(id => ids.add(id));
    (t.subtasks || []).forEach(s => (s.assigneeIds || []).forEach(id => ids.add(id)));
    if (ids.size) ensureOnProjectCrew(t.projectId, [...ids]);
  });
}

function getTasksForProject(projectId) {
  return (state.installTasks || []).filter(t => t.projectId === projectId);
}
function getShopWorkTasks() {
  return (state.installTasks || []).filter(t => t.shopWork);
}
function getInstallTaskById(taskId) {
  return (state.installTasks || []).find(t => String(t.id) === String(taskId)) || null;
}

// A master task's effective date range — derived from its subtasks' dates.
// Returns { start, end } or null if no subtask has a date. For milestones,
// returns { start: dueDate, end: dueDate }.
function getTaskDateRange(task) {
  if (!task) return null;
  if (task.isMilestone) {
    return task.dueDate ? { start: task.dueDate, end: task.dueDate } : null;
  }
  // Pinned step dates are the granular source of truth: when any step is dated,
  // the task spans its steps. The coarse schedStart/schedEnd is only a fallback
  // for tasks with no dated steps. This keeps every calendar AND the Schedule
  // Builder panel in agreement (a stale drag-span can't override the steps).
  const dates = (task.subtasks || []).map(s => s.date).filter(Boolean).sort();
  if (dates.length) return { start: dates[0], end: dates[dates.length - 1] };
  if (task.schedStart) return { start: task.schedStart, end: task.schedEnd || task.schedStart };
  return null;
}

// Auto-add a person (or list of people) to a project's install crew if not
// already on it. Keeps task assignment and dashboard visibility consistent.
function ensureOnProjectCrew(projectId, memberIds) {
  if (projectId == null) return;
  const ids = (Array.isArray(memberIds) ? memberIds : [memberIds]).filter(id => id != null);
  if (ids.length === 0) return;
  const a = getProjectAssignment(projectId);
  const installList = [...(a.install || [])];
  let changed = false;
  ids.forEach(id => {
    const onInstall = installList.some(x => x.id === id);
    const onPm = (a.pm || []).some(x => x.id === id);
    if (!onInstall && !onPm) {
      installList.push({ id, lead: false });
      changed = true;
    }
  });
  if (changed) setProjectAssignment(projectId, 'install', installList);
}

function addInstallTask({ projectId, shopWork, system, title, assigneeIds, isMilestone, dueDate, templateKey }) {
  if (!state.installTasks) state.installTasks = [];
  const ids = Array.isArray(assigneeIds) ? assigneeIds.filter(x => x != null) : [];
  const task = {
    id: _nextTaskId(),
    projectId: projectId != null ? projectId : null,
    shopWork: !!shopWork,
    system: system || null,
    title: title || 'Task',
    assigneeIds: isMilestone ? [] : ids,
    isMilestone: !!isMilestone,
    dueDate: isMilestone ? (dueDate || null) : null,
    done: false,
    subtasks: [],
    templateKey: templateKey || null,
    createdAt: new Date().toISOString()
  };
  state.installTasks.push(task);
  _syncTasksNow('install');
  if (!isMilestone && projectId != null && ids.length) ensureOnProjectCrew(projectId, ids);
  return task;
}

function updateInstallTask(taskId, patch) {
  const t = getInstallTaskById(taskId);
  if (!t) return;
  Object.assign(t, patch);
  if (t.isMilestone) t.assigneeIds = [];
  _syncTasksNow('install');
  if (!t.isMilestone && t.projectId != null && Array.isArray(t.assigneeIds) && t.assigneeIds.length) {
    ensureOnProjectCrew(t.projectId, t.assigneeIds);
  }
}

// Awaited cloud write for task stores so a delete/edit actually persists on
// mobile instead of reverting on the next reload/focus-sync.
async function _syncTasksNow(phase) {
  const key = phase === 'design' ? 'vi_design_tasks' : 'vi_install_tasks';
  const val = phase === 'design' ? state.designTasks : state.installTasks;
  save(key, val);
  const sb = window._sb;
  if (!sb) return;
  try {
    const { error } = await sb.from('app_data').upsert({ key, value: val }, { onConflict: 'key' });
    if (error) showToast('Change may not have synced — try again', 'error');
  } catch (e) { showToast('Change may not have synced — try again', 'error'); }
}
function deleteInstallTask(taskId) {
  if (!_canDeleteTasks()) { showToast('Only managers can delete tasks', 'error'); return; }
  state.installTasks = (state.installTasks || []).filter(t => String(t.id) !== String(taskId));
  _syncTasksNow('install');
}

function toggleInstallTaskDone(taskId) {
  const t = getInstallTaskById(taskId);
  if (!t) return;
  t.done = !t.done;
  _syncTasksNow('install');
}

function addInstallSubtask(taskId, { title, date, assigneeIds, notes, photoRequired, time }) {
  const t = getInstallTaskById(taskId);
  if (!t) return;
  if (!t.subtasks) t.subtasks = [];
  const ids = Array.isArray(assigneeIds) ? assigneeIds.filter(x => x != null) : [];
  t.subtasks.push({
    id: _nextTaskId(),
    title: title || 'Subtask',
    date: date || null,
    time: time || null,
    assigneeIds: ids,
    notes: notes || '',
    photoRequired: !!photoRequired,
    done: false
  });
  _syncTasksNow('install');
  if (t.projectId != null && ids.length) ensureOnProjectCrew(t.projectId, ids);
}

function updateInstallSubtask(taskId, subtaskId, patch) {
  const t = getInstallTaskById(taskId);
  if (!t) return;
  const s = (t.subtasks || []).find(x => x.id === subtaskId);
  if (!s) return;
  Object.assign(s, patch);
  if (!Array.isArray(s.assigneeIds)) s.assigneeIds = [];
  _syncTasksNow('install');
  if (t.projectId != null && s.assigneeIds.length) ensureOnProjectCrew(t.projectId, s.assigneeIds);
}

function deleteInstallSubtask(taskId, subtaskId) {
  if (!_canDeleteTasks()) { showToast('Only managers can delete tasks', 'error'); return; }
  const t = getInstallTaskById(taskId);
  if (!t) return;
  t.subtasks = (t.subtasks || []).filter(x => String(x.id) !== String(subtaskId));
  _syncTasksNow('install');
}

function toggleInstallSubtaskDone(taskId, subtaskId) {
  const t = getInstallTaskById(taskId);
  if (!t) return;
  const s = (t.subtasks || []).find(x => x.id === subtaskId);
  if (!s) return;
  _applyDone(s);
  _syncTasksNow('install');
}
function toggleInstallSubtaskStarted(taskId, subtaskId) {
  const t = getInstallTaskById(taskId);
  if (!t) return;
  const s = (t.subtasks || []).find(x => x.id === subtaskId);
  if (!s) return;
  _applyStarted(s);
  _syncTasksNow('install');
}

// ────────────────────────────────────────────────────────────────────────────
// DESIGN TASKS — parallel system to install tasks. Same shape, separate store.
// Storage: state.designTasks (array of task objects). Each task has:
//   id, projectId, system, title, assigneeIds[], isMilestone, dueDate,
//   done, subtasks[], templateKey, createdAt
// Same shape as install tasks but stored separately so we can filter, render,
// and migrate independently. Renderer is shared via a `phase` parameter.
// ────────────────────────────────────────────────────────────────────────────

function getDesignTaskById(taskId) {
  return (state.designTasks || []).find(t => String(t.id) === String(taskId)) || null;
}

