// ── Phase router — given a task id, return which phase it belongs to ──
// Used by the shared task UI / edit-mode functions so they can route writes
// to the correct store (install vs design). Returns 'install' | 'design' | null.
function _getTaskPhase(taskId) {
  const sid = String(taskId);
  if ((state.installTasks || []).some(t => String(t.id) === sid)) return 'install';
  if ((state.designTasks || []).some(t => String(t.id) === sid)) return 'design';
  return null;
}
function _getTaskByIdAnyPhase(taskId) {
  return getInstallTaskById(taskId) || getDesignTaskById(taskId);
}
// Phase-aware CRUD wrappers — UI code calls these without knowing the phase
function toggleTaskDone(taskId) {
  return _getTaskPhase(taskId) === 'design' ? toggleDesignTaskDone(taskId) : toggleInstallTaskDone(taskId);
}
function deleteTask(taskId) {
  if (!_canDeleteTasks()) { showToast('Only managers can delete tasks', 'error'); return; }
  const sid = String(taskId);
  const inD = (state.designTasks || []).some(t => String(t.id) === sid);
  const inI = (state.installTasks || []).some(t => String(t.id) === sid);
  if (inD) { state.designTasks = state.designTasks.filter(t => String(t.id) !== sid); _syncTasksNow('design'); }
  if (inI) { state.installTasks = state.installTasks.filter(t => String(t.id) !== sid); _syncTasksNow('install'); }
  if (!inD && !inI) showToast("Couldn't find that task to delete", 'error');
}
function toggleSubtaskDone(taskId, subtaskId) {
  return _getTaskPhase(taskId) === 'design' ? toggleDesignSubtaskDone(taskId, subtaskId) : toggleInstallSubtaskDone(taskId, subtaskId);
}
function toggleSubtaskStarted(taskId, subtaskId) {
  return _getTaskPhase(taskId) === 'design' ? toggleDesignSubtaskStarted(taskId, subtaskId) : toggleInstallSubtaskStarted(taskId, subtaskId);
}
// ── Subtask status stamping (started / completed, each records who + when) ──
function _whoNow() { return (typeof getActiveTeamMemberId === 'function') ? getActiveTeamMemberId() : null; }
function _applyStarted(s) {
  s.started = !s.started;
  if (s.started) { s.startedAt = new Date().toISOString(); s.startedBy = _whoNow(); }
  else { s.startedAt = null; s.startedBy = null; }
}
function _applyDone(s) {
  s.done = !s.done;
  if (s.done) { s.doneAt = new Date().toISOString(); s.doneBy = _whoNow(); }
  else { s.doneAt = null; s.doneBy = null; }
}
function _memberName(id) {
  if (id == null) return 'someone';
  const m = (typeof getTeamMember === 'function') ? getTeamMember(id) : null;
  if (!m) return 'someone';
  return (m.name || '').split(' ')[0] || m.name || 'someone';
}
function _fmtStamp(iso) {
  if (!iso) return '';
  const d = new Date(iso);
  if (isNaN(d.getTime())) return '';
  return d.toLocaleString('en-US', { month: 'short', day: 'numeric', hour: 'numeric', minute: '2-digit' });
}
function _fmtTime12(hhmm) {
  if (!hhmm) return '';
  const m = /^(\d{1,2}):(\d{2})/.exec(hhmm);
  if (!m) return hhmm;
  let h = parseInt(m[1], 10); const min = m[2];
  const ap = h >= 12 ? 'PM' : 'AM'; h = h % 12; if (h === 0) h = 12;
  return `${h}:${min} ${ap}`;
}
function _subStatusMetaHTML(s) {
  const bits = [];
  if (s.startedAt) bits.push('Started ' + _memberName(s.startedBy) + ' \u00B7 ' + _fmtStamp(s.startedAt));
  if (s.doneAt) bits.push('Done ' + _memberName(s.doneBy) + ' \u00B7 ' + _fmtStamp(s.doneAt));
  if (!bits.length) return '';
  return '<div style="font-size:10px;color:#6E7681;margin-top:2px">' + bits.map(esc).join('  \u00B7  ') + '</div>';
}
function deleteSubtask(taskId, subtaskId) {
  return _getTaskPhase(taskId) === 'design' ? deleteDesignSubtask(taskId, subtaskId) : deleteInstallSubtask(taskId, subtaskId);
}
function addSubtaskAnyPhase(taskId, payload) {
  return _getTaskPhase(taskId) === 'design' ? addDesignSubtask(taskId, payload) : addInstallSubtask(taskId, payload);
}
function updateSubtaskAnyPhase(taskId, subtaskId, patch) {
  return _getTaskPhase(taskId) === 'design' ? updateDesignSubtask(taskId, subtaskId, patch) : updateInstallSubtask(taskId, subtaskId, patch);
}
function updateTaskAnyPhase(taskId, patch) {
  return _getTaskPhase(taskId) === 'design' ? updateDesignTask(taskId, patch) : updateInstallTask(taskId, patch);
}

// ── Install task EDIT MODE ──
// Per-task edit mode state. window._editingTaskId holds the task that's
// currently in edit mode (only one at a time across all cards). The companion
// Set tracks which subtask rows are selected for bulk-apply.
window._editingTaskId = null;
window._selectedSubtaskIds = new Set();

function _toggleTaskEditMode(taskId) {
  if (window._editingTaskId === taskId) {
    window._editingTaskId = null;
    window._selectedSubtaskIds = new Set();
  } else {
    window._editingTaskId = taskId;
    window._selectedSubtaskIds = new Set();
  }
  renderCurrentPage();
}

function _toggleSubtaskSelected(taskId, subtaskId) {
  if (window._editingTaskId !== taskId) return;
  if (window._selectedSubtaskIds.has(subtaskId)) {
    window._selectedSubtaskIds.delete(subtaskId);
  } else {
    window._selectedSubtaskIds.add(subtaskId);
  }
  renderCurrentPage();
}

function _selectAllSubtasks(taskId) {
  const t = _getTaskByIdAnyPhase(taskId);
  if (!t) return;
  const all = (t.subtasks || []).map(s => s.id);
  if (window._selectedSubtaskIds.size === all.length && all.every(id => window._selectedSubtaskIds.has(id))) {
    window._selectedSubtaskIds = new Set(); // toggle off if all already selected
  } else {
    window._selectedSubtaskIds = new Set(all);
  }
  renderCurrentPage();
}

function _bulkSetDateOnSelected(taskId, dateStr) {
  const t = _getTaskByIdAnyPhase(taskId);
  if (!t) return;
  const targets = (t.subtasks || []).filter(s => window._selectedSubtaskIds.has(s.id));
  targets.forEach(s => { s.date = dateStr || null; });
  const phase = _getTaskPhase(taskId);
  _syncTasksNow(phase);
  renderCurrentPage();
}

function _bulkSetAssigneesOnSelected(taskId, ids) {
  const t = _getTaskByIdAnyPhase(taskId);
  if (!t) return;
  const cleanIds = (ids || []).filter(id => id != null);
  const targets = (t.subtasks || []).filter(s => window._selectedSubtaskIds.has(s.id));
  targets.forEach(s => { s.assigneeIds = [...cleanIds]; });
  if (t.projectId != null && cleanIds.length > 0) ensureOnProjectCrew(t.projectId, cleanIds);
  const phase = _getTaskPhase(taskId);
  _syncTasksNow(phase);
  renderCurrentPage();
}

function _reorderSubtask(taskId, fromIdx, toIdx) {
  const t = _getTaskByIdAnyPhase(taskId);
  if (!t || !t.subtasks) return;
  if (fromIdx === toIdx || fromIdx < 0 || toIdx < 0) return;
  if (fromIdx >= t.subtasks.length || toIdx >= t.subtasks.length) return;
  const [moved] = t.subtasks.splice(fromIdx, 1);
  t.subtasks.splice(toIdx, 0, moved);
  // Persist the new order as priority so the dashboards (which sort date → priority)
  // reflect it within each day.
  t.subtasks.forEach((s, i) => { s.priority = i; });
  const phase = _getTaskPhase(taskId);
  _syncTasksNow(phase);
  renderCurrentPage();
}

// ▲▼ reorder (reliable on mobile, where HTML5 drag doesn't fire). dir = -1 up / +1 down.
function _moveSubtask(taskId, subId, dir) {
  const t = _getTaskByIdAnyPhase(taskId);
  if (!t || !t.subtasks) return;
  const from = t.subtasks.findIndex(s => String(s.id) === String(subId));
  if (from < 0) return;
  _reorderSubtask(taskId, from, from + dir);
}

// Drag tracking for subtask reorder
window._subtaskDragSrc = null;
function _subtaskDragStart(ev, taskId, subtaskId) {
  window._subtaskDragSrc = { taskId, subtaskId };
  try { ev.dataTransfer.effectAllowed = 'move'; ev.dataTransfer.setData('text/plain', String(subtaskId)); } catch(e){}
}
function _subtaskDragOver(ev) {
  if (window._subtaskDragSrc) { ev.preventDefault(); try{ ev.dataTransfer.dropEffect = 'move'; }catch(e){} }
}
function _subtaskDrop(ev, taskId, subtaskId) {
  ev.preventDefault();
  const src = window._subtaskDragSrc;
  window._subtaskDragSrc = null;
  if (!src || src.taskId !== taskId || src.subtaskId === subtaskId) return;
  const t = _getTaskByIdAnyPhase(taskId);
  if (!t) return;
  const fromIdx = t.subtasks.findIndex(s => s.id === src.subtaskId);
  const toIdx = t.subtasks.findIndex(s => s.id === subtaskId);
  _reorderSubtask(taskId, fromIdx, toIdx);
}

// Bulk-apply day picker: opens the same calendar popup we use elsewhere,
// commits the chosen date to every selected subtask at once.
function _openBulkDayPicker(taskId) {
  if (window._selectedSubtaskIds.size === 0) {
    showToast('Select at least one step first', 'info');
    return;
  }
  window._dayPickerState = {
    mode: 'bulk',
    bulkTaskId: taskId,
    anchor: new Date()
  };
  document.getElementById('day-picker')?.remove();
  const overlay = document.createElement('div');
  overlay.id = 'day-picker';
  overlay.className = 'modal-overlay';
  overlay.style.zIndex = '10002';
  overlay.onclick = (e) => { if (e.target === overlay) { overlay.remove(); window._dayPickerState = null; } };
  overlay.innerHTML = _renderSubDayPickerContent();
  document.body.appendChild(overlay);
}
function _closeBulkPicker() {
  const m = document.getElementById('bulk-day-modal'); if (m) m.remove();
  const p = document.getElementById('bulk-people-modal'); if (p) p.remove();
  const p2 = document.getElementById('bulk-people-dialog'); if (p2) p2.remove();
  document.getElementById('day-picker')?.remove();
  window._dayPickerState = null;
}

// Bulk-apply people picker
function _openBulkPeoplePicker(taskId) {
  if (window._selectedSubtaskIds.size === 0) {
    showToast('Select at least one step first', 'info');
    return;
  }
  const t = _getTaskByIdAnyPhase(taskId);
  if (!t) return;
  // Available people: install crew + PM on this project, then everyone else.
  // Same pool as the per-subtask dialog so users see a consistent picker.
  const projId = t.projectId;
  const crew = projId != null ? getProjectAssignment(projId) : { install: [], pm: [] };
  const crewIds = new Set([...(crew.install || []).map(x => x.id), ...(crew.pm || []).map(x => x.id)]);
  const pool = state.team || [];
  const sortedPool = [...pool].sort((a, b) => {
    const aOn = crewIds.has(a.id) ? 0 : 1;
    const bOn = crewIds.has(b.id) ? 0 : 1;
    if (aOn !== bOn) return aOn - bOn;
    return a.name.localeCompare(b.name);
  });
  window._bulkPeopleSelectedIds = new Set();
  window._bulkPeopleTaskId = taskId;

  document.getElementById('bulk-people-dialog')?.remove();
  const overlay = document.createElement('div');
  overlay.id = 'bulk-people-dialog';
  overlay.className = 'modal-overlay';
  overlay.style.zIndex = '10002';
  overlay.onclick = (e) => { if (e.target === overlay) _closeBulkPicker(); };
  overlay.innerHTML = `
    <div class="modal-container" style="max-width:420px;display:flex;flex-direction:column">
      <div class="modal-header">
        <div class="modal-title">Assign to ${window._selectedSubtaskIds.size} steps</div>
        <button class="modal-close" onclick="_closeBulkPicker()">&times;</button>
      </div>
      <div class="modal-body" style="display:flex;flex-direction:column;gap:10px">
        <div style="font-size:11px;color:#8B949E">Replaces existing assignees on selected steps.</div>
        <div class="itask-assignee-pick" id="bulk-people-list">
          ${sortedPool.map(m => `
            <label class="itask-assignee-chip">
              <input type="checkbox" value="${m.id}" onchange="_bulkTogglePeople(${m.id},this.checked)">
              <span>${esc(m.name)}${crewIds.has(m.id) ? '' : ' <span style="font-size:9px;color:#D29922">(not on crew)</span>'}</span>
            </label>
          `).join('')}
        </div>
      </div>
      <div class="modal-footer" style="display:flex;gap:8px;justify-content:flex-end;padding:12px 16px;border-top:1px solid #30363D">
        <button class="btn btn-sm" onclick="_closeBulkPicker()">Cancel</button>
        <button class="btn btn-sm btn-primary" onclick="_commitBulkPeople(${taskId})">Apply</button>
      </div>
    </div>
  `;
  document.body.appendChild(overlay);
}
function _bulkTogglePeople(id, checked) {
  if (!window._bulkPeopleSelectedIds) window._bulkPeopleSelectedIds = new Set();
  if (checked) window._bulkPeopleSelectedIds.add(id);
  else window._bulkPeopleSelectedIds.delete(id);
}
function _commitBulkPeople(taskId) {
  const ids = [...(window._bulkPeopleSelectedIds || new Set())];
  _bulkSetAssigneesOnSelected(taskId, ids);
  _closeBulkPicker();
}

// Tasks (and subtasks) that fall on a given date — used by calendar surfacing.
function getInstallTasksForDate(dateStr, projectId) {
  const out = [];
  (state.installTasks || []).forEach(t => {
    if (projectId != null && t.projectId !== projectId) return;
    (t.subtasks || []).forEach(s => { if (s.date === dateStr) out.push({ task: t, subtask: s }); });
    if (t.isMilestone && t.dueDate === dateStr) out.push({ task: t, subtask: null });
  });
  return out;
}

// ════════════════════════════════════════════════════════════════════════════
// INSTALL TASK TEMPLATES — tag → standard master task + subtasks
// ────────────────────────────────────────────────────────────────────────────
// state.installTaskTemplates is the editable per-tag template map. Migrated
// once from the legacy TEMPLATES.install on first load, then editable via UI.
//
// Shape: {
//   [systemKey]: {
//     systemKey, label, subtasks: [ { title, notes } ]
//   }
// }
// systemKey matches what detectSystems() emits ('led_wall', 'pa_install', etc.)
// ════════════════════════════════════════════════════════════════════════════

// Map from canonical scope-tag label (as on SCOPE_TAGS) to systemKey, so the
// project's scope_tags can be looked up against templates.
const SCOPE_TAG_TO_SYSTEM = {
  'PA System': 'pa_install',
  'LED Wall': 'led_wall',
  'Key Lights': 'lighting',
  'House Lights': 'lighting',
  'House Lighting – 110V': 'house_lighting_110v',
  'House Lighting – Low Volt': 'house_lighting_lowvolt',
  'Projection': 'projector_install',
  'Broadcast Video System': 'streaming',
  'Streaming Audio System': 'streaming',
  'Camera': 'camera',
  'Control (Q-sys)': 'control',
  'Control (AHM)': 'control',
  'Control (Atlona)': 'control'
  // tags without a default template (Distributed Audio, TVs,
  // Conferencing, Mics, Acoustic Treatment, Drape, Network) just don't seed —
  // user can add a custom template for them through the UI.
};

function _migrateInstallTaskTemplates() {
  if (state.installTaskTemplates && Object.keys(state.installTaskTemplates).length) return;
  // First-time seed of the editable template map from the legacy TEMPLATES.install
  const seeded = {};
  const src = (typeof TEMPLATES !== 'undefined' && TEMPLATES && TEMPLATES.install) ? TEMPLATES.install : {};
  Object.keys(src).forEach(sysKey => {
    const t = src[sysKey];
    seeded[sysKey] = {
      systemKey: sysKey,
      label: t.name || sysKey,
      subtasks: (t.items || []).map(_normalizeTemplateItem)
    };
  });
  state.installTaskTemplates = seeded;
  save('vi_install_task_templates', seeded);
}

// Template items may be a plain string or { title, note, photo } — normalize to
// the stored subtask shape { title, notes, photoRequired }.
function _normalizeTemplateItem(item) {
  if (typeof item === 'string') return { title: item, notes: '', photoRequired: false };
  return {
    title: item.title || '',
    notes: item.note || item.notes || '',
    photoRequired: !!(item.photo || item.photoRequired)
  };
}

// Top-up: install templates introduced after a device first seeded its editable
// map (the first-time migrate above runs only once). Add-if-missing for these
// specific keys only; a one-time flag prevents re-adding after a user deletes one.
function _ensureNewInstallTemplates() {
  try { if (localStorage.getItem('vi_install_tpl_v2') === '1') return; } catch (e) {}
  if (!state.installTaskTemplates) state.installTaskTemplates = {};
  const src = (typeof TEMPLATES !== 'undefined' && TEMPLATES && TEMPLATES.install) ? TEMPLATES.install : {};
  const NEW_KEYS = ['house_lighting_110v', 'house_lighting_lowvolt', 'projector_install'];
  let added = 0;
  NEW_KEYS.forEach(k => {
    if (state.installTaskTemplates[k] || !src[k]) return;
    state.installTaskTemplates[k] = {
      systemKey: k,
      label: src[k].name || k,
      subtasks: (src[k].items || []).map(_normalizeTemplateItem)
    };
    added++;
  });
  try { localStorage.setItem('vi_install_tpl_v2', '1'); } catch (e) {}
  if (added) _syncKeyNow('vi_install_task_templates', state.installTaskTemplates);
}

function getInstallTaskTemplate(systemKey) {
  return (state.installTaskTemplates || {})[systemKey] || null;
}

function getAllInstallTaskTemplates() {
  return Object.values(state.installTaskTemplates || {}).sort((a, b) => a.label.localeCompare(b.label));
}

function upsertInstallTaskTemplate(systemKey, { label, subtasks }) {
  if (!state.installTaskTemplates) state.installTaskTemplates = {};
  state.installTaskTemplates[systemKey] = {
    systemKey,
    label: label || systemKey,
    subtasks: (subtasks || []).map(s => ({ title: s.title || '', notes: s.notes || '', photoRequired: !!s.photoRequired }))
  };
  save('vi_install_task_templates', state.installTaskTemplates);
}

function deleteInstallTaskTemplate(systemKey) {
  if (!state.installTaskTemplates) return;
  delete state.installTaskTemplates[systemKey];
  save('vi_install_task_templates', state.installTaskTemplates);
}

// ── Design task templates — mirrors install template system, separate store ──
function _migrateDesignTaskTemplates() {
  if (state.designTaskTemplates && Object.keys(state.designTaskTemplates).length) return;
  const seeded = {};
  const src = (typeof TEMPLATES !== 'undefined' && TEMPLATES && TEMPLATES.design) ? TEMPLATES.design : {};
  Object.keys(src).forEach(sysKey => {
    const t = src[sysKey];
    seeded[sysKey] = {
      systemKey: sysKey,
      label: t.name || sysKey,
      subtasks: (t.items || []).map(item => ({ title: item, notes: '' }))
    };
  });
  state.designTaskTemplates = seeded;
  save('vi_design_task_templates', seeded);
}

function getDesignTaskTemplate(systemKey) {
  return (state.designTaskTemplates || {})[systemKey] || null;
}

function getAllDesignTaskTemplates() {
  return Object.values(state.designTaskTemplates || {}).sort((a, b) => a.label.localeCompare(b.label));
}

function upsertDesignTaskTemplate(systemKey, { label, subtasks }) {
  if (!state.designTaskTemplates) state.designTaskTemplates = {};
  state.designTaskTemplates[systemKey] = {
    systemKey,
    label: label || systemKey,
    subtasks: (subtasks || []).map(s => ({ title: s.title || '', notes: s.notes || '' }))
  };
  save('vi_design_task_templates', state.designTaskTemplates);
}

function deleteDesignTaskTemplate(systemKey) {
  if (!state.designTaskTemplates) return;
  delete state.designTaskTemplates[systemKey];
  save('vi_design_task_templates', state.designTaskTemplates);
}

// Seed design tasks from a project's scope. Mirrors _seedTasksFromScope but for
// design phase. If reseed=true, deletes existing template-seeded design tasks
// first (preserves manual tasks).
function _seedDesignTasksFromScope(projectId, reseed) {
  const p = state.projects.find(pp => pp.id === projectId);
  if (!p) return;
  if (reseed) {
    state.designTasks = (state.designTasks || []).filter(t => !(t.projectId === projectId && t.templateKey));
  }
  const existing = new Set((state.designTasks || [])
    .filter(t => t.projectId === projectId && t.templateKey)
    .map(t => t.templateKey));
  const systemKeys = getProjectSystemKeys(p);
  let added = 0;
  systemKeys.forEach(sysKey => {
    if (existing.has(sysKey)) return;
    const tpl = getDesignTaskTemplate(sysKey);
    if (!tpl) return;
    const newTask = addDesignTask({
      projectId,
      system: sysKey,
      title: tpl.label,
      templateKey: sysKey
    });
    (tpl.subtasks || []).forEach(s => addDesignSubtask(newTask.id, { title: s.title, notes: s.notes }));
    added++;
  });
  if (added > 0) showToast(`Seeded ${added} design task${added > 1 ? 's' : ''}`, 'success');
  else if (reseed) showToast('Design tasks re-seeded', 'success');
  else showToast('No new design tasks to seed', 'info');
  renderCurrentPage();
}

// Which systemKeys does this project's scope cover? Reads from project.systems
// (auto-detected) and project.scope_tags (explicit user selections, mapped
// through SCOPE_TAG_TO_SYSTEM).
function getProjectSystemKeys(project) {
  const keys = new Set();
  (project.systems || []).forEach(k => keys.add(k));
  (project.scope_tags || []).forEach(tag => {
    const k = SCOPE_TAG_TO_SYSTEM[tag];
    if (k) keys.add(k);
  });
  return [...keys];
}

// Which systemKeys on this project already have a seeded master task? Used so
// the seed button only seeds tags not already seeded (safe default).
function getSeededSystemKeysForProject(projectId) {
  const tasks = getTasksForProject(projectId);
  return [...new Set(tasks.map(t => t.templateKey).filter(Boolean))];
}

// Seed standard install tasks for a project from its scope. By default only
// seeds systems that haven't already been seeded (safe). overwrite=true wipes
// any prior tasks with a templateKey and reseeds — destructive option.
function seedTasksFromProjectScope(projectId, { overwrite } = {}) {
  const p = state.projects.find(x => x.id === projectId);
  if (!p) return { seeded: 0, skipped: 0 };
  const systemKeys = getProjectSystemKeys(p);
  if (overwrite) {
    // remove existing template-seeded tasks (manual tasks with no templateKey are preserved)
    state.installTasks = (state.installTasks || []).filter(t => !(t.projectId === projectId && t.templateKey));
    save('vi_install_tasks', state.installTasks);
  }
  const alreadySeeded = new Set(getSeededSystemKeysForProject(projectId));
  let seededCount = 0, skippedCount = 0;
  systemKeys.forEach(sysKey => {
    const tpl = getInstallTaskTemplate(sysKey);
    if (!tpl) { skippedCount++; return; }
    if (alreadySeeded.has(sysKey)) { skippedCount++; return; }
    const master = addInstallTask({
      projectId,
      system: sysKey,
      title: tpl.label,
      assigneeIds: [],
      isMilestone: false,
      templateKey: sysKey
    });
    // Add each template subtask with no date / no assignees — user fills in
    (tpl.subtasks || []).forEach(s => addInstallSubtask(master.id, {
      title: s.title, notes: s.notes || '', date: null, assigneeIds: [], photoRequired: !!s.photoRequired
    }));
    seededCount++;
  });
  return { seeded: seededCount, skipped: skippedCount };
}

// Opens the install window picker in REQUEST mode for an installer who can't
// edit directly. On confirm, a pending change request is created for the PM.
function openInstallWindowChangeRequest(projectId) {
  const p = state.projects.find(x => x.id === projectId);
  if (!p) return;
  const win = getInstallWindow(p);
  const bookedStored = state.bookedDates?.[projectId];
  const storedObj = (bookedStored && typeof bookedStored === 'object') ? bookedStored : {};
  openInstallWindowPicker({
    projectId,
    mode: 'booked',
    requestMode: true,
    initialStart: win?.start,
    initialEnd: win?.end,
    initialExcludeWeekends: storedObj.excludeWeekends !== false,
    initialWeekendIncludes: storedObj.weekendIncludes || [],
    onConfirm: () => { renderCurrentPage(); }
  });
}

function showSetBookedDatesDialog(projectId) {
  if (!canEditInstallWindow(projectId)) {
    if (canRequestInstallWindowChange(projectId)) {
      // Installer (not PM lead) — open the picker as a CHANGE REQUEST. On
      // confirm, the dates are captured as a pending request for the PM to
      // approve rather than applied directly.
      openInstallWindowChangeRequest(projectId);
    } else {
      showToast('Only the project PM can edit install dates', 'info');
    }
    return;
  }
  const p = state.projects.find(x => x.id === projectId);
  if (!p) return;
  // This entry point is for setting BOOKED dates specifically.
  // If the project currently has a booked window, pre-fill from it.
  // If only an estimated window exists, pre-fill the dates from that (so the user
  // can promote it to booked) but still open in booked mode.
  const win = getInstallWindow(p);
  const bookedStored = state.bookedDates?.[projectId];
  const stored = bookedStored && bookedStored.start ? bookedStored : (state.estimatedInstallOverride?.[projectId] || {});
  const storedObj = (stored && typeof stored === 'object') ? stored : {};

  openInstallWindowPicker({
    projectId,
    mode: 'booked',
    initialStart: win?.start,
    initialEnd: win?.end,
    initialExcludeWeekends: storedObj.excludeWeekends !== false,
    initialWeekendIncludes: storedObj.weekendIncludes || [],
    onConfirm: () => {
      renderCurrentPage();
    }
  });
}

// Legacy save handler retained for any inline callers; new picker calls setBookedDates directly
function saveBookedDatesDialog(projectId) {
  const start = document.getElementById('booked-start')?.value;
  const end = document.getElementById('booked-end')?.value || '';
  if (!start) { alert('Please set a start date.'); return; }
  setBookedDates(projectId, start, end);
  document.getElementById('booked-dates-dialog')?.remove();
  renderCurrentPage();
}

// ── Enrich Project ──
function enrichProject(p) {
  const name = p.name || p.title || 'Untitled';
  const scope = [name, p.description || '', p.notes || ''].join(' ');
  const systems = detectSystems(scope);
  const total = parseFloat(p.total) || parseFloat(p.equipment_total) || 0;
  const labor = parseFloat(p.labor_total) || 0;
  const equipment = parseFloat(p.equipment_total) || total - labor;
  const stage = mapStage(p.stage || p.status);
  const archiveStatus = state.archived[p.id] || null;

  return {
    id: p.id,
    jetbuilt_id: p.id,
    name,
    client: p.client || { id: p.client_id },
    client_name: p.client?.company_name || p.client?.name || '',
    stage,
    raw_stage: p.stage || p.status || '',
    total,
    labor,
    equipment,
    systems,
    description: p.description || '',
    notes: p.notes || '',
    address: p.address || '',
    city: p.city || '',
    state_abbr: p.state || '',
    zip: p.zip || p.postal_code || '',
    created_at: p.created_at || '',
    updated_at: p.updated_at || '',
    start_date: p.start_date || p.install_date || '',
    end_date: p.end_date || '',
    primary_contact_name: '',
    primary_contact_email: '',
    primary_contact_phone: '',
    // Jetbuilt additional fields (Pass 1 of Overview redesign)
    jb_project_type: p.project_type || '',
    jb_close_date: p.close_date || '',
    jb_commission_date: p.commission_date || '',
    jb_estimated_install: p.estimated_install_on || '',
    jb_price_valid_until: p.price_valid_until || '',
    jb_probability: parseFloat(p.probability) || null,
    jb_custom_id: p.custom_id || '',
    jb_version: p.version || '',
    jb_contract_number: p.contract_number || '',
    jb_budget: parseFloat(p.budget) || null,
    jb_paid_to_date: parseFloat(p.paid_to_date) || 0,
    jb_total_margin: p.total_margin ? parseFloat(p.total_margin) : null,
    jb_equipment_margin: p.equipment_margin ? parseFloat(p.equipment_margin) : null,
    jb_shipping_total: parseFloat(p.shipping_total) || 0,
    jb_tax_total: parseFloat(p.tax_total) || 0,
    jb_owner_name: p.owner?.full_name || '',
    jb_pm_name: p.project_manager?.full_name || '',
    jb_engineer_name: p.engineer?.full_name || '',
    jb_market_segment: p.market_segment?.name || '',
    jb_company_location: p.company_location?.name || '',
    archived: archiveStatus
  };
}

// ── Archive System ──
const ARCHIVE_BINS = [
  { key: 'completed', label: 'Completed', icon: '✓', color: '#3FB950' },
  { key: 'icebox', label: 'Icebox', icon: '❄️', color: '#58A6FF' },
  { key: 'lost', label: 'Lost', icon: '✕', color: '#F85149' },
  { key: 'trash', label: 'Trash', icon: '🗑', color: '#6E7681' }
];

// Awaited cloud write for vi_archived so completing/reopening a job actually
// sticks on mobile (the passive mirror can drop a single-blob write).
async function _syncArchivedNow() {
  // Legacy single-blob mirror (kept for back-compat / older clients).
  save('vi_archived', state.archived);
  const sb = window._sb;
  if (!sb) return;
  try { await sb.from('app_data').upsert({ key: 'vi_archived', value: state.archived }, { onConflict: 'key' }); } catch (e) {}
}
// Per-project archive record — clobber-proof (one key per project), awaited so
// a failed write surfaces instead of silently reverting on reload.
async function _persistArchiveRecord(projectId, bin) {
  const sb = window._sb;
  if (!sb) return;
  const key = 'vi_arch_' + projectId;
  try {
    let res;
    if (bin) res = await sb.from('app_data').upsert({ key, value: bin }, { onConflict: 'key' });
    else res = await sb.from('app_data').delete().eq('key', key);
    if (res && res.error) showToast('Status may not have synced — try again', 'error');
  } catch (e) { showToast('Status may not have synced — try again', 'error'); }
}

// Generic awaited cloud upsert for a single vi_* key. Use for writes that MUST
// persist: the passive localStorage→cloud mirror can silently drop a write when
// a mobile PWA backgrounds, which is the recurring "I changed it and it reverted"
// bug. Mirrors the _syncArchivedNow / _lrUpsert pattern. Returns {ok, err}.
async function _syncKeyNow(key, value) {
  save(key, value);
  const sb = window._sb;
  if (!sb) return { ok: false, err: 'no cloud connection' };
  try {
    const { error } = await sb.from('app_data').upsert({ key, value }, { onConflict: 'key' });
    if (error) return { ok: false, err: error.message || error.code || 'write rejected' };
    return { ok: true };
  } catch (e) { return { ok: false, err: (e && e.message) ? e.message : String(e) }; }
}

// Awaited cloud upsert for the meetings blob. Calendar items (incl. design
// kickoff) were riding the passive mirror and dropping on mobile. NOTE: vi_meetings
// is still a single shared blob (last-write-wins) — concurrent multi-user edits
// can still clobber; tombstone-merge is a separate tracked item.
function _syncMeetingsNow() {
  _syncKeyNow('vi_meetings', state.meetings).then(r => {
    if (!r.ok) showToast('Meeting didn\u2019t save: ' + r.err + ' \u2014 try again', 'error');
  });
}

function archiveProject(projectId, bin) {
  state.archived[projectId] = bin;
  const p = state.projects.find(x => x.id === projectId);
  if (p) p.archived = bin;
  try { localStorage.setItem('vi_arch_' + projectId, JSON.stringify(bin)); } catch (e) {}
  save('vi_archived', state.archived);
  _persistArchiveRecord(projectId, bin);
  if (bin === 'completed') showToast('Marked completed', 'success');
  renderCurrentPage();
}

function unarchiveProject(projectId) {
  delete state.archived[projectId];
  const p = state.projects.find(x => x.id === projectId);
  if (p) p.archived = null;
  try { localStorage.removeItem('vi_arch_' + projectId); } catch (e) {}
  save('vi_archived', state.archived);
  _persistArchiveRecord(projectId, null);
  renderCurrentPage();
}

// Restore each project's archived flag from the stored source of truth
// (vi_archived). The cached project blob doesn't carry archived state, so
// without this a completed job reappears after a reload.
function _reconcileArchived() {
  // Per-project keys (vi_arch_<id>) win over the legacy vi_archived blob.
  const merged = Object.assign({}, state.archived || {});
  try {
    for (let i = 0; i < localStorage.length; i++) {
      const k = localStorage.key(i);
      if (!k || k.indexOf('vi_arch_') !== 0) continue;
      const id = k.slice(8);
      let v = null;
      try { v = JSON.parse(localStorage.getItem(k)); } catch (e) { v = localStorage.getItem(k); }
      if (v) merged[id] = v; else delete merged[id];
    }
  } catch (e) {}
  // Safeguard: any archive value that isn't a known bin is treated as NOT
  // archived, so a stray/legacy value can never hide a project from every view.
  const _validBins = new Set(ARCHIVE_BINS.map(b => b.key));
  Object.keys(merged).forEach(id => { if (!_validBins.has(merged[id])) delete merged[id]; });
  state.archived = merged;
  (state.projects || []).forEach(p => { p.archived = merged[p.id] || merged[String(p.id)] || null; });
}

// Mark a single project completed from its page (reversible).
function markProjectCompleted(projectId) {
  const p = state.projects.find(x => x.id === projectId);
  const name = (p && p.name) || 'this job';
  if (!confirm('Mark "' + name + '" as completed? It drops off dashboards and files under Completed. You can reopen it anytime.')) return;
  archiveProject(projectId, 'completed');
}

// ── Stage picker from the project header pill ──────────────────────────────
// Map a target stage to the highest PHASES index whose milestones "should" be
// done before entering it. Used to warn which milestones a forward jump skips.
const STAGE_TO_PHASE_CHECK = { lead:-1, proposal:0, sent:0, contract:1, install:5, commissioning:6, signoff:7, closeout:8, warranty:8 };
function _incompleteMilestonesUpTo(projectId, maxIdx) {
  const out = [];
  PHASES.forEach((ph, idx) => {
    if (idx > maxIdx) return;
    (ph.milestones || []).forEach(ms => {
      if (!getMilestone(projectId, ph.key, ms.key)) out.push(ph.label + ' \u2014 ' + ms.label);
    });
  });
  return out;
}
function _stageLabel(key) { const s = STAGES.find(x => x.key === key); return s ? s.label : key; }
function showProjectStagePicker(projectId, event) {
  if (event) event.stopPropagation();
  document.getElementById('move-menu')?.remove();
  const p = state.projects.find(x => x.id === projectId);
  if (!p) return;
  if (!(currentUserHasPermission('projects.change_stage') || currentUserHasPermission('admin.system'))) return;
  const isCompleted = p.archived === 'completed';
  const menu = document.createElement('div');
  menu.id = 'move-menu';
  menu.style.cssText = 'position:fixed;bottom:70px;left:12px;right:12px;background:#161B22;border:1px solid #30363D;border-radius:12px;z-index:70;padding:8px 0;box-shadow:0 8px 32px rgba(0,0,0,0.5);max-height:72vh;overflow-y:auto';
  const stageRows = STAGES.map(s => {
    const cur = !isCompleted && p.stage === s.key;
    return `<div onclick="document.getElementById('move-menu')?.remove();_jumpProjectStage(${projectId},'${s.key}')" style="padding:13px 20px;font-size:14px;cursor:pointer;display:flex;align-items:center;gap:10px;-webkit-tap-highlight-color:transparent;${cur ? 'background:#0D1117' : ''}">
      <span class="status-pill status-${s.color}" style="font-size:11px">${esc(s.label)}</span>
      ${cur ? '<span style="margin-left:auto;color:#3FB950;font-size:11px">current</span>' : ''}
    </div>`;
  }).join('');
  menu.innerHTML = `
    <div style="padding:8px 20px 4px;font-size:11px;font-weight:700;color:#6E7681;text-transform:uppercase;letter-spacing:.07em">Move to phase</div>
    ${stageRows}
    <div style="border-top:1px solid #30363D;margin:6px 0"></div>
    ${isCompleted
      ? `<div onclick="document.getElementById('move-menu')?.remove();unarchiveProject(${projectId})" style="padding:13px 20px;color:#C9D1D9;font-size:14px;cursor:pointer">\u21A9 Reopen (remove completed)</div>`
      : `<div onclick="document.getElementById('move-menu')?.remove();_jumpProjectCompleted(${projectId})" style="padding:13px 20px;color:#3FB950;font-weight:600;font-size:14px;cursor:pointer">\u2713 Mark Completed</div>`}
    <div style="border-top:1px solid #30363D;margin:6px 0"></div>
    <div style="padding:6px 20px 2px;font-size:11px;font-weight:700;color:#6E7681;text-transform:uppercase;letter-spacing:.07em">Archive / remove</div>
    ${ARCHIVE_BINS.filter(b => b.key !== 'completed').map(b => `<div onclick="document.getElementById('move-menu')?.remove();archiveProject(${projectId},'${b.key}')" style="padding:13px 20px;color:${b.color};font-size:14px;cursor:pointer;display:flex;align-items:center;gap:10px">${b.icon} ${esc(b.label)}</div>`).join('')}
    <div onclick="document.getElementById('move-menu')?.remove()" style="padding:12px 20px;color:#6E7681;font-size:13px;cursor:pointer;text-align:center;border-top:1px solid #30363D;margin-top:4px">Cancel</div>
  `;
  document.body.appendChild(menu);
  setTimeout(() => { const h = (e) => { if (!menu.contains(e.target)) { menu.remove(); document.removeEventListener('click', h); } }; document.addEventListener('click', h); }, 60);
}
function _jumpProjectStage(projectId, targetStage) {
  const p = state.projects.find(x => x.id === projectId);
  if (!p) return;
  const order = STAGES.map(s => s.key);
  const movingForward = p.archived === 'completed' || order.indexOf(targetStage) > order.indexOf(p.stage);
  if (movingForward) {
    const maxIdx = (STAGE_TO_PHASE_CHECK[targetStage] != null) ? STAGE_TO_PHASE_CHECK[targetStage] : -1;
    const skipped = _incompleteMilestonesUpTo(projectId, maxIdx);
    if (skipped.length) {
      const msg = 'Moving to "' + _stageLabel(targetStage) + '" skips these unfinished milestones:\n\n\u2022 ' + skipped.join('\n\u2022 ') + '\n\nMove anyway?';
      if (!confirm(msg)) return;
    }
  }
  moveProjectToStage(projectId, targetStage);
  showToast('Moved to ' + _stageLabel(targetStage), 'success');
}
function _jumpProjectCompleted(projectId) {
  const skipped = _incompleteMilestonesUpTo(projectId, PHASES.length - 1);
  if (skipped.length) {
    const msg = 'Marking completed skips these unfinished milestones:\n\n\u2022 ' + skipped.join('\n\u2022 ') + '\n\nMark completed anyway?';
    if (!confirm(msg)) return;
  }
  archiveProject(projectId, 'completed');
}
window.showProjectStagePicker = showProjectStagePicker;

function getArchivedProjects(bin) {
  return state.projects.filter(p => p.archived === bin);
}

// ── Likely to Close ──
function isLikelyToClose(projectId) {
  return !!state.likelyToClose[projectId];
}

function toggleLikelyToClose(projectId) {
  if (state.likelyToClose[projectId]) {
    delete state.likelyToClose[projectId];
  } else {
    state.likelyToClose[projectId] = new Date().toISOString();
  }
  save('vi_likely', state.likelyToClose);
  renderCurrentPage();
}

function getLikelyToCloseTotal() {
  const projects = state.projects.filter(p => !p.archived && isLikelyToClose(p.id));
  return getPipelineValue(projects);
}

// ── Column Ordering ──
function getColumnOrder(stage) {
  return state.columnOrder[stage] || [];
}

function setColumnOrder(stage, orderedIds) {
  state.columnOrder[stage] = orderedIds;
  save('vi_col_order', state.columnOrder);
}

function sortByColumnOrder(projects, stage) {
  const order = getColumnOrder(stage);
  const likely = [];
  const ordered = [];
  const rest = [];

  projects.forEach(p => {
    if (isLikelyToClose(p.id)) {
      likely.push(p);
    } else if (order.includes(p.id)) {
      ordered.push(p);
    } else {
      rest.push(p);
    }
  });

  likely.sort((a, b) => {
    const ai = order.indexOf(a.id);
    const bi = order.indexOf(b.id);
    if (ai >= 0 && bi >= 0) return ai - bi;
    return 0;
  });

  ordered.sort((a, b) => order.indexOf(a.id) - order.indexOf(b.id));

  return [...likely, ...ordered, ...rest];
}

function onReorderDragStart(e, projectId, stage) {
  e.dataTransfer.setData('text/plain', projectId);
  e.dataTransfer.setData('reorder-stage', stage);
  e.target.style.opacity = '0.4';
}

function onReorderDrop(e, targetId, stage) {
  e.preventDefault();
  e.stopPropagation();
  const sourceId = parseInt(e.dataTransfer.getData('text/plain'));
  const reorderStage = e.dataTransfer.getData('reorder-stage');

  if (!sourceId) return;

  if (reorderStage !== stage) {
    moveProjectToStage(sourceId, stage);
    return;
  }

  if (sourceId === targetId) return;

  const stageProjects = state.projects.filter(p => !p.archived && p.stage === stage);
  const sorted = sortByColumnOrder(stageProjects, stage);
  const ids = sorted.map(p => p.id);

  const fromIdx = ids.indexOf(sourceId);
  if (fromIdx >= 0) ids.splice(fromIdx, 1);
  const toIdx = ids.indexOf(targetId);
  if (toIdx >= 0) ids.splice(toIdx, 0, sourceId);
  else ids.push(sourceId);

  setColumnOrder(stage, ids);
  renderCurrentPage();
}

// ── GBB ──
function getGBBGroup(projectId) {
  for (const [gid, group] of Object.entries(state.gbbLinks)) {
    if (group.good === projectId || group.better === projectId || group.best === projectId) {
      return { groupId: gid, ...group };
    }
  }
  return null;
}

function getGBBTier(projectId) {
  const group = getGBBGroup(projectId);
  if (!group) return null;
  if (group.good === projectId) return 'good';
  if (group.better === projectId) return 'better';
  if (group.best === projectId) return 'best';
  return null;
}

function linkGBB(goodId, betterId, bestId) {
  const groupId = 'gbb_' + Date.now();
  state.gbbLinks[groupId] = { good: goodId, better: betterId, best: bestId };
  save('vi_gbb', state.gbbLinks);
}

function unlinkGBB(projectId) {
  const group = getGBBGroup(projectId);
  if (group) {
    delete state.gbbLinks[group.groupId];
    save('vi_gbb', state.gbbLinks);
  }
}

function showGBBLinkDialog(projectId) {
  const p = state.projects.find(x => x.id === projectId);
  if (!p) return;
  const existing = getGBBGroup(projectId);
  const others = state.projects.filter(x => x.id !== projectId && !x.archived && !getGBBGroup(x.id));

  const modal = document.createElement('div');
  modal.id = 'gbb-dialog';
  modal.style.cssText = 'position:fixed;inset:0;background:rgba(0,0,0,0.7);z-index:110;display:flex;align-items:center;justify-content:center;padding:20px';

  if (existing) {
    const goodP = state.projects.find(x => x.id === existing.good);
    const betterP = state.projects.find(x => x.id === existing.better);
    const bestP = state.projects.find(x => x.id === existing.best);
    modal.innerHTML = `<div style="background:#161B22;border:1px solid #30363D;border-radius:12px;padding:20px;max-width:400px;width:100%">
      <div style="font-size:15px;font-weight:600;color:#E6EDF3;margin-bottom:14px">Good / Better / Best Group</div>
      <div style="font-size:13px;color:#C9D1D9;line-height:2">
        <div>🥉 <strong>Good:</strong> ${esc(goodP?.name || 'Unknown')}</div>
        <div>🥈 <strong>Better:</strong> ${esc(betterP?.name || 'Unknown')} <span style="color:#58A6FF;font-size:11px">(counts in pipeline)</span></div>
        <div>🥇 <strong>Best:</strong> ${esc(bestP?.name || 'Unknown')}</div>
      </div>
      <div style="display:flex;gap:8px;margin-top:16px">
        <button class="btn btn-danger" onclick="unlinkGBB(${projectId});document.getElementById('gbb-dialog')?.remove();renderCurrentPage()">Unlink Group</button>
        <button class="btn" onclick="document.getElementById('gbb-dialog')?.remove()">Close</button>
      </div>
    </div>`;
  } else {
    const opts = others.map(o => `<option value="${o.id}">${esc(o.name)}${o.client_name ? ' — ' + esc(o.client_name) : ''}</option>`).join('');
    modal.innerHTML = `<div style="background:#161B22;border:1px solid #30363D;border-radius:12px;padding:20px;max-width:400px;width:100%">
      <div style="font-size:15px;font-weight:600;color:#E6EDF3;margin-bottom:4px">Link Good / Better / Best</div>
      <div style="font-size:12px;color:#6E7681;margin-bottom:14px">This project: <strong style="color:#E6EDF3">${esc(p.name)}</strong></div>
      <div class="form-group">
        <label class="form-label">This project is the…</label>
        <select class="form-select" id="gbb-tier">
          <option value="good">Good (lowest tier)</option>
          <option value="better" selected>Better (middle tier)</option>
          <option value="best">Best (highest tier)</option>
        </select>
      </div>
      <div class="form-group" id="gbb-good-group">
        <label class="form-label">Good project</label>
        <select class="form-select" id="gbb-good"><option value="">Select…</option>${opts}</select>
      </div>
      <div class="form-group" id="gbb-better-group">
        <label class="form-label">Better project</label>
        <select class="form-select" id="gbb-better"><option value="">Select…</option>${opts}</select>
      </div>
      <div class="form-group" id="gbb-best-group">
        <label class="form-label">Best project</label>
        <select class="form-select" id="gbb-best"><option value="">Select…</option>${opts}</select>
      </div>
      <div style="display:flex;gap:8px;margin-top:12px">
        <button class="btn-primary" onclick="submitGBBLink(${projectId})">Link Projects</button>
        <button class="btn" onclick="document.getElementById('gbb-dialog')?.remove()">Cancel</button>
      </div>
    </div>`;
  }
  document.body.appendChild(modal);
  modal.addEventListener('click', e => { if (e.target === modal) modal.remove(); });

  if (!existing) {
    const tierSel = document.getElementById('gbb-tier');
    function updateGBBFields() {
      const tier = tierSel.value;
      document.getElementById('gbb-good-group').style.display = tier === 'good' ? 'none' : '';
      document.getElementById('gbb-better-group').style.display = tier === 'better' ? 'none' : '';
      document.getElementById('gbb-best-group').style.display = tier === 'best' ? 'none' : '';
    }
    tierSel.addEventListener('change', updateGBBFields);
    updateGBBFields();
  }
}

function submitGBBLink(projectId) {
  const tier = document.getElementById('gbb-tier')?.value;
  const goodId = tier === 'good' ? projectId : parseInt(document.getElementById('gbb-good')?.value);
  const betterId = tier === 'better' ? projectId : parseInt(document.getElementById('gbb-better')?.value);
  const bestId = tier === 'best' ? projectId : parseInt(document.getElementById('gbb-best')?.value);
  if (!goodId || !betterId || !bestId) { alert('Please select all three projects.'); return; }
  if (new Set([goodId, betterId, bestId]).size !== 3) { alert('Each project must be different.'); return; }
  linkGBB(goodId, betterId, bestId);
  document.getElementById('gbb-dialog')?.remove();
  renderCurrentPage();
}

function getPipelineValue(projects) {
  let total = 0;
  const counted = new Set();
  projects.forEach(p => {
    if (counted.has(p.id)) return;
    const group = getGBBGroup(p.id);
    if (group) {
      if (!counted.has(group.good) && !counted.has(group.better) && !counted.has(group.best)) {
        const betterProject = state.projects.find(x => x.id === group.better);
        if (betterProject) total += betterProject.total;
        counted.add(group.good);
        counted.add(group.better);
        counted.add(group.best);
      }
    } else {
      total += p.total;
      counted.add(p.id);
    }
  });
  return total;
}

function getDashboardTitle() {
  const view = state.dashboardView || currentUserRole;
  const roleLabels = {
    admin: 'Admin Dashboard',
    sales: 'Sales Dashboard',
    design: 'Design Dashboard',
    project_manager: 'Project Management Dashboard',
    installer: 'Install Dashboard'
  };
  return `${currentUserName}\u2019s ${roleLabels[view] || 'Dashboard'}`;
}

function switchDashboardView(view) {
  state.dashboardView = view;
  renderDashboard(document.getElementById('content'));
}

// ── Drag & Drop ──
function onDragStart(e, projectId) {
  e.dataTransfer.setData('text/plain', projectId);
  e.dataTransfer.effectAllowed = 'move';
  e.target.style.opacity = '0.5';
}

function onDragEnd(e) {
  e.target.style.opacity = '1';
  document.querySelectorAll('.pipeline-col, .archive-bin').forEach(el => el.classList.remove('drag-over'));
}

function onDragOver(e) {
  e.preventDefault();
  e.dataTransfer.dropEffect = 'move';
  e.currentTarget.classList.add('drag-over');
}

function onDragLeave(e) {
  e.currentTarget.classList.remove('drag-over');
}

function onDropStage(e, stage) {
  e.preventDefault();
  e.currentTarget.classList.remove('drag-over');
  const projectId = parseInt(e.dataTransfer.getData('text/plain'));
  if (!projectId) return;
  moveProjectToStage(projectId, stage);
}

function onDropArchive(e, bin) {
  e.preventDefault();
  e.currentTarget.classList.remove('drag-over');
  const projectId = parseInt(e.dataTransfer.getData('text/plain'));
  if (!projectId) return;
  archiveProject(projectId, bin);
}

function moveProjectToStage(projectId, newStage) {
  const p = state.projects.find(x => x.id === projectId);
  if (!p) return;
  if (p.archived) {
    delete state.archived[projectId];
    save('vi_archived', state.archived);
    p.archived = null;
  }
  p.stage = newStage;
  try { localStorage.setItem('vi_projects_cache', JSON.stringify(state.projects)); } catch(e) {}
  renderCurrentPage();
}

function showMoveMenu(projectId, event) {
  event.stopPropagation();
  const existing = document.getElementById('move-menu');
  if (existing) existing.remove();

  const menu = document.createElement('div');
  menu.id = 'move-menu';
  menu.style.cssText = 'position:fixed;bottom:70px;left:12px;right:12px;background:#161B22;border:1px solid #30363D;border-radius:12px;z-index:70;padding:8px 0;box-shadow:0 8px 32px rgba(0,0,0,0.5)';

  const canChangeStage = currentUserHasPermission('projects.change_stage');
  const canDelete = currentUserHasPermission('projects.delete');

  const stageItems = canChangeStage ? STAGES.map(s =>
    `<div onclick="moveProjectToStage(${projectId},'${s.key}');document.getElementById('move-menu')?.remove()" style="padding:14px 20px;color:#C9D1D9;font-size:14px;cursor:pointer;display:flex;align-items:center;gap:10px;-webkit-tap-highlight-color:transparent">
      <span class="status-pill status-${s.color}" style="font-size:11px">${s.label}</span>
    </div>`
  ).join('') : '';

  const archiveItems = canDelete ? ARCHIVE_BINS.map(b =>
    `<div onclick="archiveProject(${projectId},'${b.key}');document.getElementById('move-menu')?.remove()" style="padding:14px 20px;color:${b.color};font-size:14px;cursor:pointer;display:flex;align-items:center;gap:10px">
      ${b.icon} ${b.label}
    </div>`
  ).join('') : '';

  const likely = isLikelyToClose(projectId);
  menu.innerHTML = `
    <div onclick="toggleLikelyToClose(${projectId});document.getElementById('move-menu')?.remove()" style="padding:14px 20px;color:${likely ? '#6E7681' : '#3FB950'};font-size:14px;cursor:pointer;display:flex;align-items:center;gap:10px;background:${likely ? 'transparent' : '#0D1A0E'};-webkit-tap-highlight-color:transparent">
      ${likely ? '⊘ Remove Likely to Close' : '★ Mark Likely to Close'}
    </div>
    ${canChangeStage ? `
      <div style="border-top:1px solid #30363D;margin:4px 0"></div>
      <div style="padding:8px 20px 4px;font-size:11px;color:#6E7681;text-transform:uppercase;letter-spacing:0.06em">Move to Stage</div>
      ${stageItems}
    ` : ''}
    ${canDelete ? `
      <div style="border-top:1px solid #30363D;margin:4px 0"></div>
      <div style="padding:8px 20px 4px;font-size:11px;color:#6E7681;text-transform:uppercase;letter-spacing:0.06em">Archive</div>
      ${archiveItems}
    ` : ''}
    <div style="border-top:1px solid #30363D;margin:4px 0"></div>
    <div onclick="document.getElementById('move-menu')?.remove()" style="padding:12px 20px;color:#6E7681;font-size:13px;cursor:pointer;text-align:center">Cancel</div>
  `;
  document.body.appendChild(menu);
  setTimeout(() => {
    document.addEventListener('click', function closer(e) {
      if (!menu.contains(e.target)) { menu.remove(); document.removeEventListener('click', closer); }
    });
  }, 10);
}

