// ── Navigation ──
function navigate(page) {
  if (typeof isContractorUser === 'function' && isContractorUser() && !CONTRACTOR_ALLOWED_PAGES.includes(page)) {
    page = 'dashboard';
  }
  state.currentPage = page;
  state.currentProject = null;
  // Home/Dashboard nav exits the Notepad sub-view (the in-page "Dashboard" pill
  // already did this; the bottom-nav Home button did not).
  if (page === 'dashboard') state.myWorkLayout = 'cards';
  document.getElementById('more-menu')?.remove();
  if (typeof removeTopbarBackButton === 'function') removeTopbarBackButton();
  document.querySelectorAll('.nav-item').forEach(el => {
    el.classList.toggle('active', el.dataset.page === page);
  });
  document.querySelectorAll('#bottom-nav .bnav-item').forEach(el => {
    const p = el.dataset.page;
    el.classList.toggle('active', p === page || (page === 'dashboard' && p === 'dashboard'));
  });
  const titles = {
    dashboard: 'Dashboard', calendar: 'Calendar', projects: 'Projects',
    'schedule-builder': 'Schedule Builder',
    'open-projects': 'Open Projects',
    shopwork: 'Shop Work', vendors: 'Vendors', intake: 'New Intake', team: 'Team',
    'feature-requests': 'Feature Requests'
  };
  document.getElementById('page-title').textContent = titles[page] || 'Dashboard';
  renderCurrentPage();
}

function toggleSidebar() {
  document.getElementById('sidebar').classList.toggle('open');
}

let _navRestored = false;
function _persistNav() {
  // Per-device, NOT synced (no vi_ prefix) — remembers the last page so a reload stays put.
  // Don't save until the boot-time restore has run, or early renders overwrite the remembered page.
  if (!_navRestored) return;
  try {
    localStorage.setItem('nav_last', JSON.stringify({
      page: state.currentPage,
      projectId: state.currentPage === 'project' ? (state.currentProject?.id ?? null) : null,
      projectTab: state.currentPage === 'project' ? (state.projectTab || null) : null,
      rightPanel: state.rightPanel || null,
      activeConversation: state.rightPanel === 'messages' ? (state.activeConversation || null) : null
    }));
  } catch (e) {}
}

function _ensureMobileFitStyles() {
  if (document.getElementById('vi-mobile-fit')) return;
  const st = document.createElement('style');
  st.id = 'vi-mobile-fit';
  st.textContent = `
    @media (max-width: 768px) {
      #main, #content { min-width: 0; max-width: 100vw; }
      /* Root cause: the body-wrap is a column flex with align-items:flex-start on
         mobile, which sizes the body to its widest content instead of the screen.
         Stretch it so cards fit the viewport (no clipping, no zoom needed). */
      .project-page-body-wrap { align-items: stretch; }
      .project-page-body { width: 100%; align-self: stretch; min-width: 0; }
      #content .dashboard-card { max-width: 100%; box-sizing: border-box; }
      #content img { max-width: 100%; height: auto; }
      .attn-grid { grid-template-columns: 1fr !important; }
      /* In-cell month event chips: on a narrow phone column long titles were
         wrapping one word per line into tall chips. Force a single truncated
         line (matching the multi-day bars). min-width:0 handles flex children. */
      .mcal-month-event {
        white-space: nowrap !important;
        overflow: hidden !important;
        text-overflow: ellipsis !important;
        min-width: 0 !important;
      }
      .mcal-month-event > * { min-width: 0; overflow: hidden; text-overflow: ellipsis; }
      .mcal-month-event-label {
        white-space: nowrap !important;
        overflow: hidden !important;
        text-overflow: ellipsis !important;
        min-width: 0 !important;
      }
    }
  `;
  document.head.appendChild(st);
}
function _ensurePhaseFocusStyles() {
  if (document.getElementById('vi-phase-focus')) return;
  const st = document.createElement('style');
  st.id = 'vi-phase-focus';
  // Focus+context: completed/upcoming phase labels shrink to abbreviations; the
  // phase(s) currently in progress grow to stay readable. Space is grow-weighted,
  // so wider screens reveal more text. The progress BAR stays proportional.
  st.textContent = `
    /* Bar segments share the SAME focus weights as the labels (zero gap on both),
       so each phase's segment sits directly above its label. */
    .pmap-track-focus { display: flex; gap: 0; }
    .pmap-track-focus .pmap-seg { width: auto; min-width: 0; }
    .pmap-track-focus .pmap-seg.pmap-seg-done,
    .pmap-track-focus .pmap-seg.pmap-seg-future { flex: 1 1 0; }
    .pmap-track-focus .pmap-seg.pmap-seg-active { flex: 5 1 0; }

    .pmap-labels-focus { display: flex; gap: 0; align-items: flex-start; }
    .pmap-labels-focus .pmap-label { width: auto; min-width: 0; overflow: hidden; padding: 5px 5px 0 0; text-align: left; box-sizing: border-box; }
    .pmap-labels-focus .pmap-label.pmap-done,
    .pmap-labels-focus .pmap-label.pmap-future { flex: 1 1 0; }
    .pmap-labels-focus .pmap-label.pmap-active { flex: 5 1 0; }
    .pmap-labels-focus .pmap-label-name { white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }
    .pmap-labels-focus .pmap-label.pmap-future .pmap-label-name { opacity: 0.6; }

    .ready-sublabels-focus { display: flex; gap: 6px; }
    .ready-sublabels-focus .ready-sales-sublabel { width: auto; min-width: 0; }
    .ready-sublabels-focus .rsl-done,
    .ready-sublabels-focus .rsl-future { flex: 1 1 0; }
    .ready-sublabels-focus .rsl-active { flex: 5 1 0; }
    body:not(.can-del-tasks) .itask-del { display: none !important; }
    .itask-reorder { display:inline-flex; flex-direction:column; gap:1px; flex:0 0 auto; margin-right:2px; }
    .itask-ord-btn { width:22px; height:18px; line-height:1; padding:0; font-size:9px; border:1px solid #30363D; background:#161B22; color:#8B949E; border-radius:4px; cursor:pointer; display:grid; place-items:center; }
    .itask-ord-btn:active { background:#1F2630; color:#E6EDF3; }
  `;
  document.head.appendChild(st);
}
function _canDeleteTasks() {
  if (currentUserHasPermission('admin.system')) return true; // Master Admin (Jacob)
  const bk = getActiveUserBundleKey();
  // Install Manager (Clint) + anyone with project-management responsibilities.
  return ['master_admin', 'install_admin', 'project_coordinator', 'project_manager'].includes(bk);
}
// Pin currentUserName/currentUserRole to the resolved login for non-admins so
// no stale device default (e.g. the owner) shows through. Master admins keep
// switcher-driven identity.
function _bindLoginIdentity() {
  if (canSwitchUsers()) return;
  const _lid = getAuthMemberId();
  const _lm = _lid != null ? getTeamMember(_lid) : null;
  if (!_lm) return;
  currentUserName = _lm.name;
  currentUserRole = _lm.primaryRole || (Array.isArray(_lm.access) && _lm.access[0]) || 'installer';
  state.dashboardView = currentUserRole;
  try { localStorage.setItem('vi_user', currentUserName); localStorage.setItem('vi_role', currentUserRole); } catch (e) {}
}
function renderCurrentPage() {
  _ensureMobileFitStyles();
  _ensurePhaseFocusStyles();
  if (_isUnlinkedLogin()) { _renderUnlinkedLock(); return; }
  { const _lk = document.getElementById('vi-unlinked-lock'); if (_lk) _lk.remove(); }
  _bindLoginIdentity();
  _reconcileArchived();
  try { document.body.classList.toggle('can-del-tasks', _canDeleteTasks()); } catch (e) {}
  const c = document.getElementById('content');
  if (!c) return;
  // Cleanup any lingering floating tooltips before re-rendering. Defensive —
  // covers any navigation path that bypasses openProject().
  const tip = document.getElementById('cal-hover-tip');
  if (tip) tip.style.display = 'none';
  try {
    switch (state.currentPage) {
      case 'dashboard': renderDashboard(c); break;
      case 'calendar': renderCalendar(c); break;
      case 'schedule-builder': renderScheduleBuilder(c); break;
      case 'projects': renderProjects(c); break;
      case 'open-projects': renderOpenProjects(c); break;
      case 'shopwork': renderShopWork(c); break;
      case 'vendors': renderVendors(c); break;
      case 'intake': renderIntake(c); break;
      case 'team': renderTeam(c); break;
      case 'admin': renderAdmin(c); break;
      case 'settings': renderSettings(c); break;
      case 'feature-requests': renderFeatureRequests(c); break;
      case 'project': renderProjectPage(c); break;
      default: renderDashboard(c);
    }
  } catch (e) {
    c.innerHTML = `<div class="alert alert-error">Render error: ${e.message}</div>`;
    console.error(e);
  }
  updateRightPanel();
  if (typeof updateContextNav === 'function') updateContextNav();
  _persistNav();
}

// ── Project Page Navigation ──
// v1.16: project detail is a full page, not a modal
function openProject(id, tabOrAnchor, anchor) {
  if (typeof isContractorUser === 'function' && isContractorUser()) {
    if (typeof showToast === 'function') showToast('Contractors can only see their assigned work', 'info');
    return;
  }
  const p = state.projects.find(x => x.id === id);
  if (!p) return;
  // Cleanup any lingering calendar hover tooltip — fixed-position element
  // appended to body persists across page navigations otherwise.
  _calHoverLeave();
  // Remember where we came from so Back returns to the right page
  if (state.currentPage && state.currentPage !== 'project') {
    state.projectOrigin = state.currentPage;
  } else if (!state.projectOrigin) {
    state.projectOrigin = 'dashboard';
  }
  state.currentProject = p;
  // If second arg looks like a known tab, use it as the tab. Otherwise treat as anchor on default tab.
  const KNOWN_TABS = ['overview','progress','details','design','install','schedule','assets','location','files','notes'];
  let tab = getDefaultProjectTab();
  let anchorKey = null;
  if (tabOrAnchor && KNOWN_TABS.includes(tabOrAnchor)) {
    tab = tabOrAnchor;
    anchorKey = anchor || null;
  } else if (tabOrAnchor) {
    // It's an anchor, not a tab. Decide which tab the anchor belongs to.
    anchorKey = tabOrAnchor;
    if (anchorKey === 'attention' || anchorKey === 'needs-attention') tab = 'overview';
    else tab = 'progress'; // milestone anchors default to progress
  }
  state.projectTab = tab;
  state.projectPendingAnchor = anchorKey;
  state.currentPage = 'project';
  document.querySelectorAll('.nav-item').forEach(el => el.classList.remove('active'));
  document.querySelectorAll('#bottom-nav .bnav-item').forEach(el => el.classList.remove('active'));
  const titleEl = document.getElementById('page-title');
  if (titleEl) titleEl.textContent = p.name;
  injectTopbarBackButton();
  renderCurrentPage();
  const c = document.getElementById('content');
  if (c) c.scrollTop = 0;
  // After render, scroll to anchor if specified
  if (anchorKey) {
    setTimeout(() => scrollToProjectAnchor(anchorKey), 100);
  }
}

// Scroll to a labeled anchor within the project page and briefly highlight it
function scrollToProjectAnchor(anchorKey) {
  if (!anchorKey) return;
  const el = document.querySelector(`[data-project-anchor="${anchorKey}"]`);
  if (!el) return;
  const rect = el.getBoundingClientRect();
  const offset = 20;
  window.scrollTo({ top: window.scrollY + rect.top - offset, behavior: 'smooth' });
  // Briefly highlight
  el.classList.add('project-anchor-flash');
  setTimeout(() => el.classList.remove('project-anchor-flash'), 1800);
  state.projectPendingAnchor = null;
}

function injectTopbarBackButton() {
  // Remove any existing back button first
  document.getElementById('topbar-back-btn')?.remove();
  const titleEl = document.getElementById('page-title');
  if (!titleEl) return;
  const btn = document.createElement('button');
  btn.id = 'topbar-back-btn';
  btn.className = 'topbar-back-btn';
  btn.setAttribute('aria-label', 'Back');
  btn.title = 'Back';
  btn.innerHTML = '<svg width="16" height="16" viewBox="0 0 14 14" fill="none"><path d="M9 2L4 7l5 5" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round"/></svg>';
  btn.onclick = function() { closeProjectPage(); };
  titleEl.parentNode.insertBefore(btn, titleEl);
}

function removeTopbarBackButton() {
  document.getElementById('topbar-back-btn')?.remove();
}

function getDefaultProjectTab() {
  const view = state.dashboardView || currentUserRole;
  if (view === 'design') return 'design';
  if (view === 'installer' || view === 'project_manager') return 'install';
  return 'overview';
}

function closeProjectPage() {
  state.currentProject = null;
  removeTopbarBackButton();
  const origin = state.projectOrigin || 'dashboard';
  state.projectOrigin = null;
  navigate(origin);
}

function switchProjectTab(tab) {
  state.projectTab = tab;
  renderProjectPage(document.getElementById('content'));
}

// ── To-Do List (per-role) ──
function getTodos(role) {
  return (state.todos[role] || []);
}

function addTodo(text) {
  const role = state.dashboardView || currentUserRole;
  if (!state.todos[role]) state.todos[role] = [];
  state.todos[role].unshift({ id: Date.now(), text, done: false, doneAt: null });
  save('vi_todos', state.todos);
  renderCurrentPage();
}

function toggleTodo(id) {
  const role = state.dashboardView || currentUserRole;
  const item = (state.todos[role] || []).find(t => t.id === id);
  if (!item) return;
  item.done = !item.done;
  item.doneAt = item.done ? new Date().toISOString() : null;
  save('vi_todos', state.todos);
  renderCurrentPage();
}

function deleteTodo(id) {
  const role = state.dashboardView || currentUserRole;
  state.todos[role] = (state.todos[role] || []).filter(t => t.id !== id);
  save('vi_todos', state.todos);
  renderCurrentPage();
}

function clearCompletedTodos() {
  const role = state.dashboardView || currentUserRole;
  state.todos[role] = (state.todos[role] || []).filter(t => !t.done);
  save('vi_todos', state.todos);
  renderCurrentPage();
}

// ── Tasks ──
function getTaskUrgency(dueDate) {
  if (!dueDate) return { label: '', color: '#6E7681', bg: 'transparent', border: '#1C2333' };
  const now = new Date(); now.setHours(0,0,0,0);
  const due = new Date(dueDate); due.setHours(0,0,0,0);
  const diff = Math.round((due - now) / 86400000);
  if (diff < 0)  return { label: 'Overdue',   color: '#F85149', bg: '#1A0D0D', border: '#DA363344' };
  if (diff === 0) return { label: 'Today',    color: '#D29922', bg: '#1A130D', border: '#9E6A0344' };
  if (diff <= 3)  return { label: `${diff}d`,  color: '#58A6FF', bg: '#0D1626', border: '#1565C044' };
  if (diff <= 7)  return { label: `${diff}d`,  color: '#8B949E', bg: '#0D1117', border: '#1C2333' };
  return              { label: fmtDate(dueDate), color: '#6E7681', bg: '#0D1117', border: '#1C2333' };
}

function addTask(text, dueDate, projectId) {
  const activeMemberId = getActiveTeamMemberId();
  state.tasks.push({
    id: Date.now(),
    text,
    dueDate: dueDate || '',
    projectId: projectId || null,
    memberId: activeMemberId,
    done: false,
    doneAt: null
  });
  state.tasks.sort((a, b) => {
    if (!a.dueDate && !b.dueDate) return 0;
    if (!a.dueDate) return 1;
    if (!b.dueDate) return -1;
    return a.dueDate.localeCompare(b.dueDate);
  });
  save('vi_tasks', state.tasks);
  renderCurrentPage();
}

function toggleTask(id) {
  const task = state.tasks.find(t => t.id === id);
  if (!task) return;
  task.done = !task.done;
  task.doneAt = task.done ? new Date().toISOString() : null;
  save('vi_tasks', state.tasks);
  renderCurrentPage();
}

function deletePersonalTask(id) {
  // Personal "My Tasks"/Notepad manual items (state.tasks, memberId-based).
  // Renamed from deleteTask so it no longer shadows the store-agnostic
  // deleteTask() that handles design/install tasks.
  state.tasks = state.tasks.filter(t => t.id !== id);
  save('vi_tasks', state.tasks);
  renderCurrentPage();
}

// ── Project Assignments (Pass 3B: expanded role slots) ──
// New shape per project: { sales: [{id, lead}], design: [...], pm: [...], install: [...], warehouse: [...] }
// Legacy shape: { design: [1, 2], install: [3] } — auto-migrated on access
const ASSIGNMENT_ROLES = [
  { key: 'sales',     label: 'Sales',       color: '#3FB950', desc: 'Client relationship, contract holder' },
  { key: 'design',    label: 'Design',      color: '#A371F7', desc: 'CAD, engineering, BOM' },
  { key: 'pm',        label: 'Project Manager', color: '#58A6FF', desc: 'Owns schedule + coordination' },
  { key: 'install',   label: 'Install',     color: '#F85149', desc: 'On-site crew' },
  { key: 'warehouse', label: 'Warehouse',   color: '#F0883E', desc: 'Receiving + staging' }
];

function migrateAssignment(a) {
  // Normalize a project's assignment object to new shape. Handles legacy and new.
  const out = { sales: [], design: [], pm: [], install: [], warehouse: [] };
  if (!a) return out;
  ASSIGNMENT_ROLES.forEach(r => {
    const raw = a[r.key];
    if (!raw) { out[r.key] = []; return; }
    if (Array.isArray(raw)) {
      out[r.key] = raw.map((item, idx) => {
        if (typeof item === 'number' || typeof item === 'string') {
          // Legacy: bare member id — first one becomes lead
          return { id: parseInt(item), lead: idx === 0 };
        }
        if (item && typeof item === 'object') {
          return { id: parseInt(item.id), lead: !!item.lead };
        }
        return null;
      }).filter(Boolean);
    }
  });
  return out;
}

function getProjectAssignment(projectId) {
  const raw = state.assignments[projectId];
  return migrateAssignment(raw);
}

function setProjectAssignment(projectId, role, list) {
  if (!state.assignments[projectId]) state.assignments[projectId] = {};
  // Persist migrated version of whole project to avoid future legacy reads
  const full = migrateAssignment(state.assignments[projectId]);
  full[role] = list;
  state.assignments[projectId] = full;
  // Awaited cloud upsert (not just the passive mirror) so assignment changes
  // can't silently revert when a mobile PWA backgrounds.
  _syncKeyNow('vi_assignments', state.assignments).then(r => {
    if (!r.ok) showToast('Assignment didn\u2019t save: ' + r.err + ' \u2014 try again', 'error');
  });
}

function isAssignedToProject(memberId, projectId, role) {
  const a = getProjectAssignment(projectId);
  if (role) return (a[role] || []).some(x => x.id === memberId);
  return ASSIGNMENT_ROLES.some(r => (a[r.key] || []).some(x => x.id === memberId));
}

function isLeadOnProject(memberId, projectId, role) {
  const a = getProjectAssignment(projectId);
  return (a[role] || []).some(x => x.id === memberId && x.lead);
}

function getLeadForRole(projectId, role) {
  const a = getProjectAssignment(projectId);
  return (a[role] || []).find(x => x.lead) || null;
}

function toggleRoleAssignment(projectId, role, memberId) {
  const a = getProjectAssignment(projectId);
  const list = a[role] || [];
  const idx = list.findIndex(x => x.id === memberId);
  if (idx >= 0) {
    const wasLead = list[idx].lead;
    list.splice(idx, 1);
    // If the removed member was Lead and there are others left, promote the first one
    if (wasLead && list.length > 0) list[0].lead = true;
  } else {
    // If no one is Lead yet, make this new assignee the Lead
    const hasLead = list.some(x => x.lead);
    list.push({ id: memberId, lead: !hasLead });
  }
  setProjectAssignment(projectId, role, list);
  // Always re-render — mobile paths and dashboard surfaces need the update too,
  // not just the project page in-place panel
  renderCurrentPage();
}

function setRoleLead(projectId, role, memberId) {
  // Find current lead and count affected manual actions before prompting
  const a = getProjectAssignment(projectId);
  const list = a[role] || [];
  const currentLead = list.find(x => x.lead);
  const currentLeadId = currentLead?.id || null;

  // If no change, just return
  if (currentLeadId === memberId) return;

  // Count manual actions on this project assigned to current lead
  const newLeadName = getTeamMember(memberId)?.name || 'this person';
  const oldLeadName = currentLeadId ? (getTeamMember(currentLeadId)?.name || 'previous lead') : null;
  const affectedManual = (state.actionsManual || []).filter(m =>
    m.projectId === projectId &&
    currentLeadId &&
    m.assigneeId === currentLeadId
  );

  // Auto-actions auto-cascade because they're computed live from the lead.
  // For manual actions, prompt the user.
  const projectName = state.projects.find(p => p.id === projectId)?.name || 'this project';
  const proceed = function(reassignManual) {
    list.forEach(x => x.lead = (x.id === memberId));
    setProjectAssignment(projectId, role, list);
    if (reassignManual && affectedManual.length > 0) {
      affectedManual.forEach(m => { m.assigneeId = memberId; });
      _persistActionsManual();
    }
    if (state.currentPage === 'project' && state.currentProject?.id === projectId) {
      renderCurrentPage();
    } else {
      renderCurrentPage();
    }
    if (typeof showToast === 'function') {
      const note = affectedManual.length > 0 && reassignManual
        ? ` &middot; ${affectedManual.length} manual action${affectedManual.length === 1 ? '' : 's'} reassigned`
        : '';
      showToast(`${role} lead set to ${newLeadName}${note}`, 'success');
    }
  };

  if (oldLeadName && affectedManual.length > 0) {
    // Prompt with checkbox
    document.getElementById('lead-cascade-dialog')?.remove();
    const overlay = document.createElement('div');
    overlay.id = 'lead-cascade-dialog';
    overlay.className = 'modal-overlay';
    overlay.innerHTML = `
      <div class="modal-container" style="max-width:420px">
        <div class="modal-header">
          <div class="modal-title">Change ${esc(role)} lead?</div>
          <button class="modal-close" onclick="document.getElementById('lead-cascade-dialog')?.remove()">&times;</button>
        </div>
        <div class="modal-body">
          <div style="font-size:13px;color:#C9D1D9;line-height:1.5;margin-bottom:14px">
            ${esc(role.charAt(0).toUpperCase() + role.slice(1))} lead on <strong>${esc(projectName)}</strong> changes from <strong>${esc(oldLeadName)}</strong> to <strong>${esc(newLeadName)}</strong>.
          </div>
          <div style="background:#0D1117;border:1px solid #1C2333;border-radius:6px;padding:10px 12px;margin-bottom:14px">
            <div style="font-size:11px;color:#8B949E;margin-bottom:6px">Auto-derived actions reassign automatically.</div>
            <label style="display:flex;align-items:flex-start;gap:8px;cursor:pointer;font-size:12px;color:#E6EDF3">
              <input type="checkbox" id="cascade-manual" checked style="margin-top:2px">
              <span>Also reassign <strong>${affectedManual.length} manual action${affectedManual.length === 1 ? '' : 's'}</strong> previously assigned to ${esc(oldLeadName)}</span>
            </label>
          </div>
          <div style="display:flex;gap:8px">
            <button type="button" class="btn" onclick="document.getElementById('lead-cascade-dialog')?.remove()" style="flex:1">Cancel</button>
            <button type="button" class="btn-primary" onclick="_confirmLeadChange(${projectId}, '${role}', ${memberId})" style="flex:2">Change Lead</button>
          </div>
        </div>
      </div>
    `;
    document.body.appendChild(overlay);
  } else {
    // No manual actions affected — just proceed
    proceed(false);
  }
}

function _confirmLeadChange(projectId, role, memberId) {
  const cascade = document.getElementById('cascade-manual')?.checked || false;
  const a = getProjectAssignment(projectId);
  const list = a[role] || [];
  const currentLead = list.find(x => x.lead);
  const currentLeadId = currentLead?.id || null;
  const affectedManual = (state.actionsManual || []).filter(m =>
    m.projectId === projectId &&
    currentLeadId &&
    m.assigneeId === currentLeadId
  );
  list.forEach(x => x.lead = (x.id === memberId));
  setProjectAssignment(projectId, role, list);
  if (cascade && affectedManual.length > 0) {
    affectedManual.forEach(m => { m.assigneeId = memberId; });
    _persistActionsManual();
  }
  document.getElementById('lead-cascade-dialog')?.remove();
  const newLeadName = getTeamMember(memberId)?.name || 'this person';
  const note = cascade && affectedManual.length > 0
    ? ` · ${affectedManual.length} manual action${affectedManual.length === 1 ? '' : 's'} reassigned`
    : '';
  if (typeof showToast === 'function') showToast(`${role} lead set to ${newLeadName}${note}`, 'success');
  renderCurrentPage();
}

// ── Legacy compatibility — used by old renderers until migrated ──
function isAssignedTo(projectId, phase, memberId) {
  // Old callers pass 'design' or 'install' — map 'install' correctly
  return isAssignedToProject(memberId, projectId, phase);
}

function toggleProjectAssignment(projectId, phase, memberId) {
  toggleRoleAssignment(projectId, phase, memberId);
}

function getDerivedTasks(role) {
  const derived = [];
  const activeProjects = state.projects.filter(p => !p.archived);
  const memberId = getActiveTeamMemberId();

  if (role === 'design' || role === 'admin') {
    activeProjects.forEach(p => {
      if (!['proposal','sent','contract'].includes(p.stage)) return;
      if (role !== 'admin' && !isAssignedTo(p.id, 'design', memberId)) return;
      p.systems.forEach(sys => {
        const template = TEMPLATES.design[sys];
        if (!template) return;
        const checkKey = `${p.id}_design_${sys}`;
        const checks = state.checklists[checkKey] || {};
        const incomplete = template.items.filter((_, i) => !checks[i]);
        if (incomplete.length > 0) {
          derived.push({
            id: `derived_design_${p.id}_${sys}`,
            text: `${template.name}: ${incomplete.length} item${incomplete.length !== 1 ? 's' : ''} remaining`,
            projectId: p.id,
            projectName: p.name,
            dueDate: p.start_date || '',
            source: 'design',
            done: false
          });
        }
      });
    });
  }

  if (role === 'installer' || role === 'project_manager' || role === 'admin') {
    // Surface incomplete subtasks from the unified Install Tasks system. For
    // installers/PMs, show subtasks where they're an assignee. For admins,
    // show all open subtasks on contract-stage projects.
    const contractProjectIds = new Set(activeProjects.filter(p => p.stage === 'contract').map(p => p.id));
    (state.installTasks || []).forEach(t => {
      if (t.projectId == null) return;
      if (!contractProjectIds.has(t.projectId)) return;
      const proj = activeProjects.find(p => p.id === t.projectId);
      if (!proj) return;
      (t.subtasks || []).forEach(s => {
        if (s.done) return;
        const youAssigned = Array.isArray(s.assigneeIds) && s.assigneeIds.includes(memberId);
        if (role !== 'admin' && !youAssigned) return;
        derived.push({
          id: `derived_itask_${t.id}_${s.id}`,
          text: `${t.title}: ${s.title}`,
          projectId: t.projectId,
          projectName: proj.name,
          dueDate: s.date || '',
          source: 'install',
          done: false
        });
      });
      // Milestone tasks the viewer is responsible for (or any milestone for admin)
      if (t.isMilestone && !t.done) {
        const responsible = Array.isArray(t.assigneeIds) && t.assigneeIds.includes(memberId);
        if (role === 'admin' || responsible) {
          derived.push({
            id: `derived_milestone_${t.id}`,
            text: `🚩 ${t.title}`,
            projectId: t.projectId,
            projectName: proj.name,
            dueDate: t.dueDate || '',
            source: 'install',
            done: false
          });
        }
      }
    });
  }

  return derived;
}

function showAddTaskDialog() {
  let d = document.getElementById('add-task-dialog');
  if (d) { d.remove(); return; }
  d = document.createElement('div');
  d.id = 'add-task-dialog';
  d.style.cssText = 'position:fixed;inset:0;background:rgba(0,0,0,0.7);z-index:120;display:flex;align-items:center;justify-content:center;padding:20px';

  const projectOptions = state.projects
    .filter(p => !p.archived)
    .map(p => `<option value="${p.id}">${esc(p.name)}</option>`)
    .join('');

  d.innerHTML = `
    <div style="background:#161B22;border:1px solid #30363D;border-radius:12px;padding:20px;max-width:380px;width:100%">
      <div style="font-size:15px;font-weight:600;color:#E6EDF3;margin-bottom:16px">Add Task</div>
      <div class="form-group">
        <label class="form-label">Task</label>
        <input class="form-input" id="new-task-text" placeholder="What needs to get done?" autofocus>
      </div>
      <div class="form-row">
        <div class="form-group">
          <label class="form-label">Due Date</label>
          <input class="form-input" type="date" id="new-task-date">
        </div>
        <div class="form-group">
          <label class="form-label">Project <span style="color:#6E7681;font-weight:400">(optional)</span></label>
          <select class="form-select" id="new-task-project">
            <option value="">None</option>
            ${projectOptions}
          </select>
        </div>
      </div>
      <div style="display:flex;gap:8px;margin-top:4px">
        <button class="btn-primary" onclick="submitAddTask()" style="flex:1;padding:11px">Add Task</button>
        <button class="btn" onclick="document.getElementById('add-task-dialog')?.remove()">Cancel</button>
      </div>
    </div>
  `;
  document.body.appendChild(d);
  d.addEventListener('click', e => { if (e.target === d) d.remove(); });
  document.getElementById('new-task-text')?.focus();

  document.getElementById('new-task-text')?.addEventListener('keydown', e => {
    if (e.key === 'Enter') submitAddTask();
  });
}

function switchWidgetTab(tab) {
  state.widgetTab = tab;
  renderCurrentPage();
}

function switchWidgetFilter(filter) {
  state.widgetFilter = filter;
  renderCurrentPage();
}

function toggleWidgetCollapsed() {
  state.widgetCollapsed = !state.widgetCollapsed;
  renderCurrentPage();
}

function toggleColExpanded(stage) {
  state.expandedCols[stage] = !state.expandedCols[stage];
  renderCurrentPage();
}

function submitAddTask() {
  const text = document.getElementById('new-task-text')?.value?.trim();
  const dueDate = document.getElementById('new-task-date')?.value || '';
  const projectId = parseInt(document.getElementById('new-task-project')?.value) || null;
  if (!text) { document.getElementById('new-task-text')?.focus(); return; }
  addTask(text, dueDate, projectId);
  document.getElementById('add-task-dialog')?.remove();
}
// ── Dashboard Widgets ──
function renderTodoWidget(role) {
  const all = getTodos(role);
  const active = all.filter(t => !t.done);
  const done = all.filter(t => t.done);
  const showAll = state._todoExpanded;
  const visible = showAll ? active : active.slice(0, 5);
  const hidden = active.length - 5;

  const roleLabel = DASHBOARD_ACCESS.find(d => d.key === role)?.label || role;
  const roleColor = DASHBOARD_ACCESS.find(d => d.key === role)?.color || '#8B949E';

  return `
    <div class="dashboard-card" style="height:100%">
      <div class="dashboard-card-title" style="display:flex;align-items:center;justify-content:space-between;margin-bottom:10px">
        <span>To-Do <span style="font-size:10px;font-weight:400;color:${roleColor};padding:1px 6px;border-radius:3px;background:${roleColor}18;margin-left:4px">${roleLabel}</span></span>
        ${active.length > 0 ? `<span style="font-size:11px;color:#6E7681;font-weight:400">${active.length} open</span>` : ''}
      </div>

      <div style="display:flex;gap:6px;margin-bottom:10px">
        <input class="form-input" id="todo-input-${role}" placeholder="Add item…"
          style="flex:1;padding:8px 10px;font-size:13px"
          onkeydown="if(event.key==='Enter'){const v=this.value.trim();if(v){addTodo(v);this.value=''}}">
        <button class="btn-primary" style="padding:8px 12px;font-size:13px;flex-shrink:0"
          onclick="const v=document.getElementById('todo-input-${role}')?.value?.trim();if(v){addTodo(v);document.getElementById('todo-input-${role}').value=''}">+</button>
      </div>

      ${active.length === 0 && done.length === 0 ? `
        <div style="text-align:center;padding:16px 0;color:#6E7681;font-size:12px">No items — add one above</div>
      ` : ''}

      <div style="display:flex;flex-direction:column;gap:2px">
        ${visible.map(t => `
          <div style="display:flex;align-items:center;gap:8px;padding:7px 6px;border-radius:6px;background:#0D1117;border:1px solid #1C2333;margin-bottom:2px">
            <div onclick="toggleTodo(${t.id})" style="width:16px;height:16px;border-radius:4px;border:1.5px solid #30363D;cursor:pointer;flex-shrink:0;display:flex;align-items:center;justify-content:center;-webkit-tap-highlight-color:transparent"></div>
            <span style="flex:1;font-size:13px;color:#C9D1D9;line-height:1.3">${esc(t.text)}</span>
            <button onclick="deleteTodo(${t.id})" style="background:none;border:none;color:#6E7681;cursor:pointer;padding:2px 4px;font-size:14px;line-height:1;-webkit-tap-highlight-color:transparent" title="Remove">×</button>
          </div>
        `).join('')}
      </div>

      ${!showAll && hidden > 0 ? `
        <div onclick="state._todoExpanded=true;renderCurrentPage()" style="font-size:11px;color:#58A6FF;cursor:pointer;padding:6px 0;text-align:center;-webkit-tap-highlight-color:transparent">
          +${hidden} more
        </div>
      ` : showAll && active.length > 5 ? `
        <div onclick="state._todoExpanded=false;renderCurrentPage()" style="font-size:11px;color:#6E7681;cursor:pointer;padding:6px 0;text-align:center">
          Show less
        </div>
      ` : ''}

      ${done.length > 0 ? `
        <details style="margin-top:8px">
          <summary style="font-size:11px;color:#6E7681;cursor:pointer;list-style:none;display:flex;align-items:center;gap:6px;-webkit-tap-highlight-color:transparent">
            <svg width="10" height="10" viewBox="0 0 10 10" fill="none"><path d="M2 4l3 3 3-3" stroke="currentColor" stroke-width="1.3" stroke-linecap="round"/></svg>
            ${done.length} completed
            <span onclick="event.preventDefault();event.stopPropagation();clearCompletedTodos()" style="color:#F85149;margin-left:auto;font-size:10px">Clear all</span>
          </summary>
          <div style="margin-top:6px;display:flex;flex-direction:column;gap:2px">
            ${done.slice(0, 8).map(t => `
              <div style="display:flex;align-items:center;gap:8px;padding:6px;border-radius:6px;opacity:0.5">
                <div onclick="toggleTodo(${t.id})" style="width:16px;height:16px;border-radius:4px;border:1.5px solid #3FB950;background:#3FB95022;cursor:pointer;flex-shrink:0;display:flex;align-items:center;justify-content:center">
                  <svg width="9" height="9" viewBox="0 0 9 9" fill="none"><path d="M1.5 4.5l2 2L7.5 2" stroke="#3FB950" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"/></svg>
                </div>
                <span style="flex:1;font-size:12px;color:#6E7681;text-decoration:line-through">${esc(t.text)}</span>
                <button onclick="deleteTodo(${t.id})" style="background:none;border:none;color:#6E7681;cursor:pointer;padding:2px 4px;font-size:14px">×</button>
              </div>
            `).join('')}
          </div>
        </details>
      ` : ''}
    </div>
  `;
}

function renderTasksWidget(role) {
  const memberId = getActiveTeamMemberId();
  const filter = state.widgetFilter;

  const now = new Date(); now.setHours(0,0,0,0);
  const weekOut = new Date(now); weekOut.setDate(weekOut.getDate() + 7);

  function isThisWeek(dueDate) {
    if (!dueDate) return false;
    const d = new Date(dueDate); d.setHours(0,0,0,0);
    return d <= weekOut;
  }

  const allManual = state.tasks.filter(t => t.memberId === memberId && !t.done);
  const completedTasks = state.tasks.filter(t => t.memberId === memberId && t.done);
  const derived = getDerivedTasks(role);

  const manualFiltered = filter === 'week'
    ? allManual.filter(t => !t.dueDate || isThisWeek(t.dueDate))
    : allManual;

  const manualSorted = [...manualFiltered].sort((a, b) => {
    if (!a.dueDate && !b.dueDate) return 0;
    if (!a.dueDate) return 1;
    if (!b.dueDate) return -1;
    return a.dueDate.localeCompare(b.dueDate);
  });

  const allActive = [...derived, ...manualSorted];
  const hiddenCount = filter === 'week' ? allManual.filter(t => t.dueDate && !isThisWeek(t.dueDate)).length : 0;

  return `
    <div class="dashboard-card" style="height:100%">
      <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:10px">
        <div class="dashboard-card-title" style="margin-bottom:0">Tasks</div>
        <div style="display:flex;align-items:center;gap:6px">
          <div style="display:flex;background:#0D1117;border:1px solid #30363D;border-radius:5px;overflow:hidden;font-size:11px">
            <div onclick="switchWidgetFilter('week')" style="padding:4px 10px;cursor:pointer;-webkit-tap-highlight-color:transparent;${filter === 'week' ? 'background:#1565C0;color:#58A6FF;font-weight:500' : 'color:#6E7681'}">This Week</div>
            <div onclick="switchWidgetFilter('all')" style="padding:4px 10px;cursor:pointer;-webkit-tap-highlight-color:transparent;${filter === 'all' ? 'background:#1565C0;color:#58A6FF;font-weight:500' : 'color:#6E7681'}">All</div>
          </div>
          <button class="btn btn-sm" onclick="showAddTaskDialog()" style="font-size:11px;padding:4px 10px">+ Add</button>
        </div>
      </div>

      ${allActive.length === 0 ? `
        <div style="text-align:center;padding:16px 0;color:#6E7681;font-size:12px">
          ${filter === 'week' ? 'No tasks due this week' : 'No tasks yet'}
        </div>
      ` : ''}

      <div style="display:flex;flex-direction:column;gap:4px;max-height:320px;overflow-y:auto;padding-right:2px">
        ${allActive.map(t => {
          const urgency = getTaskUrgency(t.dueDate);
          const proj = t.projectId ? state.projects.find(p => p.id === t.projectId) : null;
          const isDerived = !!t.source;

          return `
            <div style="display:flex;align-items:flex-start;gap:8px;padding:9px 10px;border-radius:8px;background:${urgency.bg};border:1px solid ${urgency.border};cursor:${isDerived ? 'pointer' : 'default'}"
              ${isDerived ? `onclick="openProject(${t.projectId})"` : ''}>
              ${!isDerived ? `
                <div onclick="event.stopPropagation();toggleTask(${t.id})" style="width:16px;height:16px;border-radius:4px;border:1.5px solid #30363D;cursor:pointer;flex-shrink:0;margin-top:1px;-webkit-tap-highlight-color:transparent"></div>
              ` : `
                <div style="width:16px;height:16px;border-radius:4px;background:${t.source === 'design' ? '#D2992222' : '#58A6FF22'};border:1.5px solid ${t.source === 'design' ? '#D29922' : '#58A6FF'};flex-shrink:0;margin-top:1px;display:flex;align-items:center;justify-content:center">
                  <svg width="8" height="8" viewBox="0 0 8 8" fill="none"><path d="M1 4h6M4 1v6" stroke="${t.source === 'design' ? '#D29922' : '#58A6FF'}" stroke-width="1.3" stroke-linecap="round"/></svg>
                </div>
              `}
              <div style="flex:1;min-width:0">
                <div style="font-size:13px;color:#C9D1D9;line-height:1.3">${esc(t.text)}</div>
                ${(proj || t.projectName) ? `<div style="font-size:11px;color:#6E7681;margin-top:2px">📁 ${esc(proj?.name || t.projectName || '')}</div>` : ''}
              </div>
              <div style="display:flex;flex-direction:column;align-items:flex-end;gap:3px;flex-shrink:0">
                ${urgency.label ? `<span style="font-size:10px;font-weight:600;color:${urgency.color};white-space:nowrap">${urgency.label}</span>` : ''}
                ${!isDerived ? `<button onclick="event.stopPropagation();deletePersonalTask(${t.id})" style="background:none;border:none;color:#6E7681;cursor:pointer;padding:0;font-size:14px;line-height:1">×</button>` : ''}
              </div>
            </div>
          `;
        }).join('')}
      </div>

      ${filter === 'week' && hiddenCount > 0 ? `
        <div onclick="switchWidgetFilter('all')" style="font-size:11px;color:#58A6FF;cursor:pointer;padding:6px 0;text-align:center;-webkit-tap-highlight-color:transparent">
          +${hiddenCount} more — view all
        </div>
      ` : ''}

      ${completedTasks.length > 0 ? `
        <details style="margin-top:10px">
          <summary style="font-size:11px;color:#6E7681;cursor:pointer;list-style:none;display:flex;align-items:center;gap:6px;-webkit-tap-highlight-color:transparent">
            <svg width="10" height="10" viewBox="0 0 10 10" fill="none"><path d="M2 4l3 3 3-3" stroke="currentColor" stroke-width="1.3" stroke-linecap="round"/></svg>
            ${completedTasks.length} completed
          </summary>
          <div style="margin-top:6px;display:flex;flex-direction:column;gap:2px">
            ${completedTasks.slice(0, 6).map(t => {
              const proj = t.projectId ? state.projects.find(p => p.id === t.projectId) : null;
              return `
                <div style="display:flex;align-items:center;gap:8px;padding:7px;border-radius:6px;opacity:0.45">
                  <div onclick="toggleTask(${t.id})" style="width:16px;height:16px;border-radius:4px;border:1.5px solid #3FB950;background:#3FB95022;cursor:pointer;flex-shrink:0;display:flex;align-items:center;justify-content:center">
                    <svg width="9" height="9" viewBox="0 0 9 9" fill="none"><path d="M1.5 4.5l2 2L7.5 2" stroke="#3FB950" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"/></svg>
                  </div>
                  <div style="flex:1;min-width:0">
                    <div style="font-size:12px;color:#6E7681;text-decoration:line-through">${esc(t.text)}</div>
                    ${proj ? `<div style="font-size:10px;color:#6E7681">${esc(proj.name)}</div>` : ''}
                  </div>
                  <button onclick="deletePersonalTask(${t.id})" style="background:none;border:none;color:#6E7681;cursor:pointer;padding:2px 4px;font-size:14px">×</button>
                </div>
              `;
            }).join('')}
          </div>
        </details>
      ` : ''}
    </div>
  `;
}

function getCloseRate() {
  const contracted = state.projects.filter(p => !p.archived && p.stage === 'contract').length;
  const lost = Object.keys(state.archived).filter(id => state.archived[id] === 'lost').length;
  const total = contracted + lost;
  return total > 0 ? Math.round((contracted / total) * 100) : null;
}

// ── Right Panel ──
function toggleRightPanel(panel) {
  state.rightPanel = state.rightPanel === panel ? null : panel;
  if (state.rightPanel !== 'messages') { state.activeConversation = null; state.composingGroup = false; }
  if (state.rightPanel === 'messages' && state.activeConversation) {
    markChannelRead(state.activeConversation);
  }
  updateRightPanel();
  if (state.rightPanel === 'messages' && state.activeConversation) {
    setTimeout(() => { const el = document.getElementById('msg-list'); if (el) el.scrollTop = el.scrollHeight; }, 50);
  }
}

function getDMChannelId(id1, id2) {
  return `dm_${Math.min(id1, id2)}_${Math.max(id1, id2)}`;
}

function getChannelMessages(channelId) {
  return state.messages.filter(m => (m.channelId || 'team') === channelId);
}

function getChannelUnread(channelId) {
  const myId = getActiveTeamMemberId();
  const lastRead = state.lastReadByChannel[channelId] || 0;
  return state.messages.filter(m =>
    (m.channelId || 'team') === channelId &&
    m.senderId !== myId &&
    m.timestamp > lastRead
  ).length;
}

function markChannelRead(channelId) {
  state.lastReadByChannel[channelId] = Date.now();
  localStorage.setItem('vi_last_read_ch', JSON.stringify(state.lastReadByChannel));
}

// A channel is "mine" if it's the shared team channel or a DM I'm part of.
function _isMyChannel(channelId, myId) {
  if (!channelId || channelId === 'team') return true;
  if (channelId.indexOf('dm_') === 0) {
    const parts = channelId.split('_');
    return parseInt(parts[1]) === myId || parseInt(parts[2]) === myId;
  }
  if (channelId.indexOf('grp_') === 0) {
    const c = getChannel(channelId);
    if (!c) return false;
    if ((c.memberIds || []).map(Number).includes(myId)) return true;
    return (c.projectIds || []).some(pid => _canViewProject(pid, myId));
  }
  return true;
}
// ── Group chats ───────────────────────────────────────────────────
function getChannel(id) { return (state.channels || []).find(c => c.id === id) || null; }
function _isGroupChannel(ch) { return typeof ch === 'string' && ch.indexOf('grp_') === 0; }
function _canViewProject(pid, myId) {
  if (currentUserHasPermission('projects.view_all')) return true;
  try { return isAssignedToProject(myId, pid); } catch (e) { return false; }
}
// Group chats the viewer can see: a member, or linked to a project they can view.
function getMyChannels(myId) {
  return (state.channels || []).filter(c =>
    (c.memberIds || []).map(Number).includes(myId) ||
    (c.projectIds || []).some(pid => _canViewProject(pid, myId))
  );
}
function openGroupComposer(prelinkPid) {
  state.composingGroup = true;
  const pid = prelinkPid ? Number(prelinkPid) : null;
  state._grpPrelink = pid;
  state._grpSelProjects = pid ? [pid] : [];
  updateRightPanel();
}
function closeGroupComposer() { state.composingGroup = false; state._grpPrelink = null; updateRightPanel(); }
function createGroupChat() {
  const name = (document.getElementById('grp-name')?.value || '').trim();
  if (!name) { alert('Give the chat a name.'); return; }
  const myId = getActiveTeamMemberId();
  const memberIds = [myId];
  document.querySelectorAll('#grp-members [data-on="1"]').forEach(el => {
    const id = parseInt(el.dataset.id); if (id && !memberIds.includes(id)) memberIds.push(id);
  });
  const projectIds = (state._grpSelProjects || []).slice();
  if (memberIds.length < 2 && projectIds.length === 0) { alert('Add at least one other person, or link a project.'); return; }
  const id = 'grp_' + Date.now() + '_' + Math.floor(Math.random() * 1000);
  if (!state.channels) state.channels = [];
  state.channels.push({ id, name, memberIds, projectIds, createdBy: myId, createdAt: Date.now() });
  save('vi_channels', state.channels);
  _syncChannelsNow();
  state.composingGroup = false;
  state._grpPrelink = null;
  openConversation(id);
}
function _grpChipStyle(on) {
  return 'display:inline-block;padding:6px 11px;border-radius:14px;border:1px solid;font-size:13px;cursor:pointer;-webkit-tap-highlight-color:transparent;user-select:none;' +
    (on ? 'background:#1565C0;border-color:#1565C0;color:#fff' : 'background:#161B22;border-color:#30363D;color:#C9D1D9');
}
function _grpToggle(el) {
  const on = el.getAttribute('data-on') === '1';
  el.setAttribute('data-on', on ? '0' : '1');
  el.style.cssText = _grpChipStyle(!on);
}
function _grpFilter(containerId, val) {
  const q = (val || '').trim().toLowerCase();
  document.querySelectorAll('#' + containerId + ' .grp-chip').forEach(el => {
    const name = el.getAttribute('data-name') || '';
    el.style.display = (!q || name.indexOf(q) !== -1) ? 'inline-block' : 'none';
  });
}
function _grpToggleProj(el) {
  const pid = parseInt(el.dataset.pid);
  state._grpSelProjects = state._grpSelProjects || [];
  const i = state._grpSelProjects.indexOf(pid);
  const on = i !== -1;
  if (on) state._grpSelProjects.splice(i, 1); else state._grpSelProjects.push(pid);
  el.setAttribute('data-on', on ? '0' : '1');
  el.style.cssText = _grpChipStyle(!on);
}
function _grpProjectList(sort, client, q) {
  q = (q || '').trim().toLowerCase();
  let list = (state.projects || []).filter(p => !(state.archived || {})[p.id]);
  if (client) list = list.filter(p => (p.client_name || '') === client);
  if (q) list = list.filter(p => ((p.name || '') + ' ' + (p.client_name || '')).toLowerCase().indexOf(q) !== -1);
  const byName = (a, b) => (a.name || '').localeCompare(b.name || '');
  if (sort === 'old') list.sort((a, b) => ((Date.parse(a.created_at) || 0) - (Date.parse(b.created_at) || 0)) || byName(a, b));
  else if (sort === 'name') list.sort(byName);
  else list.sort((a, b) => ((Date.parse(b.created_at) || 0) - (Date.parse(a.created_at) || 0)) || byName(a, b));
  return list;
}
function _grpProjectChip(p) {
  const on = (state._grpSelProjects || []).includes(p.id);
  const cn = p.client_name || '';
  return `<span class="grp-chip" data-pid="${p.id}" data-name="${esc(((p.name || '') + ' ' + cn).toLowerCase())}" data-on="${on ? '1' : '0'}" onclick="_grpToggleProj(this)" style="${_grpChipStyle(on)}">${esc(p.name || ('Project ' + p.id))}${cn ? ` <span style="opacity:0.6;font-weight:400">\u00b7 ${esc(cn)}</span>` : ''}</span>`;
}
function _grpRenderProjects() {
  const sort = (document.getElementById('grp-proj-sort') || {}).value || 'new';
  const client = (document.getElementById('grp-proj-client') || {}).value || '';
  const q = (document.getElementById('grp-proj-search') || {}).value || '';
  const list = _grpProjectList(sort, client, q);
  const box = document.getElementById('grp-projects');
  if (box) box.innerHTML = list.length ? list.map(_grpProjectChip).join('') : '<span style="font-size:12px;color:#6E7681">No matching projects</span>';
}
function _groupComposerHTML() {
  const myId = getActiveTeamMemberId();
  const me = getTeamMember(myId);
  const others = (state.team || []).filter(m => m.id !== myId)
    .slice().sort((a, b) => (a.name || '').localeCompare(b.name || ''));
  const activeProjects = (state.projects || []).filter(p => !(state.archived || {})[p.id]);
  const clients = [...new Set(activeProjects.map(p => p.client_name).filter(Boolean))].sort((a, b) => a.localeCompare(b));
  const pre = state._grpPrelink || null;
  const preName = pre ? ((state.projects.find(pp => pp.id === pre) || {}).name || '') : '';
  const srch = "width:100%;box-sizing:border-box;background:#0D1117;border:1px solid #30363D;border-radius:8px;color:#E6EDF3;font-size:16px;font-family:'DM Sans',sans-serif;padding:7px 10px;outline:none;margin-bottom:7px";
  const selStyle = "background:#0D1117;border:1px solid #30363D;border-radius:8px;color:#C9D1D9;font-size:13px;padding:7px 8px;font-family:'DM Sans',sans-serif;flex:1;min-width:0";
  const initialChips = (() => { const l = _grpProjectList('new', '', ''); return l.length ? l.map(_grpProjectChip).join('') : '<span style="font-size:12px;color:#6E7681">No active projects</span>'; })();
  return `
    <div class="rpanel-header" style="gap:8px">
      <button onclick="closeGroupComposer()" style="background:none;border:none;color:#6E7681;cursor:pointer;padding:4px;display:flex;align-items:center;-webkit-tap-highlight-color:transparent">
        <svg width="14" height="14" viewBox="0 0 14 14" fill="none"><path d="M9 2L4 7l5 5" stroke="currentColor" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"/></svg>
      </button>
      <div style="font-size:13px;font-weight:600;color:#E6EDF3">New Group Chat</div>
    </div>
    <div class="rpanel-body" style="padding:12px">
      <div class="form-group">
        <label class="form-label">Name</label>
        <input class="form-input" id="grp-name" value="${esc(preName)}" placeholder="e.g. Grace Cathedral crew" style="font-size:16px">
      </div>
      <div class="form-group">
        <label class="form-label">Members <span style="color:#6E7681;font-weight:400;text-transform:none;letter-spacing:0">(${esc((me?.name || 'you').split(' ')[0])} included \u2014 tap to add others)</span></label>
        ${others.length > 6 ? `<input id="grp-mem-search" oninput="_grpFilter('grp-members', this.value)" placeholder="Search people\u2026" style="${srch}">` : ''}
        <div id="grp-members" style="display:flex;flex-wrap:wrap;gap:6px">
          ${others.length ? others.map(m => `<span class="grp-chip" data-id="${m.id}" data-name="${esc((m.name || '').toLowerCase())}" data-on="0" onclick="_grpToggle(this)" style="${_grpChipStyle(false)}">${esc((m.name || '').split(' ')[0])}</span>`).join('') : '<span style="font-size:12px;color:#6E7681">No other team members</span>'}
        </div>
      </div>
      <div class="form-group">
        <label class="form-label">Link projects <span style="color:#6E7681;font-weight:400;text-transform:none;letter-spacing:0">(optional \u2014 anyone on a linked project can see &amp; post)</span></label>
        <div style="display:flex;gap:6px;margin-bottom:7px">
          <select id="grp-proj-sort" onchange="_grpRenderProjects()" style="${selStyle}">
            <option value="new">Newest first</option>
            <option value="old">Oldest first</option>
            <option value="name">Name A\u2013Z</option>
          </select>
          <select id="grp-proj-client" onchange="_grpRenderProjects()" style="${selStyle}">
            <option value="">All clients</option>
            ${clients.map(cn => `<option value="${esc(cn)}">${esc(cn)}</option>`).join('')}
          </select>
        </div>
        <input id="grp-proj-search" oninput="_grpRenderProjects()" placeholder="Search projects\u2026" style="${srch}">
        <div id="grp-projects" style="display:flex;flex-wrap:wrap;gap:6px;max-height:180px;overflow:auto">
          ${initialChips}
        </div>
      </div>
      <button class="btn-primary" onclick="createGroupChat()" style="width:100%;padding:10px;font-size:13px;margin-top:4px">Create chat</button>
    </div>`;
}
function getUnreadCount() {
  const myId = getActiveTeamMemberId();
  return state.messages.filter(m => {
    const ch = m.channelId || 'team';
    if (!_isMyChannel(ch, myId)) return false; // ignore DMs I'm not part of
    const lastRead = state.lastReadByChannel[ch] || 0;
    return m.senderId !== myId && m.timestamp > lastRead;
  }).length;
}

function openConversation(channelId) {
  state.activeConversation = channelId;
  state.composingGroup = false;
  state._pendingAttach = [];
  markChannelRead(channelId);
  updateRightPanel();
  setTimeout(() => {
    const el = document.getElementById('msg-list'); if (el) el.scrollTop = el.scrollHeight;
    const inp = document.getElementById('msg-input'); if (inp) inp.focus();
  }, 50);
}

function closeConversation() {
  state.activeConversation = null;
  updateRightPanel();
}

function sendMessage() {
  const input = document.getElementById('msg-input');
  const text = input?.value?.trim();
  const attachments = (state._pendingAttach || []).slice();
  if (!text && !attachments.length) return;
  const member = getTeamMember(getActiveTeamMemberId());
  if (!member) return;
  state.messages.push({
    id: Date.now() * 1000 + Math.floor(Math.random() * 1000),
    senderId: member.id,
    senderName: member.name,
    senderInitials: member.initials || getInitials(member.name),
    senderColor: DASHBOARD_ACCESS.find(d => d.key === member.primaryRole)?.color || '#6E7681',
    text: text || '',
    channelId: state.activeConversation || 'team',
    timestamp: Date.now(),
    attachments
  });
  save('vi_messages', state.messages);
  _pushNotifyMessage(member, text || ('\ud83d\udcce ' + ((attachments[0] && attachments[0].name) || 'Attachment')), state.activeConversation || 'team');
  state._pendingAttach = [];
  state._attachUploading = false;
  if (input) input.value = '';
  updateRightPanel();
  setTimeout(() => { try { _syncMessagesNow({ toastError: true }); } catch (e) {} }, 150);
  setTimeout(() => { const list = document.getElementById('msg-list'); if (list) list.scrollTop = list.scrollHeight; }, 50);
}

// ===== Web Push notifications =====
// Each device stores ITS OWN subscription under its own key (vi_push_sub_<id>), so
// one device can never clobber another's (the old single shared blob did exactly that).
function _pushSubKey(memberId) { return 'vi_push_sub_' + memberId; }
function _getMyPushSub() {
  try { const v = localStorage.getItem(_pushSubKey(getActiveTeamMemberId())); return v ? JSON.parse(v) : null; } catch (e) { return null; }
}
function _getPushSubs() {
  // Back-compat reader: gather any per-device keys present locally into one map.
  const out = {};
  try {
    for (let i = 0; i < localStorage.length; i++) {
      const k = localStorage.key(i);
      if (k && k.indexOf('vi_push_sub_') === 0) {
        try { out[k.slice('vi_push_sub_'.length)] = JSON.parse(localStorage.getItem(k)); } catch (e) {}
      }
    }
  } catch (e) {}
  return out;
}
function _savePushSub(memberId, subJSON) {
  if (memberId == null) return;
  save(_pushSubKey(memberId), subJSON); // local (and mirrored by the sync layer)
  // Belt-and-suspenders: write straight to the cloud too, since the localStorage
  // mirror can be skipped if a hydrate is in flight at save time.
  try {
    const sb = window._sb;
    if (sb) sb.from('app_data').upsert({ key: _pushSubKey(memberId), value: subJSON }, { onConflict: 'key' });
  } catch (e) {}
}
// Pull subscriptions for specific members straight from the cloud (freshest source).
async function _fetchSubsFor(ids) {
  const out = {};
  ids.forEach(id => { try { const v = localStorage.getItem(_pushSubKey(id)); if (v) out[id] = JSON.parse(v); } catch (e) {} });
  try {
    const sb = window._sb;
    if (sb && ids.length) {
      const { data } = await sb.from('app_data').select('key,value').in('key', ids.map(_pushSubKey));
      (data || []).forEach(row => {
        const idNum = parseInt(row.key.slice('vi_push_sub_'.length));
        if (row.value) out[idNum] = (typeof row.value === 'string') ? JSON.parse(row.value) : row.value;
      });
    }
  } catch (e) {}
  return out;
}
function _urlBase64ToUint8Array(base64String) {
  const padding = '='.repeat((4 - (base64String.length % 4)) % 4);
  const base64 = (base64String + padding).replace(/-/g, '+').replace(/_/g, '/');
  const raw = atob(base64);
  const arr = new Uint8Array(raw.length);
  for (let i = 0; i < raw.length; i++) arr[i] = raw.charCodeAt(i);
  return arr;
}
function _pushSupported() {
  return ('serviceWorker' in navigator) && ('PushManager' in window) && (typeof Notification !== 'undefined');
}
// Called from the More menu — asks permission and registers this device.
async function viEnablePush() {
  try {
    if (!_pushSupported()) {
      alert('This device doesn\u2019t support push notifications. On iPhone, open the app from the Home Screen icon (not Safari).');
      return;
    }
    if (!window.VI_VAPID_PUBLIC) { alert('Push isn\u2019t configured yet (the VAPID public key is missing in index.html).'); return; }
    const perm = await Notification.requestPermission();
    if (perm !== 'granted') { alert('Notifications weren\u2019t enabled. You can turn them on later in your device settings.'); return; }
    const reg = await navigator.serviceWorker.ready;
    let sub = await reg.pushManager.getSubscription();
    if (!sub) {
      sub = await reg.pushManager.subscribe({
        userVisibleOnly: true,
        applicationServerKey: _urlBase64ToUint8Array(window.VI_VAPID_PUBLIC)
      });
    }
    _savePushSub(getActiveTeamMemberId(), sub.toJSON());
    alert('Notifications enabled on this device.');
  } catch (e) {
    console.warn('enable push failed', e);
    alert('Couldn\u2019t enable notifications: ' + (e && e.message ? e.message : e));
  }
}
// On load, if permission was already granted, keep this device's subscription saved.
async function ensurePushSubscribed() {
  try {
    if (!_pushSupported() || !window.VI_VAPID_PUBLIC) return;
    if (Notification.permission !== 'granted') return;
    const reg = await navigator.serviceWorker.ready;
    let sub = await reg.pushManager.getSubscription();
    if (!sub) {
      sub = await reg.pushManager.subscribe({
        userVisibleOnly: true,
        applicationServerKey: _urlBase64ToUint8Array(window.VI_VAPID_PUBLIC)
      });
    }
    _savePushSub(getActiveTeamMemberId(), sub.toJSON());
  } catch (e) { /* silent */ }
}
// Fire a push to the recipients of a just-sent message.
async function _pushNotifyMessage(sender, text, channelId) {
  try {
    if (!sender || !window.VI_VAPID_PUBLIC) return;
    let recipientIds = [];
    if (channelId === 'team') {
      recipientIds = state.team.map(m => m.id).filter(id => id !== sender.id);
    } else if (channelId.indexOf('dm_') === 0) {
      const parts = channelId.split('_');
      const a = parseInt(parts[1]), b = parseInt(parts[2]);
      recipientIds = [a === sender.id ? b : a];
    } else if (channelId.indexOf('grp_') === 0) {
      const c = getChannel(channelId);
      if (c) recipientIds = (c.memberIds || []).map(Number).filter(id => id !== sender.id);
    }
    const subs = await _fetchSubsFor(recipientIds);
    const targets = recipientIds.map(id => subs[id]).filter(Boolean);
    if (!targets.length) return;
    const title = channelId === 'team' ? `${sender.name} \u00b7 Team`
      : (channelId.indexOf('grp_') === 0 ? `${sender.name} \u00b7 ${(getChannel(channelId) || {}).name || 'Group'}` : sender.name);
    fetch('/api/push-send', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ subscriptions: targets, title, body: text.slice(0, 140), url: '/', tag: 'msg_' + channelId })
    })
      .then(r => r.json())
      .then(res => { if (res && Array.isArray(res.expired) && res.expired.length) _pruneExpiredSubs(res.expired); })
      .catch(() => {});
  } catch (e) { /* silent */ }
}
function _pruneExpiredSubs(endpoints) {
  try {
    const keys = [];
    for (let i = 0; i < localStorage.length; i++) {
      const k = localStorage.key(i);
      if (k && k.indexOf('vi_push_sub_') === 0) keys.push(k);
    }
    keys.forEach(k => {
      try {
        const v = JSON.parse(localStorage.getItem(k));
        if (v && endpoints.indexOf(v.endpoint) !== -1) localStorage.removeItem(k); // also clears the cloud row
      } catch (e) {}
    });
  } catch (e) {}
}

// Send a push to a set of subscription targets (shared by the triggers below).
function _pushSend(targets, title, body, url, tag) {
  try {
    fetch('/api/push-send', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ subscriptions: targets, title, body: (body || '').slice(0, 140), url: url || '/', tag: tag || 'vi' })
    })
      .then(r => r.json())
      .then(res => { if (res && Array.isArray(res.expired) && res.expired.length) _pruneExpiredSubs(res.expired); })
      .catch(() => {});
  } catch (e) {}
}
function _pushMeetingWhen(m) {
  let s = '';
  try { s = fmtDate(m.date) || ''; } catch (e) {}
  const t = m.startTime || m.time || '';
  if (t) {
    let tt = t;
    try { if (m.startTime && typeof _fmt12h === 'function') tt = _fmt12h(m.startTime); } catch (e) {}
    s += (s ? ', ' : '') + tt;
  }
  return s;
}
// Trigger: a meeting was scheduled -> notify its attendees (except whoever created it).
async function _pushNotifyMeeting(meeting) {
  try {
    if (!meeting || !window.VI_VAPID_PUBLIC) return;
    const creatorId = meeting.createdBy;
    const recipientIds = [...new Set((meeting.attendees || []).map(Number))].filter(id => id && id !== creatorId);
    if (!recipientIds.length) return;
    const subs = await _fetchSubsFor(recipientIds);
    const targets = recipientIds.map(id => subs[id]).filter(Boolean);
    if (!targets.length) return;
    const creator = getTeamMember(creatorId);
    const when = _pushMeetingWhen(meeting);
    const title = 'New meeting: ' + (meeting.title || 'Meeting');
    const body = (creator ? creator.name + ' scheduled this' : 'Meeting scheduled') + (when ? ' \u2014 ' + when : '');
    _pushSend(targets, title, body, '/', 'meeting_' + meeting.id);
  } catch (e) {}
}
// Trigger: a meeting needs conflict approval -> notify the conflicted members.
async function _pushNotifyMeetingApproval(meeting, conflicts) {
  try {
    if (!meeting || !window.VI_VAPID_PUBLIC) return;
    const ids = (conflicts || []).map(c => Number(c.memberId)).filter(Boolean);
    const recipientIds = [...new Set(ids)].filter(id => id !== meeting.createdBy);
    if (!recipientIds.length) return;
    const subs = await _fetchSubsFor(recipientIds);
    const targets = recipientIds.map(id => subs[id]).filter(Boolean);
    if (!targets.length) return;
    const requester = getTeamMember(meeting.createdBy);
    const title = 'Approval needed';
    const body = (requester ? requester.name : 'Someone') + ' wants to book \u201c' + (meeting.title || 'a meeting') + '\u201d during your booked time';
    _pushSend(targets, title, body, '/', 'mtgappr_' + meeting.id);
  } catch (e) {}
}
// Who can approve a project's install date-change: PM lead (fall back to any assigned PM).
function _installApproverIds(projectId) {
  try {
    const a = getProjectAssignment(projectId);
    let ids = [];
    const lead = (a.pm || []).find(x => x.lead);
    if (lead && lead.id != null) ids.push(Number(lead.id));
    if (!ids.length) (a.pm || []).forEach(x => { if (x.id != null) ids.push(Number(x.id)); });
    return [...new Set(ids)].filter(Boolean);
  } catch (e) { return []; }
}
// Trigger: an install date-change was requested -> notify the approver(s).
async function _pushNotifyInstallApproval(projectId) {
  try {
    if (!window.VI_VAPID_PUBLIC) return;
    const req = (typeof getInstallChangeRequest === 'function') ? getInstallChangeRequest(projectId) : null;
    const requesterId = req ? Number(req.requestedBy) : null;
    const recipientIds = _installApproverIds(projectId).filter(id => id !== requesterId);
    if (!recipientIds.length) return;
    const subs = await _fetchSubsFor(recipientIds);
    const targets = recipientIds.map(id => subs[id]).filter(Boolean);
    if (!targets.length) return;
    const p = state.projects.find(x => x.id === projectId);
    const requester = getTeamMember(requesterId);
    const title = 'Approval needed';
    const body = (requester ? requester.name : 'Someone') + ' requested an install date change' + (p ? ' \u2014 ' + p.name : '');
    _pushSend(targets, title, body, '/', 'installappr_' + projectId);
  } catch (e) {}
}

// Send a test push to THIS device's own subscription (verification only).
async function viTestPush() {
  const myId = getActiveTeamMemberId();
  const mine = _getMyPushSub();
  if (!mine) { alert('Enable notifications on this device first.'); return; }
  let writeResult = 'skipped (no db)';
  try {
    const sb = window._sb;
    if (sb) {
      const { error } = await sb.from('app_data').upsert({ key: _pushSubKey(myId), value: mine }, { onConflict: 'key' });
      writeResult = error ? ('FAILED: ' + (error.message || JSON.stringify(error))) : 'ok (uploaded)';
    }
  } catch (e) { writeResult = 'threw: ' + (e && e.message ? e.message : e); }
  try {
    const r = await fetch('/api/push-send', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ subscriptions: [mine], title: 'Valiant', body: 'Test notification \u2705', url: '/', tag: 'test' })
    });
    const text = await r.text();
    if (!r.ok) { alert('Push endpoint error ' + r.status + ':\n' + text.slice(0, 300)); return; }
    let data = null; try { data = JSON.parse(text); } catch (e) {}
    const tail = (writeResult === 'ok (uploaded)') ? '' : ('\n\nNote: ' + writeResult);
    if (data && typeof data.sent === 'number') {
      if (data.sent > 0) alert('Test sent \u2014 watch for the notification.' + tail);
      else alert('Endpoint reachable but sent 0 (VAPID env vars?).' + tail);
    } else {
      alert('Unexpected response:\n' + text.slice(0, 200) + tail);
    }
  } catch (e) {
    alert('Could not reach /api/push-send (route missing or network):\n' + (e && e.message ? e.message : e));
  }
}

// One-screen notification diagnostic — shows install/permission/subscription/identity
// state so a teammate can see (and screenshot) exactly why push isn't reaching them.
async function viPushDiag() {
  const ua = navigator.userAgent || '';
  const isIOS = /iPhone|iPad|iPod/.test(ua);
  const standalone = (window.matchMedia && window.matchMedia('(display-mode: standalone)').matches) || window.navigator.standalone === true;
  const supported = _pushSupported();
  const perm = (typeof Notification !== 'undefined') ? Notification.permission : 'unavailable';
  const vapid = !!window.VI_VAPID_PUBLIC;
  const mid = getActiveTeamMemberId();
  const me = (mid != null && typeof getTeamMember === 'function') ? getTeamMember(mid) : null;
  const authMatched = (typeof getAuthMemberId === 'function') ? (getAuthMemberId() != null) : null;
  let localSub = false, cloudSub = false;
  try { localSub = !!_getMyPushSub(); } catch (e) {}
  try {
    if (window._sb && mid != null) {
      const { data } = await window._sb.from('app_data').select('key').eq('key', _pushSubKey(mid)).maybeSingle();
      cloudSub = !!data;
    }
  } catch (e) {}
  const ok = (b) => b ? '<span style="color:#3FB950">✓</span>' : '<span style="color:#F85149">✗</span>';
  const rows = [
    ['Logged in as', me ? (esc(me.name) + ' (#' + mid + ')') : '<span style="color:#F85149">none</span>'],
    ['Identity linked by email', authMatched == null ? '?' : (ok(authMatched) + (authMatched ? '' : ' <span style="color:#F85149">— push saves under wrong person</span>'))],
    ['Installed to Home Screen', ok(standalone) + ((!standalone && isIOS) ? ' <span style="color:#D29922">— required on iPhone</span>' : '')],
    ['Push supported here', ok(supported)],
    ['Notification permission', perm === 'granted' ? (ok(true) + ' granted') : ('<span style="color:#F85149">' + esc(perm) + '</span>')],
    ['Subscribed on this device', ok(localSub)],
    ['Subscription saved in cloud', ok(cloudSub)],
    ['Push configured (VAPID)', ok(vapid)]
  ];
  let advice;
  if (isIOS && !standalone) advice = 'On iPhone, push only works when the app is installed. In Safari tap the Share button → “Add to Home Screen,” then open the app from that icon and tap “Enable” below.';
  else if (perm !== 'granted') advice = 'Notifications aren’t granted on this device. Tap “Enable” below; if it’s blocked, check your phone’s Settings → Notifications for this app.';
  else if (!localSub || !cloudSub) advice = 'Permission is on but this device isn’t fully subscribed/synced. Tap “Enable” to (re)register, then “Send test.”';
  else if (authMatched === false) advice = 'Your subscription may be saved under the wrong identity. Make sure your team record has your login email, then tap “Enable” again.';
  else advice = 'Everything looks set on this device. Tap “Send test” to confirm a banner appears.';
  let modal = document.getElementById('push-diag');
  if (modal) modal.remove();
  modal = document.createElement('div');
  modal.id = 'push-diag';
  modal.className = 'modal-overlay';
  modal.style.display = 'flex';
  modal.innerHTML = `
    <div class="modal-container" style="max-width:440px">
      <div class="modal-header">
        <div class="modal-title">Notification Diagnostics</div>
        <button class="modal-close" onclick="document.getElementById('push-diag')?.remove()">
          <svg width="18" height="18" viewBox="0 0 18 18" fill="none"><path d="M4 4l10 10M14 4L4 14" stroke="currentColor" stroke-width="1.5" stroke-linecap="round"/></svg>
        </button>
      </div>
      <div class="modal-body">
        <div style="font-size:13px">
          ${rows.map(r => `<div style="display:flex;justify-content:space-between;gap:12px;border-bottom:1px solid #1C2333;padding:6px 0"><span style="color:#8B949E">${r[0]}</span><span style="color:#C9D1D9;text-align:right">${r[1]}</span></div>`).join('')}
        </div>
        <div style="margin-top:14px;font-size:13px;color:#C9D1D9;background:#161B22;border:1px solid #30363D;border-radius:8px;padding:12px;line-height:1.5">${advice}</div>
        <div style="display:flex;gap:8px;margin-top:14px">
          <button class="btn-primary" onclick="document.getElementById('push-diag')?.remove();viEnablePush()" style="flex:1;padding:11px">Enable</button>
          <button class="btn" onclick="viTestPush()" style="flex:1;padding:11px">Send test</button>
        </div>
      </div>
    </div>`;
  document.body.appendChild(modal);
  modal.addEventListener('click', e => { if (e.target === modal) modal.remove(); });
}
window.viPushDiag = viPushDiag;

// Apply an incoming message change pushed live by the realtime layer (no reload).
function applyLiveMessages() {
  let incoming;
  try { incoming = JSON.parse(localStorage.getItem('vi_messages') || '[]'); } catch (e) { return; }
  // Union with what we already hold so a clobbered cloud copy can't drop our own
  // not-yet-uploaded messages (the next poll re-pushes anything the cloud lacks).
  const _byId = new Map();
  (Array.isArray(incoming) ? incoming : []).forEach(m => { if (m && m.id != null) _byId.set(m.id, m); });
  (Array.isArray(state.messages) ? state.messages : []).forEach(m => { if (m && m.id != null && !_byId.has(m.id)) _byId.set(m.id, m); });
  state.messages = Array.from(_byId.values());
  const list = document.getElementById('msg-list');
  if (list) {
    // Messages panel is open — refresh just the list, keeping scroll position.
    const channelId = state.activeConversation || 'team';
    const atBottom = (list.scrollHeight - list.scrollTop - list.clientHeight) < 80;
    list.innerHTML = renderMessagesList(channelId);
    if (atBottom) list.scrollTop = list.scrollHeight;
    updateBottomNavMsgBadge();
    return;
  }
  // Not viewing messages — refresh the unread badge, unless the user is typing in the panel.
  const ae = document.activeElement;
  const typingInPanel = ae && (ae.tagName === 'TEXTAREA' || ae.tagName === 'INPUT') &&
    typeof ae.closest === 'function' && ae.closest('#right-panel');
  if (!typingInPanel) updateRightPanel();
}

// Called by the realtime bootstrap when a live key (chat) changes in the cloud.
window.viOnLiveKey = function (key) {
  if (key === 'vi_messages') applyLiveMessages();
  if (key === 'vi_channels') { try { _pollChannels(); } catch (e) {} }
};

// ── Message polling (realtime-independent delivery) ──────────────────────────
// Realtime can be disabled or flaky, so we also poll the shared message log on a
// timer: read the cloud copy, union it with what we have (messages are add-only),
// and push back anything the cloud is missing. Two people can converse even if
// realtime never fires. _lastCloudMsgCount surfaces in the debug line.
let _lastCloudMsgCount = -1;
async function _pollMessages() {
  const sb = window._sb;
  if (!sb || !state.team || !state.team.length) return;
  let cloud;
  try {
    const { data } = await sb.from('app_data').select('value').eq('key', 'vi_messages').maybeSingle();
    cloud = (data && Array.isArray(data.value)) ? data.value : [];
  } catch (e) { return; }            // row not created yet, or a transient error
  _lastCloudMsgCount = cloud.length;
  const local = Array.isArray(state.messages) ? state.messages : [];
  const localIds = new Set(local.map(m => m && m.id).filter(v => v != null));
  const cloudIds = new Set(cloud.map(m => m && m.id).filter(v => v != null));
  const byId = new Map();
  cloud.forEach(m => { if (m && m.id != null) byId.set(m.id, m); });
  local.forEach(m => { if (m && m.id != null) byId.set(m.id, m); });
  const union = Array.from(byId.values());
  // Membership diff — length comparison missed simultaneous cross-adds and clobbers.
  let gotNew = false;       cloudIds.forEach(id => { if (!localIds.has(id)) gotNew = true; });
  let cloudMissing = false; localIds.forEach(id => { if (!cloudIds.has(id)) cloudMissing = true; });
  // Track which ids the cloud has confirmed (drives the per-message sent indicator),
  // and refresh the open thread when that set changes so 'sending' flips to 'sent'.
  state._cloudMsgIds = cloudIds;
  if (document.getElementById('msg-list') && cloud.length !== state._prevCloudCount) {
    state._prevCloudCount = cloud.length;
    try { const _l = document.getElementById('msg-list'); if (_l) _l.innerHTML = renderMessagesList(state.activeConversation || 'team'); } catch (e) {}
  }
  if (!gotNew && !cloudMissing) return;
  state.messages = union;
  try { localStorage.setItem('vi_messages', JSON.stringify(union)); } catch (e) {}  // mirrors up
  if (gotNew) {
    if (document.getElementById('msg-list')) { try { applyLiveMessages(); } catch (e) {} }
    else { try { updateBottomNavMsgBadge(); } catch (e) {} }
  }
}
setInterval(_pollMessages, 2000);

// ── Channel (group-chat) sync ────────────────────────────────────────────────
// vi_channels used to be written as one blob, so a stale write from any device
// could clobber the whole list and a freshly-created group chat would vanish even
// though its messages survived (messages union-merge). Channels now get the same
// add-only union-merge + a self-healing poll: any device that still has a channel
// re-publishes it on its next tick, so a clobber can't make it disappear.
async function _syncChannelsNow() {
  const sb = window._sb;
  if (!sb) return false;
  try {
    let cloud = [];
    try {
      const { data } = await sb.from('app_data').select('value').eq('key', 'vi_channels').maybeSingle();
      cloud = (data && Array.isArray(data.value)) ? data.value : [];
    } catch (e) {}
    const byId = new Map();
    cloud.forEach(c => { if (c && c.id != null) byId.set(c.id, c); });
    (Array.isArray(state.channels) ? state.channels : []).forEach(c => { if (c && c.id != null) byId.set(c.id, c); }); // local wins, keeps cloud-only
    const union = Array.from(byId.values());
    const { error } = await sb.from('app_data').upsert({ key: 'vi_channels', value: union }, { onConflict: 'key' });
    if (error) { console.warn('channel sync write FAILED', error); return false; }
    state.channels = union;
    try { localStorage.setItem('vi_channels', JSON.stringify(union)); } catch (e) {}
    return true;
  } catch (e) { console.warn('channel sync error', e); return false; }
}

async function _pollChannels() {
  const sb = window._sb;
  if (!sb || !state.team || !state.team.length) return;
  let cloud;
  try {
    const { data } = await sb.from('app_data').select('value').eq('key', 'vi_channels').maybeSingle();
    cloud = (data && Array.isArray(data.value)) ? data.value : [];
  } catch (e) { return; }
  const local = Array.isArray(state.channels) ? state.channels : [];
  const byId = new Map();
  cloud.forEach(c => { if (c && c.id != null) byId.set(c.id, c); });
  local.forEach(c => { if (c && c.id != null) byId.set(c.id, c); });
  const union = Array.from(byId.values());
  const localIds = new Set(local.map(c => c && c.id).filter(v => v != null));
  const cloudIds = new Set(cloud.map(c => c && c.id).filter(v => v != null));
  let gotNew = false; cloudIds.forEach(id => { if (!localIds.has(id)) gotNew = true; });
  let cloudMissing = false; localIds.forEach(id => { if (!cloudIds.has(id)) cloudMissing = true; });
  if (!gotNew && !cloudMissing) return;
  state.channels = union;
  try { localStorage.setItem('vi_channels', JSON.stringify(union)); } catch (e) {}
  // Heal: if the cloud was missing channels we hold, republish the union.
  if (cloudMissing) { try { await sb.from('app_data').upsert({ key: 'vi_channels', value: union }, { onConflict: 'key' }); } catch (e) {} }
  // Refresh the conversation list if the messages panel is open and the user isn't typing.
  if (gotNew) {
    const ae = document.activeElement;
    const typingInPanel = ae && (ae.tagName === 'TEXTAREA' || ae.tagName === 'INPUT') && typeof ae.closest === 'function' && ae.closest('#right-panel');
    if (!typingInPanel) { try { if (!document.getElementById('msg-list')) updateRightPanel(); } catch (e) {} }
    try { updateBottomNavMsgBadge(); } catch (e) {}
  }
}
setInterval(_pollChannels, 2000);

// Direct, awaited push of the message log to the cloud that SURFACES write errors
// (the localStorage mirror swallows them, which is why a failed upload just sits on
// the 'sending' indicator forever). Merges with the cloud copy first so we never
// clobber messages other people sent.
async function _syncMessagesNow(opts) {
  opts = opts || {};
  const sb = window._sb;
  if (!sb) { if (opts.toastError) showToast('Not connected to the cloud', 'error'); return false; }
  try {
    let cloud = [];
    try {
      const { data } = await sb.from('app_data').select('value').eq('key', 'vi_messages').maybeSingle();
      cloud = (data && Array.isArray(data.value)) ? data.value : [];
    } catch (e) {}
    const byId = new Map();
    cloud.forEach(m => { if (m && m.id != null) byId.set(m.id, m); });
    (Array.isArray(state.messages) ? state.messages : []).forEach(m => { if (m && m.id != null) byId.set(m.id, m); }); // local wins
    const union = Array.from(byId.values());
    const { error } = await sb.from('app_data').upsert({ key: 'vi_messages', value: union }, { onConflict: 'key' });
    if (error) {
      console.warn('message sync write FAILED', error);
      if (opts.toastError) showToast('Send failed: ' + (error.message || error.code || 'cloud write rejected'), 'error');
      return false;
    }
    state.messages = union;
    state._cloudMsgIds = new Set(union.map(m => m && m.id).filter(v => v != null));
    const _l = document.getElementById('msg-list');
    if (_l) _l.innerHTML = renderMessagesList(state.activeConversation || 'team');
    if (opts.toastOk) showToast('Synced', 'success');
    return true;
  } catch (e) {
    console.warn('message sync error', e);
    if (opts.toastError) showToast('Send error: ' + (e && e.message ? e.message : e), 'error');
    return false;
  }
}
// Manual trigger for debugging from anywhere: viSyncNow()
window.viSyncNow = function () { return _syncMessagesNow({ toastError: true, toastOk: true }); };

// Team is a single-blob, low-frequency, high-importance write. The background
// mirror can silently fail on a backgrounding mobile PWA, so on every team change
// we push directly and AWAIT it, surfacing any error instead of losing the change.
async function _syncTeamNow(opts) {
  opts = opts || {};
  const sb = window._sb;
  if (!sb) { if (opts.toast) showToast('Not connected to the cloud \u2014 change not saved', 'error'); return false; }
  try {
    const { error } = await sb.from('app_data').upsert({ key: 'vi_team', value: state.team }, { onConflict: 'key' });
    if (error) {
      console.warn('team cloud save FAILED', error);
      if (opts.toast) showToast('Cloud save failed: ' + (error.message || error.code || 'write rejected'), 'error');
      return false;
    }
    if (opts.toast) showToast('Saved', 'success');
    return true;
  } catch (e) {
    console.warn('team cloud save error', e);
    if (opts.toast) showToast('Save error: ' + (e && e.message ? e.message : e), 'error');
    return false;
  }
}
// When the app returns to the foreground (iOS suspends PWAs), re-push anything stuck and pull anything new.
document.addEventListener('visibilitychange', () => {
  if (document.visibilityState === 'visible') {
    try { _syncMessagesNow({}); } catch (e) {}
    try { _pollMessages(); } catch (e) {}
  }
});

function getNoteSections(role) {
  return state.noteSections[role] || [];
}

function addNoteSection(role, title, type) {
  if (!state.noteSections[role]) state.noteSections[role] = [];
  state.noteSections[role].push({
    id: Date.now(), title: title || 'Untitled',
    type: type || 'text', content: '', items: [], collapsed: false
  });
  save('vi_note_sections', state.noteSections);
  renderCurrentPage();
}

function deleteNoteSection(role, id) {
  state.noteSections[role] = (state.noteSections[role] || []).filter(s => s.id !== id);
  save('vi_note_sections', state.noteSections);
  renderCurrentPage();
}

function toggleNoteSectionCollapsed(role, id) {
  const s = (state.noteSections[role] || []).find(x => x.id === id);
  if (s) { s.collapsed = !s.collapsed; save('vi_note_sections', state.noteSections); renderCurrentPage(); }
}

function updateNoteSectionText(role, id, content) {
  const s = (state.noteSections[role] || []).find(x => x.id === id);
  if (s) { s.content = content; save('vi_note_sections', state.noteSections); }
}

function addNoteChecklistItem(role, sectionId, text) {
  const s = (state.noteSections[role] || []).find(x => x.id === sectionId);
  if (!s || !text.trim()) return;
  if (!s.items) s.items = [];
  s.items.push({ id: Date.now(), text: text.trim(), done: false });
  save('vi_note_sections', state.noteSections);
  renderCurrentPage();
}

function toggleNoteChecklistItem(role, sectionId, itemId) {
  const s = (state.noteSections[role] || []).find(x => x.id === sectionId);
  if (!s) return;
  const item = (s.items || []).find(i => i.id === itemId);
  if (item) { item.done = !item.done; save('vi_note_sections', state.noteSections); renderCurrentPage(); }
}

function deleteNoteChecklistItem(role, sectionId, itemId) {
  const s = (state.noteSections[role] || []).find(x => x.id === sectionId);
  if (!s) return;
  s.items = (s.items || []).filter(i => i.id !== itemId);
  save('vi_note_sections', state.noteSections);
  renderCurrentPage();
}

function showAddSectionDialog(role) {
  let d = document.getElementById('add-section-dialog');
  if (d) { d.remove(); return; }
  d = document.createElement('div');
  d.id = 'add-section-dialog';
  d.style.cssText = 'position:fixed;inset:0;background:rgba(0,0,0,0.7);z-index:120;display:flex;align-items:center;justify-content:center;padding:20px';
  d.innerHTML = `
    <div style="background:#161B22;border:1px solid #30363D;border-radius:12px;padding:20px;max-width:340px;width:100%">
      <div style="font-size:15px;font-weight:600;color:#E6EDF3;margin-bottom:16px">Add Section</div>
      <div class="form-group">
        <label class="form-label">Heading</label>
        <input class="form-input" id="ns-title" placeholder="e.g. Follow-ups, Weekly Goals…" autofocus>
      </div>
      <div class="form-group">
        <label class="form-label">Type</label>
        <div style="display:grid;grid-template-columns:1fr 1fr;gap:8px">
          <div id="ns-type-text" onclick="document.getElementById('ns-type-text').style.borderColor='#58A6FF';document.getElementById('ns-type-checklist').style.borderColor='#1C2333';window._nsType='text'"
            style="padding:10px;border-radius:8px;border:1px solid #58A6FF;background:#0D1626;cursor:pointer;text-align:center">
            <div style="font-size:13px;font-weight:500;color:#58A6FF">📝 Text</div>
            <div style="font-size:10px;color:#6E7681;margin-top:2px">Free-form notes</div>
          </div>
          <div id="ns-type-checklist" onclick="document.getElementById('ns-type-checklist').style.borderColor='#58A6FF';document.getElementById('ns-type-text').style.borderColor='#1C2333';window._nsType='checklist'"
            style="padding:10px;border-radius:8px;border:1px solid #1C2333;background:#0D1117;cursor:pointer;text-align:center">
            <div style="font-size:13px;font-weight:500;color:#C9D1D9">☑ Checklist</div>
            <div style="font-size:10px;color:#6E7681;margin-top:2px">Check-off items</div>
          </div>
        </div>
      </div>
      <div style="display:flex;gap:8px;margin-top:4px">
        <button class="btn-primary" onclick="submitAddSection('${role}')" style="flex:1;padding:11px">Add</button>
        <button class="btn" onclick="document.getElementById('add-section-dialog')?.remove()">Cancel</button>
      </div>
    </div>
  `;
  window._nsType = 'text';
  document.body.appendChild(d);
  d.addEventListener('click', e => { if (e.target === d) d.remove(); });
  document.getElementById('ns-title')?.focus();
  document.getElementById('ns-title')?.addEventListener('keydown', e => { if (e.key === 'Enter') submitAddSection(role); });
}

function submitAddSection(role) {
  const title = document.getElementById('ns-title')?.value?.trim();
  if (!title) { document.getElementById('ns-title')?.focus(); return; }
  addNoteSection(role, title, window._nsType || 'text');
  document.getElementById('add-section-dialog')?.remove();
}

function renderNotesSection(role, s) {
  const doneCount = s.type === 'checklist' ? (s.items || []).filter(i => i.done).length : 0;
  const totalCount = s.type === 'checklist' ? (s.items || []).length : 0;
  return `
    <div style="border:1px solid #1C2333;border-radius:8px;margin-bottom:8px;overflow:hidden">
      <div style="display:flex;align-items:center;justify-content:space-between;padding:9px 12px;background:#161B22;cursor:pointer;-webkit-tap-highlight-color:transparent"
        onclick="toggleNoteSectionCollapsed('${role}', ${s.id})">
        <div style="display:flex;align-items:center;gap:8px;min-width:0">
          <span style="font-size:11px;color:#6E7681">${s.type === 'checklist' ? '☑' : '📝'}</span>
          <span style="font-size:13px;font-weight:500;color:#E6EDF3;white-space:nowrap;overflow:hidden;text-overflow:ellipsis">${esc(s.title)}</span>
          ${s.type === 'checklist' && totalCount > 0 ? `<span style="font-size:10px;color:${doneCount === totalCount ? '#3FB950' : '#6E7681'}">${doneCount}/${totalCount}</span>` : ''}
        </div>
        <div style="display:flex;align-items:center;gap:6px;flex-shrink:0">
          <svg width="12" height="12" viewBox="0 0 12 12" fill="none" style="color:#6E7681;transform:${s.collapsed ? 'rotate(-90deg)' : 'rotate(0)'};transition:transform 0.15s"><path d="M2 4l4 4 4-4" stroke="currentColor" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"/></svg>
          <button onclick="event.stopPropagation();deleteNoteSection('${role}',${s.id})" style="background:none;border:none;color:#6E7681;cursor:pointer;font-size:14px;padding:0;line-height:1">×</button>
        </div>
      </div>
      ${!s.collapsed ? `
        <div style="padding:10px 12px;background:#0D1117">
          ${s.type === 'text' ? `
            <textarea
              style="width:100%;background:transparent;border:none;color:#C9D1D9;font-size:12px;line-height:1.6;resize:none;outline:none;font-family:'DM Sans',sans-serif;min-height:60px"
              placeholder="Start typing…"
              oninput="updateNoteSectionText('${role}',${s.id},this.value)"
            >${esc(s.content || '')}</textarea>
          ` : `
            <div style="display:flex;flex-direction:column;gap:4px;margin-bottom:8px">
              ${(s.items || []).map(item => `
                <div style="display:flex;align-items:center;gap:8px">
                  <div onclick="toggleNoteChecklistItem('${role}',${s.id},${item.id})"
                    style="width:15px;height:15px;border-radius:3px;border:1.5px solid ${item.done ? '#3FB950' : '#30363D'};background:${item.done ? '#3FB95022' : 'transparent'};cursor:pointer;flex-shrink:0;display:flex;align-items:center;justify-content:center">
                    ${item.done ? `<svg width="9" height="9" viewBox="0 0 9 9" fill="none"><path d="M1.5 4.5l2 2L7.5 2" stroke="#3FB950" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"/></svg>` : ''}
                  </div>
                  <span style="flex:1;font-size:12px;color:${item.done ? '#6E7681' : '#C9D1D9'};text-decoration:${item.done ? 'line-through' : 'none'}">${esc(item.text)}</span>
                  <button onclick="deleteNoteChecklistItem('${role}',${s.id},${item.id})" style="background:none;border:none;color:#6E7681;cursor:pointer;font-size:13px;padding:0">×</button>
                </div>
              `).join('')}
            </div>
            <div style="display:flex;gap:6px">
              <input class="form-input" id="cl-input-${s.id}" placeholder="Add item…"
                style="flex:1;padding:6px 8px;font-size:12px"
                onkeydown="if(event.key==='Enter'){const v=this.value.trim();if(v){addNoteChecklistItem('${role}',${s.id},v);}}">
              <button class="btn btn-sm" onclick="const v=document.getElementById('cl-input-${s.id}')?.value?.trim();if(v)addNoteChecklistItem('${role}',${s.id},v)"
                style="padding:5px 10px;font-size:12px">+</button>
            </div>
          `}
        </div>
      ` : ''}
    </div>
  `;
}

function renderMessagesList(channelId) {
  channelId = channelId || state.activeConversation || 'team';
  const myId = getActiveTeamMemberId();
  const messages = getChannelMessages(channelId);
  if (messages.length === 0) {
    return '<div style="text-align:center;padding:32px 12px;color:#6E7681;font-size:12px">No messages yet.<br>Say something 👋</div>';
  }
  let lastDate = '';
  return messages.map(m => {
    const isMe = m.senderId === myId;
    const dt = new Date(m.timestamp);
    const dateStr = dt.toLocaleDateString('en-US', { month: 'short', day: 'numeric' });
    const timeStr = dt.toLocaleTimeString('en-US', { hour: 'numeric', minute: '2-digit' });
    const dateDivider = dateStr !== lastDate
      ? `<div style="text-align:center;font-size:10px;color:#6E7681;padding:8px 0;margin:4px 0">${dateStr}</div>`
      : '';
    lastDate = dateStr;
    return `${dateDivider}
      <div id="msg-${m.id}" style="display:flex;flex-direction:${isMe ? 'row-reverse' : 'row'};align-items:flex-end;gap:6px;margin-bottom:8px;border-radius:8px">
        ${!isMe ? `<div style="width:26px;height:26px;border-radius:50%;background:${m.senderColor}22;border:1px solid ${m.senderColor}66;display:flex;align-items:center;justify-content:center;font-size:9px;font-weight:600;color:${m.senderColor};flex-shrink:0">${esc(m.senderInitials)}</div>` : ''}
        <div style="max-width:80%">
          ${!isMe ? `<div style="font-size:10px;color:#6E7681;margin-bottom:2px;padding-left:2px">${esc(m.senderName)}</div>` : ''}
          ${m.text ? `<div style="background:${isMe ? '#1565C0' : '#161B22'};border:1px solid ${isMe ? '#1565C066' : '#30363D'};border-radius:${isMe ? '10px 10px 2px 10px' : '10px 10px 10px 2px'};padding:7px 10px;font-size:12px;color:#E6EDF3;line-height:1.4;word-break:break-word">${esc(m.text)}</div>` : ''}${_attachmentsHTML(m, isMe)}
          <div style="font-size:9px;color:#6E7681;margin-top:2px;text-align:${isMe ? 'right' : 'left'};padding:0 2px">${timeStr}${isMe ? ((state._cloudMsgIds && state._cloudMsgIds.has(m.id)) ? ' <span style="color:#3FB950">· ✓ sent</span>' : ' <span style="color:#D29922">· ↑ sending</span>') : ''}</div>
        </div>
      </div>`;
  }).join('');
}

// ── Messages: conversation list + search ──────────────────────────
