// ── Settings page ──
// Applies a UI text-size preference as a root class. 'large' bumps a root
// font-size variable that the stylesheet's rem-based and em-based sizes follow,
// plus a scale on key fixed-px areas via the .text-large class.
function applyTextSize(size) {
  const root = document.documentElement;
  root.classList.remove('text-normal', 'text-large');
  root.classList.add(size === 'large' ? 'text-large' : 'text-normal');
}

function setTextSize(size) {
  state.textSize = size;
  localStorage.setItem('vi_text_size', size);
  applyTextSize(size);
  renderCurrentPage();
}

// ── ONE-TIME CLEANUP (run once from the console: viRunCleanup()) ──────────
// Backs up all vi_* data to a JSON download, then: sets the 20 active jobs to
// Contract/Install, moves every other non-archived project to Proposal, makes
// Jacob the PM/coordinator on the 20, and wipes ALL calendar data. Destructive
// + syncs to every device; the JSON backup is the only undo.
function viRunCleanup() {
  if (typeof currentUserHasPermission === 'function' && !currentUserHasPermission('admin.system')) {
    alert('Master Admin only — log in as yourself (Jacob) and try again.');
    return;
  }
  const CONTRACT_IDS = [612,605,599,594,593,589,588,573,572,560,554,542,541,508,505,272];
  const INSTALL_IDS  = [585,333,302,252];
  const contractSet = new Set(CONTRACT_IDS);
  const installSet  = new Set(INSTALL_IDS);

  // 1) Backup every vi_* key to a JSON download
  try {
    const backup = {};
    for (let i = 0; i < localStorage.length; i++) {
      const k = localStorage.key(i);
      if (k && k.indexOf('vi_') === 0) backup[k] = localStorage.getItem(k);
    }
    const blob = new Blob([JSON.stringify(backup, null, 2)], { type: 'application/json' });
    const a = document.createElement('a');
    const d = new Date();
    const p2 = n => String(n).padStart(2, '0');
    a.href = URL.createObjectURL(blob);
    a.download = `valiant-backup-${d.getFullYear()}${p2(d.getMonth()+1)}${p2(d.getDate())}-${p2(d.getHours())}${p2(d.getMinutes())}.json`;
    document.body.appendChild(a); a.click(); a.remove();
  } catch (e) { alert('Backup failed — aborting (no changes made).\n' + e); return; }

  // 2) Resolve targets + Jacob
  const byId = id => state.projects.find(p => Number(p.id) === Number(id));
  const matchedC = CONTRACT_IDS.map(byId).filter(Boolean);
  const matchedI = INSTALL_IDS.map(byId).filter(Boolean);
  const missing  = [...CONTRACT_IDS, ...INSTALL_IDS].filter(id => !byId(id));
  const jacob = (state.team || []).find(m => /jacob/i.test(m.name || ''));
  const others = (state.projects || []).filter(p => {
    const n = Number(p.id);
    if (contractSet.has(n) || installSet.has(n)) return false;
    if (state.archived && state.archived[p.id]) return false; // leave icebox/trash/lost
    return true;
  });

  console.log('--- Cleanup plan ---');
  console.log('Contract ' + matchedC.length + '/' + CONTRACT_IDS.length + ':', matchedC.map(p => p.id + ' ' + p.name));
  console.log('Install ' + matchedI.length + '/' + INSTALL_IDS.length + ':', matchedI.map(p => p.id + ' ' + p.name));
  console.log('-> Proposal:', others.length, 'projects');
  console.log('Coordinator (PM lead):', jacob ? jacob.name : 'NOT FOUND');
  if (missing.length) console.warn('NOT FOUND by id:', missing);

  if (!jacob) { alert('Could not find your team member named "Jacob" — aborting (backup saved).'); return; }
  if (missing.length && !confirm(missing.length + ' of the 20 target jobs were NOT found by id (see console: ' + missing.join(', ') + ').\n\nContinue anyway? Missing ones get treated as "other" -> Proposal.')) return;

  if (!confirm(
    'Backup downloaded. Apply now?\n\n' +
    '\u2022 ' + matchedC.length + ' \u2192 Contract\n' +
    '\u2022 ' + matchedI.length + ' \u2192 Install\n' +
    '\u2022 ' + others.length + ' \u2192 Proposal\n' +
    '\u2022 You (' + jacob.name + ') = PM/coordinator on ' + (matchedC.length + matchedI.length) + ' jobs\n' +
    '\u2022 ALL calendar data wiped\n\n' +
    'Syncs to every device. Only the backup can undo this.'
  )) { console.log('Cancelled (backup already downloaded).'); return; }

  // 3) Stages
  const unarchive = p => { if (state.archived && state.archived[p.id]) delete state.archived[p.id]; p.archived = null; };
  matchedC.forEach(p => { p.stage = 'contract'; unarchive(p); });
  matchedI.forEach(p => { p.stage = 'install'; unarchive(p); });
  others.forEach(p => { p.stage = 'proposal'; });
  save('vi_projects', state.projects);
  // The app boots its project list from vi_projects_cache — must write THAT key
  // (not just vi_projects) or the reload reads the stale cache and reverts.
  try { localStorage.setItem('vi_projects_cache', JSON.stringify(state.projects)); } catch (e) {}
  save('vi_archived', state.archived || {});

  // 4) Jacob as PM lead on the 20
  [...matchedC, ...matchedI].forEach(p => setProjectAssignment(p.id, 'pm', [{ id: jacob.id, lead: true }]));

  // 5) Wipe ALL calendar data
  state.bookedDates = {}; save('vi_booked_dates', state.bookedDates);
  state.estimatedInstallOverride = {}; save('vi_estimated_install', state.estimatedInstallOverride);
  state.meetings = []; _syncMeetingsNow();
  state.personalEvents = []; save('vi_personal_events', state.personalEvents);
  ['vi_meeting_logs', 'vi_meeting_approvals', 'vi_install_change_requests'].forEach(k => { try { localStorage.setItem(k, '[]'); } catch (e) {} });
  const clearDates = tasks => (tasks || []).forEach(t => {
    t.schedStart = null; t.schedEnd = null;
    (t.subtasks || []).forEach(sub => { sub.date = ''; });
  });
  clearDates(state.installTasks); save('vi_install_tasks', state.installTasks || []);
  clearDates(state.designTasks); save('vi_design_tasks', state.designTasks || []);

  alert('Cleanup complete \u2014 reloading.');
  location.reload();
}
if (typeof window !== 'undefined') window.viRunCleanup = viRunCleanup;

// ── Calendar subscribe (per-user ICS feed) ──────────────────────────────
function getOrCreateCalToken(memberId) {
  const m = (state.team || []).find(t => t.id === memberId);
  if (!m) return null;
  if (!m.calToken) {
    const rnd = (typeof crypto !== 'undefined' && crypto.randomUUID)
      ? crypto.randomUUID().replace(/-/g, '')
      : (Math.random().toString(36).slice(2) + Date.now().toString(36));
    m.calToken = 'vc_' + rnd;
    save('vi_team', state.team);
  }
  return m.calToken;
}

function copyCalUrl() {
  const el = document.getElementById('cal-url');
  if (!el) return;
  const done = () => { if (typeof showToast === 'function') showToast('Link copied', 'success'); };
  if (navigator.clipboard && navigator.clipboard.writeText) {
    navigator.clipboard.writeText(el.value).then(done).catch(() => { el.select(); document.execCommand('copy'); done(); });
  } else { el.select(); document.execCommand('copy'); done(); }
}

function regenerateCalToken() {
  const mid = getActiveTeamMemberId();
  const m = (state.team || []).find(t => t.id === mid);
  if (!m) return;
  const rnd = (typeof crypto !== 'undefined' && crypto.randomUUID)
    ? crypto.randomUUID().replace(/-/g, '')
    : (Math.random().toString(36).slice(2) + Date.now().toString(36));
  m.calToken = 'vc_' + rnd;
  save('vi_team', state.team);
  if (typeof showToast === 'function') showToast('Link reset \u2014 re-subscribe with the new URL', 'success');
  renderCurrentPage();
}

function renderCalendarSubscribeCard() {
  const mid = getActiveTeamMemberId();
  if (mid == null) return '';
  const token = getOrCreateCalToken(mid);
  if (!token) return '';
  const url = location.origin + '/api/cal?t=' + token;
  return `
      <div class="dashboard-card" style="margin-top:14px">
        <div style="font-size:11px;font-weight:600;color:#6E7681;text-transform:uppercase;letter-spacing:0.08em;margin-bottom:4px">Calendar</div>
        <div style="font-size:14px;font-weight:600;color:#E6EDF3;margin-bottom:2px">Subscribe to your calendar</div>
        <div style="font-size:12px;color:#8B949E;margin-bottom:12px">Add your Valiant schedule \u2014 install windows, meetings, your assigned tasks, and personal time \u2014 to Google or Apple Calendar. It's read-only and refreshes on its own.</div>
        <div style="display:flex;gap:8px;align-items:center;margin-bottom:12px">
          <input id="cal-url" readonly value="${esc(url)}" onclick="this.select()" class="form-input" style="font-size:12px;flex:1;min-width:0">
          <button type="button" class="btn btn-sm" onclick="copyCalUrl()">Copy</button>
        </div>
        <div style="font-size:12px;color:#8B949E;line-height:1.7">
          <b style="color:#C9D1D9">Google:</b> Calendar \u2192 Other calendars \u2192 + \u2192 From URL \u2192 paste \u2192 Add.<br>
          <b style="color:#C9D1D9">iPhone:</b> Settings \u2192 Calendar \u2192 Accounts \u2192 Add Account \u2192 Other \u2192 Add Subscribed Calendar \u2192 paste.<br>
          <b style="color:#C9D1D9">Mac:</b> Calendar \u2192 File \u2192 New Calendar Subscription \u2192 paste.
        </div>
        <div style="margin-top:12px">
          <button type="button" class="btn btn-sm" onclick="regenerateCalToken()">Reset link</button>
          <span style="font-size:11px;color:#6E7681;margin-left:8px">Resetting makes the old link stop working.</span>
        </div>
      </div>`;
}

// ── Assets (vehicles / trailers / lifts / cases / kits) — Drop 1: inventory ──
const ASSET_TYPES = [
  { key: 'vehicle', label: 'Vehicles' },
  { key: 'trailer', label: 'Trailers' },
  { key: 'lift',    label: 'Lifts' },
  { key: 'case',    label: 'Cases & Gear' },
  { key: 'kit',     label: 'Kits / Limited Stock' }
];
function _assetTypeLabel(k) { const t = ASSET_TYPES.find(x => x.key === k); return t ? t.label : k; }
function _newAssetId() {
  const rnd = (typeof crypto !== 'undefined' && crypto.randomUUID)
    ? crypto.randomUUID().replace(/-/g, '').slice(0, 12)
    : (Math.random().toString(36).slice(2) + Date.now().toString(36));
  return 'ast_' + rnd;
}
function getAssets(opts) {
  const o = opts || {};
  let list = (state.assets || []);
  if (!o.includeInactive) list = list.filter(a => a.active !== false);
  return list;
}
function getAssetsByType(type, opts) { return getAssets(opts).filter(a => a.type === type); }
function getAssetById(id) { return (state.assets || []).find(a => String(a.id) === String(id)) || null; }
function _ensureAssetsSeed() {
  try { if (localStorage.getItem('vi_assets_seed_v1') === '1') return; } catch (e) {}
  if (!Array.isArray(state.assets)) state.assets = [];
  if (state.assets.length === 0) {
    const seed = [
      ['vehicle', 'F-350'],
      ['vehicle', 'Dodge ProMaster'],
      ['trailer', '24\u2032 Trailer'],
      ['trailer', '22\u2032 Trailer'],
      ['trailer', 'Tilt-Deck Trailer'],
      ['trailer', 'Single-Man-Mast Trailer'],
      ['lift', 'Snorkel Scissor Lift'],
      ['lift', 'Genie 1930 Scissor Lift'],
      ['lift', 'Genie Single-Man Mast'],
      ['lift', 'JLG Single-Man Mast']
    ];
    state.assets = seed.map(([type, name]) => ({ id: _newAssetId(), type, name, active: true, notes: '' }));
    _syncKeyNow('vi_assets', state.assets);
  }
  try { localStorage.setItem('vi_assets_seed_v1', '1'); } catch (e) {}
}
// Top-up batch (cases / kits / ladders / scaff). Add-if-missing by name so it
// won't duplicate; one-time flag so retiring one later sticks.
function _ensureNewAssets() {
  try { if (localStorage.getItem('vi_assets_seed_v2') === '1') return; } catch (e) {}
  if (!Array.isArray(state.assets)) state.assets = [];
  const NEW = [
    ['case', 'Toolkit 1A'], ['case', 'Toolkit 1B'], ['case', 'Toolkit 1C'],
    ['case', 'Toolkit 2A'], ['case', 'Toolkit 2B'], ['case', 'Toolkit 2C'],
    ['case', 'Rigging Trunk 1'],
    ['case', 'Term Kit 1A'], ['case', 'Term Kit 1B'],
    ['case', 'Term Kit 2A'], ['case', 'Term Kit 2B'],
    ['case', 'Paint Kit'],
    ['case', '10 ft Ladder'], ['case', '8 ft Ladder'], ['case', 'Little Giant Ladder'], ['case', 'Small Scaff']
  ];
  const have = new Set((state.assets || []).map(a => (a.name || '').trim().toLowerCase()));
  let added = 0;
  NEW.forEach(([type, name]) => {
    if (have.has(name.toLowerCase())) return;
    state.assets.push({ id: _newAssetId(), type, name, active: true, notes: '' });
    added++;
  });
  try { localStorage.setItem('vi_assets_seed_v2', '1'); } catch (e) {}
  if (added) _syncKeyNow('vi_assets', state.assets);
}
function addAsset({ type, name }) {
  if (!name || !name.trim()) { showToast('Asset needs a name', 'info'); return; }
  if (!Array.isArray(state.assets)) state.assets = [];
  state.assets.push({ id: _newAssetId(), type: type || 'vehicle', name: name.trim(), active: true, notes: '' });
  _syncKeyNow('vi_assets', state.assets).then(r => { if (!r.ok) showToast('Asset didn\u2019t save: ' + r.err, 'error'); });
  renderCurrentPage();
}
function updateAsset(id, patch) {
  const a = getAssetById(id); if (!a) return;
  Object.assign(a, patch);
  _syncKeyNow('vi_assets', state.assets).then(r => { if (!r.ok) showToast('Asset didn\u2019t save: ' + r.err, 'error'); });
  renderCurrentPage();
}
function toggleAssetActive(id) { const a = getAssetById(id); if (!a) return; updateAsset(id, { active: a.active === false }); }
function deleteAsset(id) {
  const a = getAssetById(id); if (!a) return;
  if (!confirm('Remove ' + a.name + ' from assets? (Existing allocations are not changed.)')) return;
  state.assets = (state.assets || []).filter(x => String(x.id) !== String(id));
  _syncKeyNow('vi_assets', state.assets).then(r => { if (!r.ok) showToast('Asset didn\u2019t save: ' + r.err, 'error'); });
  renderCurrentPage();
}
function addAssetFromSettings() {
  const type = document.getElementById('asset-new-type')?.value || 'vehicle';
  const name = document.getElementById('asset-new-name')?.value || '';
  addAsset({ type, name });
}

// ── Asset allocations (per-project) — Drop 2 ──
function _genId(prefix) {
  const rnd = (typeof crypto !== 'undefined' && crypto.randomUUID)
    ? crypto.randomUUID().replace(/-/g, '').slice(0, 12)
    : (Math.random().toString(36).slice(2) + Date.now().toString(36));
  return (prefix || 'id_') + rnd;
}
function _addDaysYmd(ymd, n) {
  const d = _parseLocalYmd(ymd);
  if (!d) return ymd || null;
  return _ymd(_addDays(d, n));
}
function getAllocationsForProject(pid) { return (state.assetAllocations || []).filter(a => String(a.projectId) === String(pid)); }
function getAllocationsForAsset(assetId) { return (state.assetAllocations || []).filter(a => String(a.assetId) === String(assetId)); }
// Committed span = the full time the asset is tied up (prep day → dump day).
function _allocCommitted(a) { return { start: a.start, end: a.end || a.start }; }
function _spansOverlap(s1, e1, s2, e2) { if (!s1 || !e1 || !s2 || !e2) return false; return s1 <= e2 && s2 <= e1; } // ISO YMD compares lexically
// Other allocations of this asset whose committed span overlaps [start,end].
function assetConflicts(assetId, start, end, excludeAllocId) {
  if (!start || !end) return [];
  return getAllocationsForAsset(assetId).filter(a => {
    if (excludeAllocId && String(a.id) === String(excludeAllocId)) return false;
    const c = _allocCommitted(a);
    return _spansOverlap(start, end, c.start, c.end);
  });
}
function _defaultAllocWindow(p) {
  const win = getInstallWindow(p);
  const start = win && win.start ? win.start : null;
  const end = win && win.end ? win.end : start;
  return { start, end };
}
function _persistAllocations() {
  return _syncKeyNow('vi_asset_allocations', state.assetAllocations).then(r => {
    if (!r.ok) showToast('Allocation didn\u2019t save: ' + r.err + ' \u2014 try again', 'error');
    return r;
  });
}
function addAllocation({ projectId, assetId, start, end }) {
  if (!Array.isArray(state.assetAllocations)) state.assetAllocations = [];
  const id = _genId('alloc_');
  state.assetAllocations.push({ id, projectId, assetId, start: start || null, end: end || null, towedBy: null, notes: '' });
  _persistAllocations();
  return id;
}
function updateAllocation(id, patch) {
  const a = (state.assetAllocations || []).find(x => String(x.id) === String(id));
  if (!a) return;
  Object.assign(a, patch);
  _persistAllocations();
  renderCurrentPage();
}
function removeAllocation(id) {
  state.assetAllocations = (state.assetAllocations || []).filter(x => String(x.id) !== String(id));
  _persistAllocations();
  renderCurrentPage();
}

function renderAssetAllocationTab(container, p) {
  const allocs = getAllocationsForProject(p.id);
  const win = getInstallWindow(p);
  const winLabel = win && win.start ? `${fmtDateLocal(win.start)} \u2013 ${fmtDateLocal(win.end || win.start)}` : 'No install window set';
  container.innerHTML = `
    <div class="dashboard-card" style="margin-bottom:14px">
      <div style="display:flex;align-items:center;justify-content:space-between;gap:12px;margin-bottom:8px">
        <div class="dashboard-card-title" style="margin-bottom:0">Asset Allocation</div>
        <button class="btn btn-sm" onclick="openAssetPicker(${p.id})">+ Allocate asset</button>
      </div>
      <div style="font-size:12px;color:#8B949E">Install window: <span style="color:#C9D1D9">${winLabel}</span>. Assets default to the whole job \u2014 narrow the on-site dates below only if one's needed just part of the time. Link a trailer to a truck so they share one drive task.</div>
    </div>
    ${allocs.length ? allocs.map(_renderAllocationRow).join('') : `
      <div class="dashboard-card" style="color:#8B949E;font-size:13px">No assets allocated yet. Tap <strong>+ Allocate asset</strong> to pick vehicles, trailers or lifts for this job.</div>`}
  `;
}
function _renderAllocationRow(a) {
  const asset = getAssetById(a.assetId);
  const name = asset ? asset.name : 'Unknown asset';
  const typeLabel = asset ? _assetTypeLabel(asset.type) : '';
  const conflicts = assetConflicts(a.assetId, a.start, a.end || a.start, a.id);
  const conflictHTML = conflicts.length ? `
    <div style="display:flex;align-items:flex-start;gap:6px;margin-top:8px;padding:6px 8px;background:#2A1A0E;border:1px solid #5A3A1A;border-radius:5px;font-size:11px;color:#F0883E">
      \u26A0 Double-booked: also on ${conflicts.map(c => { const cp = state.projects.find(x => String(x.id) === String(c.projectId)); const cc = _allocCommitted(c); return `${cp ? esc(cp.name) : 'another job'} (${fmtDateLocal(cc.start)}\u2013${fmtDateLocal(cc.end)})`; }).join(', ')}
    </div>` : '';
  const dateField = (label, field, val) => `
    <label style="display:flex;flex-direction:column;gap:2px;font-size:10px;color:#8B949E">${label}
      <input type="date" value="${val || ''}" class="form-input" style="font-size:12px;padding:4px 6px" onchange="updateAllocation('${a.id}',{${field}:this.value||null})">
    </label>`;
  // Trailers can be towed by an allocated truck (shared drive task) or left unlinked (own drive task).
  let towedHTML = '';
  if (asset && asset.type === 'trailer') {
    const vehicleAllocs = getAllocationsForProject(a.projectId).filter(x => { const ax = getAssetById(x.assetId); return ax && ax.type === 'vehicle'; });
    const tow = _trailerTow(a);
    const selVal = tow.mode === 'vehicle' ? String(tow.vehicleAllocId) : 'personal';
    const opts = vehicleAllocs.map(v => { const va = getAssetById(v.assetId); return `<option value="${v.id}" ${selVal === String(v.id) ? 'selected' : ''}>Towed by ${esc(va ? va.name : 'vehicle')}</option>`; })
      .concat([`<option value="personal" ${selVal === 'personal' ? 'selected' : ''}>Own / personal truck (separate drive task)</option>`]);
    towedHTML = `
      <label style="display:flex;flex-direction:column;gap:2px;font-size:10px;color:#8B949E;margin-top:8px">Towing
        <select class="form-input" style="font-size:12px;padding:4px 6px" onchange="updateAllocation('${a.id}',{towedBy:this.value})">${opts.join('')}</select>
      </label>`;
  }
  return `
    <div class="dashboard-card" style="margin-bottom:10px">
      <div style="display:flex;align-items:center;gap:8px;margin-bottom:8px">
        <span style="font-size:10px;font-weight:600;color:#6E7681;text-transform:uppercase;letter-spacing:.05em">${esc(typeLabel)}</span>
        <span style="flex:1;font-size:14px;font-weight:600;color:#E6EDF3">${esc(name)}</span>
        <span style="cursor:pointer;color:#6E7681;font-size:16px;padding:0 4px" title="Remove" onclick="removeAllocation('${a.id}')">\u00D7</span>
      </div>
      <div style="display:grid;grid-template-columns:repeat(2,1fr);gap:8px">
        ${dateField('On-site start', 'start', a.start)}
        ${dateField('On-site end', 'end', a.end)}
      </div>
      ${towedHTML}
      ${conflictHTML}
    </div>`;
}
function openAssetPicker(projectId) {
  const p = state.projects.find(x => String(x.id) === String(projectId));
  if (!p) return;
  document.getElementById('asset-picker')?.remove();
  const overlay = document.createElement('div');
  overlay.id = 'asset-picker';
  overlay.className = 'modal-overlay';
  overlay.onclick = (e) => { if (e.target === overlay) overlay.remove(); };
  overlay.innerHTML = _renderAssetPickerContent(projectId);
  document.body.appendChild(overlay);
}
function _renderAssetPickerContent(projectId) {
  const p = state.projects.find(x => String(x.id) === String(projectId));
  const win = _defaultAllocWindow(p);
  const cand = { start: win.start, end: win.end };
  const haveWindow = !!(cand.start && cand.end);
  const already = new Set(getAllocationsForProject(projectId).map(a => String(a.assetId)));
  const groups = ASSET_TYPES.map(t => {
    const items = getAssetsByType(t.key);
    if (!items.length) return '';
    return `
      <div style="margin-bottom:12px">
        <div style="font-size:11px;font-weight:600;color:#8B949E;margin-bottom:6px">${t.label}</div>
        ${items.map(a => {
          const isAllocated = already.has(String(a.id));
          const conflicts = (haveWindow && !isAllocated) ? assetConflicts(a.id, cand.start, cand.end) : [];
          const busy = conflicts.length > 0;
          let badge;
          if (isAllocated) badge = `<span style="font-size:10px;color:#3FB950">\u2713 Allocated \u00b7 tap to remove</span>`;
          else if (!haveWindow) badge = `<span style="font-size:10px;color:#6E7681">No window set</span>`;
          else if (busy) { const c = conflicts[0]; const cp = state.projects.find(x => String(x.id) === String(c.projectId)); const cc = _allocCommitted(c); badge = `<span style="font-size:10px;color:#F0883E">\u26A0 ${cp ? esc(cp.name) : 'booked'} ${fmtDateLocal(cc.start)}\u2013${fmtDateLocal(cc.end)}</span>`; }
          else badge = `<span style="font-size:10px;color:#3FB950">Available</span>`;
          const clickAttr = isAllocated ? `onclick="_unpickAsset('${projectId}','${a.id}')"` : `onclick="_pickAsset('${projectId}','${a.id}',${busy})"`;
          return `
            <div style="display:flex;align-items:center;gap:8px;padding:8px;background:${isAllocated ? '#0E2A16' : '#0D1117'};border:1px solid ${isAllocated ? '#2EA043' : (busy ? '#5A3A1A' : '#1C2333')};border-radius:5px;margin-bottom:4px;cursor:pointer" ${clickAttr}>
              <span style="flex:1;font-size:13px;color:#E6EDF3">${esc(a.name)}</span>
              ${badge}
            </div>`;
        }).join('')}
      </div>`;
  }).join('');
  return `
    <div class="modal-container" style="max-width:480px;max-height:88vh;display:flex;flex-direction:column">
      <div class="modal-header">
        <div class="modal-title">Allocate assets</div>
        <button class="modal-close" onclick="document.getElementById('asset-picker')?.remove()">&times;</button>
      </div>
      <div class="modal-body" style="overflow-y:auto">
        <div style="font-size:11px;color:#8B949E;margin-bottom:12px">Availability checked for ${haveWindow ? `${fmtDateLocal(cand.start)} \u2013 ${fmtDateLocal(cand.end)}` : 'this job'}. Tap an asset to allocate; adjust dates after.</div>
        ${groups || '<div style="color:#8B949E;font-size:13px">No assets yet \u2014 add them in Settings.</div>'}
      </div>
    </div>`;
}
function _pickAsset(projectId, assetId, busy) {
  const p = state.projects.find(x => String(x.id) === String(projectId));
  if (!p) return;
  const asset = getAssetById(assetId);
  if (busy && !confirm(`${asset ? asset.name : 'This asset'} is already allocated to another job on overlapping dates. Allocate anyway?`)) return;
  const win = _defaultAllocWindow(p);
  addAllocation({ projectId: p.id, assetId, start: win.start, end: win.end });
  const overlay = document.getElementById('asset-picker');
  if (overlay) overlay.querySelector('.modal-container').outerHTML = _renderAssetPickerContent(projectId);
  renderCurrentPage();
}
function _unpickAsset(projectId, assetId) {
  state.assetAllocations = (state.assetAllocations || []).filter(a => !(String(a.projectId) === String(projectId) && String(a.assetId) === String(assetId)));
  _persistAllocations();
  const overlay = document.getElementById('asset-picker');
  if (overlay) overlay.querySelector('.modal-container').outerHTML = _renderAssetPickerContent(projectId);
  renderCurrentPage();
}

// ── Job logistics (Drop 3): per-job dates + derived assignable tasks + pack list ──
function _isInstallJob(p) {
  if (!p) return false;
  if (['install', 'commissioning', 'signoff', 'sign_off'].includes(p.stage)) return true;
  if (getInstallWindow(p)) return true;
  return getAllocationsForProject(p.id).length > 0;
}
function _logiDefaults(p) {
  const win = getInstallWindow(p);
  const s = win && win.start ? win.start : null;
  const e = win && win.end ? win.end : s;
  return { prep: s, load: s, unload: e, deprep: e };
}
function getLogisticsRecord(pid) { return (state.logistics || {})[pid] || null; }
function getLogisticsDates(p) {
  const rec = getLogisticsRecord(p.id);
  const def = _logiDefaults(p);
  const d = (rec && rec.dates) ? rec.dates : {};
  return { prep: d.prep || def.prep, load: d.load || def.load, unload: d.unload || def.unload, deprep: d.deprep || def.deprep };
}
function _ensureLogiRec(pid) {
  if (!state.logistics) state.logistics = {};
  if (!state.logistics[pid]) state.logistics[pid] = { dates: {}, items: {}, picklist: {} };
  const r = state.logistics[pid];
  if (!r.dates) r.dates = {};
  if (!r.items) r.items = {};
  if (!r.picklist) r.picklist = {};
  return r;
}
function _persistLogistics() {
  return _syncKeyNow('vi_logistics', state.logistics).then(r => {
    if (!r.ok) showToast('Logistics didn\u2019t save: ' + r.err + ' \u2014 try again', 'error');
    return r;
  });
}
function setLogisticsDate(pid, field, val) { const r = _ensureLogiRec(pid); r.dates[field] = val || null; _persistLogistics(); renderCurrentPage(); }
function getLogisticsItem(pid, key) { const r = getLogisticsRecord(pid); return (r && r.items && r.items[key]) ? r.items[key] : { assigneeIds: [] }; }
function setLogisticsItemAssignees(pid, key, ids) {
  const r = _ensureLogiRec(pid);
  if (!r.items[key]) r.items[key] = { assigneeIds: [] };
  r.items[key].assigneeIds = (ids || []).filter(x => x != null);
  if (typeof ensureOnProjectCrew === 'function' && r.items[key].assigneeIds.length) ensureOnProjectCrew(pid, r.items[key].assigneeIds);
  _persistLogistics(); renderCurrentPage();
}
function setLogisticsItem(pid, key, patch) {
  const r = _ensureLogiRec(pid);
  if (!r.items[key]) r.items[key] = { assigneeIds: [] };
  Object.assign(r.items[key], patch);
  if (Array.isArray(patch.assigneeIds) && patch.assigneeIds.length && typeof ensureOnProjectCrew === 'function') ensureOnProjectCrew(pid, patch.assigneeIds);
  _persistLogistics(); renderCurrentPage();
}
function toggleLogisticsStarted(pid, key) { const r = _ensureLogiRec(pid); if (!r.items[key]) r.items[key] = { assigneeIds: [] }; _applyStarted(r.items[key]); _persistLogistics(); renderCurrentPage(); }
function toggleLogisticsDone(pid, key) { const r = _ensureLogiRec(pid); if (!r.items[key]) r.items[key] = { assigneeIds: [] }; _applyDone(r.items[key]); _persistLogistics(); renderCurrentPage(); }
function toggleLogisticsPacked(pid, allocId) {
  const r = _ensureLogiRec(pid);
  const cur = r.picklist[allocId] || {};
  r.picklist[allocId] = cur.packed ? { packed: false } : { packed: true, packedAt: new Date().toISOString(), packedBy: _whoNow() };
  _persistLogistics(); renderCurrentPage();
}
// Resolve how a trailer travels. Default (unset towedBy) = towed by the first
// allocated truck; 'personal' is an explicit, rare choice; an allocId pins a truck.
function _trailerTow(a) {
  const vehicles = getAllocationsForProject(a.projectId).filter(x => { const ax = getAssetById(x.assetId); return ax && ax.type === 'vehicle'; });
  if (a.towedBy === 'personal') return { mode: 'personal' };
  if (a.towedBy && vehicles.some(v => String(v.id) === String(a.towedBy))) return { mode: 'vehicle', vehicleAllocId: a.towedBy };
  if (vehicles.length) return { mode: 'vehicle', vehicleAllocId: vehicles[0].id };
  return { mode: 'personal' };
}
// Rigs needing a driver: each allocated truck (noting trailers it tows) + each
// trailer set to personal-truck tow.
function getLogisticsRigs(pid) {
  const allocs = getAllocationsForProject(pid);
  const vehicles = allocs.filter(a => { const x = getAssetById(a.assetId); return x && x.type === 'vehicle'; });
  const trailers = allocs.filter(a => { const x = getAssetById(a.assetId); return x && x.type === 'trailer'; });
  const rigs = [];
  vehicles.forEach(v => {
    const vname = (getAssetById(v.assetId) || {}).name || 'Vehicle';
    const towed = trailers.filter(t => { const tow = _trailerTow(t); return tow.mode === 'vehicle' && String(tow.vehicleAllocId) === String(v.id); })
      .map(t => (getAssetById(t.assetId) || {}).name).filter(Boolean);
    rigs.push({ id: v.id, label: vname + (towed.length ? ' + ' + towed.join(' + ') : '') });
  });
  trailers.forEach(t => { if (_trailerTow(t).mode === 'personal') { const tn = (getAssetById(t.assetId) || {}).name || 'Trailer'; rigs.push({ id: t.id, label: tn + ' (personal truck)' }); } });
  return rigs;
}
function _toggleLogiPack(pid) {
  if (!window._logiPackOpen) window._logiPackOpen = {};
  window._logiPackOpen[pid] = !window._logiPackOpen[pid];
  renderCurrentPage();
}
function _logiSectionOpen(pid, key) { return !!(window._logiOpen && window._logiOpen[pid + ':' + key]); }
function _toggleLogiSection(pid, key) {
  if (!window._logiOpen) window._logiOpen = {};
  const k = pid + ':' + key;
  window._logiOpen[k] = !window._logiOpen[k];
  renderCurrentPage();
}
// Dated logistics items for calendar surfacing: prep/load/unload/de-prep + per-rig drives.
function getLogisticsCalItems(p) {
  if (!_isInstallJob(p)) return [];
  const dates = getLogisticsDates(p);
  const items = [];
  const push = (key, title, date) => { if (date) { const it = getLogisticsItem(p.id, key); items.push({ key, title, date, time: it.time || null, assigneeIds: (it.assigneeIds || []).slice(), done: !!it.done }); } };
  push('prep', 'Prep', dates.prep);
  push('load', 'Load', dates.load);
  const win = getInstallWindow(p);
  const driveOutDate = win && win.start ? win.start : dates.load;
  const driveBackDate = win && win.end ? win.end : dates.deprep;
  getLogisticsRigs(p.id).forEach(r => push('drive_out_' + r.id, 'Drive to job — ' + r.label, driveOutDate));
  push('load_in', 'Load in', win && win.start ? win.start : dates.load);
  push('load_out', 'Load out', win && win.end ? win.end : dates.deprep);
  getLogisticsRigs(p.id).forEach(r => push('drive_back_' + r.id, 'Drive back — ' + r.label, driveBackDate));
  push('unload', 'Unload', dates.unload);
  push('deprep', 'De-prep', dates.deprep);
  return items;
}
function openLogisticsDaySheet(projectId, dateStr) {
  const p = (state.projects || []).find(x => String(x.id) === String(projectId));
  if (!p) return;
  const items = getLogisticsCalItems(p).filter(it => it.date === dateStr);
  document.getElementById('logi-day-sheet')?.remove();
  const rows = items.length ? items.map(it => {
    const names = (it.assigneeIds || []).map(id => (getTeamMember(id) || {}).name).filter(Boolean).map(n => n.split(' ')[0]).join(', ') || 'Unassigned';
    return `<div style="display:flex;align-items:flex-start;gap:8px;padding:8px 0;border-bottom:1px solid #1C2333">
      <span style="flex-shrink:0;width:16px;height:16px;border-radius:4px;border:1.5px solid ${it.done ? '#2EA043' : '#30363D'};background:${it.done ? '#238636' : 'transparent'};color:#fff;display:flex;align-items:center;justify-content:center;font-size:11px;margin-top:1px">${it.done ? '✓' : ''}</span>
      <div style="flex:1;min-width:0">
        <div style="font-size:13px;font-weight:600;color:#E6EDF3">${esc(it.title)}${it.time ? ' · ' + esc(_fmtTime12(it.time)) : ''}</div>
        <div style="font-size:11px;color:#8B949E;margin-top:1px">${esc(names)}</div>
      </div>
    </div>`;
  }).join('') : '<div style="color:#8B949E;font-size:13px;padding:8px 0">No logistics for this day.</div>';
  const overlay = document.createElement('div');
  overlay.id = 'logi-day-sheet';
  overlay.className = 'modal-overlay';
  overlay.style.zIndex = '10002';
  overlay.onclick = (e) => { if (e.target === overlay) overlay.remove(); };
  overlay.innerHTML = `
    <div class="modal-container" style="max-width:440px;max-height:80vh;display:flex;flex-direction:column">
      <div class="modal-header">
        <div class="modal-title">Logistics · ${esc(fmtDateLocal(dateStr))}</div>
        <button class="modal-close" onclick="document.getElementById('logi-day-sheet')?.remove()">&times;</button>
      </div>
      <div class="modal-body" style="overflow-y:auto">
        <div style="font-size:12px;color:#8B949E;margin-bottom:6px">${esc(p.client_name || p.name)}</div>
        ${rows}
      </div>
      <div style="padding:12px;border-top:1px solid #1C2333;display:flex;justify-content:flex-end">
        <button class="btn btn-sm btn-primary" onclick="document.getElementById('logi-day-sheet')?.remove();openProject(${projectId},'install')">Open job</button>
      </div>
    </div>`;
  document.body.appendChild(overlay);
}
function _logiAssigneeChips(ids) {
  if (!ids || !ids.length) return '<span class="itask-unassigned">Unassigned</span>';
  return ids.map(id => {
    const m = getTeamMember(id);
    if (!m) return '';
    const memberColor = (DASHBOARD_ACCESS.find(d => d.key === m.primaryRole) || {}).color || '#6E7681';
    const initials = m.initials || (m.name || '').slice(0, 2).toUpperCase();
    const first = (m.name || '').split(' ')[0];
    return `<span class="itask-assignee-chipv2" title="${esc(m.name)}">
      <span class="itask-assignee-badge" style="background:${memberColor}22;border-color:${memberColor};color:${memberColor}">${esc(initials)}</span>
      <span class="itask-assignee-name">${esc(first)}</span>
    </span>`;
  }).join('');
}
function openLogisticsAssignPicker(pid, key) {
  const it = getLogisticsItem(pid, key);
  const current = new Set((it.assigneeIds || []).map(String));
  const crew = getProjectAssignment(pid) || {};
  const crewIds = new Set([...((crew.install || []).map(x => x.id)), ...((crew.pm || []).map(x => x.id))]);
  const pool = [...(state.team || [])].sort((a, b) => { const ao = crewIds.has(a.id) ? 0 : 1, bo = crewIds.has(b.id) ? 0 : 1; return ao !== bo ? ao - bo : a.name.localeCompare(b.name); });
  document.getElementById('logi-assign')?.remove();
  const overlay = document.createElement('div');
  overlay.id = 'logi-assign';
  overlay.className = 'modal-overlay';
  overlay.style.zIndex = '10001';
  overlay.onclick = (e) => { if (e.target === overlay) overlay.remove(); };
  overlay.innerHTML = `
    <div class="modal-container" style="max-width:420px;max-height:80vh;display:flex;flex-direction:column">
      <div class="modal-header"><div class="modal-title">Assign people</div><button class="modal-close" onclick="document.getElementById('logi-assign')?.remove()">&times;</button></div>
      <div class="modal-body" style="overflow-y:auto">
        <label class="form-label form-label-sm">Time (optional)</label>
        <input type="time" id="logi-assign-time" class="form-input" value="${esc(it.time || '')}" style="margin-bottom:12px">
        <div class="itask-assignee-pick">
          ${pool.map(m => `
            <label class="itask-assignee-chip">
              <input type="checkbox" class="logi-assign-cb" value="${m.id}" ${current.has(String(m.id)) ? 'checked' : ''}>
              <span>${esc(m.name)}${crewIds.has(m.id) ? '' : ' <span style="font-size:9px;color:#D29922">(not on crew)</span>'}</span>
            </label>`).join('')}
        </div>
      </div>
      <div style="padding:12px;border-top:1px solid #1C2333;display:flex;justify-content:flex-end;gap:8px">
        <button class="btn btn-sm" onclick="document.getElementById('logi-assign')?.remove()">Cancel</button>
        <button class="btn btn-sm btn-primary" onclick="_saveLogiAssign(${pid},'${key}')">Save</button>
      </div>
    </div>`;
  document.body.appendChild(overlay);
}
function _saveLogiAssign(pid, key) {
  const ids = Array.from(document.querySelectorAll('.logi-assign-cb:checked')).map(cb => parseInt(cb.value, 10)).filter(n => !isNaN(n));
  const timeEl = document.getElementById('logi-assign-time');
  const time = timeEl ? (timeEl.value || null) : null;
  document.getElementById('logi-assign')?.remove();
  setLogisticsItem(pid, key, { assigneeIds: ids, time });
}
function renderLogisticsCard(p) {
  if (!_isInstallJob(p)) return '';
  const dates = getLogisticsDates(p);
  const rigs = getLogisticsRigs(p.id);
  const cases = getAllocationsForProject(p.id).filter(a => { const x = getAssetById(a.assetId); return x && (x.type === 'case' || x.type === 'kit'); });
  const rec = getLogisticsRecord(p.id);

  const dateInput = (label, field) => `
    <label style="display:flex;flex-direction:column;gap:2px;font-size:10px;color:#8B949E">${label}
      <input type="date" value="${dates[field] || ''}" class="form-input" style="font-size:12px;padding:4px 6px" onchange="setLogisticsDate(${p.id},'${field}',this.value||null)">
    </label>`;

  const taskRow = (key, title, dateStr, extra) => {
    const it = getLogisticsItem(p.id, key);
    const started = !!it.started, done = !!it.done;
    return `
      <div class="itask-sub${done ? ' is-done' : ''}">
        <span class="itask-check" onclick="event.stopPropagation();toggleLogisticsDone(${p.id},'${key}')">${done ? '✓' : ''}</span>
        <div class="itask-sub-body" onclick="openLogisticsAssignPicker(${p.id},'${key}')">
          <div class="itask-sub-title">${esc(title)}</div>
          <div class="itask-sub-meta">
            ${dateStr ? esc(fmtDateLocal(dateStr)) : '<span class="itask-nodate">No date</span>'}${it.time ? ' · ' + esc(_fmtTime12(it.time)) : ''}
            <span class="itask-sub-assignees">${_logiAssigneeChips(it.assigneeIds)}</span>
          </div>
          ${_subStatusMetaHTML(it)}
          ${extra || ''}
        </div>
        <button onclick="event.stopPropagation();toggleLogisticsStarted(${p.id},'${key}')" title="${started ? 'Mark not started' : 'Mark started'}" style="flex-shrink:0;align-self:flex-start;font-size:10px;padding:3px 8px;border-radius:999px;border:1px solid ${started ? '#2EA043' : '#30363D'};background:${started ? '#0E2A16' : 'transparent'};color:${started ? '#3FB950' : '#8B949E'};cursor:pointer;white-space:nowrap">${started ? '● Started' : '▶ Start'}</button>
      </div>`;
  };

  const packTotal = cases.length;
  const packedCount = cases.filter(c => { const pk = (rec && rec.picklist && rec.picklist[c.id]) || {}; return pk.packed; }).length;
  const packOpen = !!(window._logiPackOpen && window._logiPackOpen[p.id]);
  const picklistHTML = packTotal ? `
    <div style="margin-top:5px">
      <div onclick="event.stopPropagation();_toggleLogiPack(${p.id})" style="display:inline-flex;align-items:center;gap:5px;cursor:pointer;font-size:11px;font-weight:600;color:${packedCount === packTotal ? '#3FB950' : '#8B949E'};user-select:none">
        <span style="display:inline-block;transform:rotate(${packOpen ? 90 : 0}deg);transition:transform .1s">▸</span>Pack list · ${packedCount}/${packTotal} packed
      </div>
      ${packOpen ? `<div style="margin-top:3px;padding-left:4px">${cases.map(c => {
        const asset = getAssetById(c.assetId);
        const pk = (rec && rec.picklist && rec.picklist[c.id]) ? rec.picklist[c.id] : {};
        return `<label style="display:flex;align-items:center;gap:8px;font-size:12px;color:${pk.packed ? '#6E7681' : '#C9D1D9'};padding:2px 0;cursor:pointer">
          <input type="checkbox" ${pk.packed ? 'checked' : ''} onchange="event.stopPropagation();toggleLogisticsPacked(${p.id},'${c.id}')">
          <span style="${pk.packed ? 'text-decoration:line-through' : ''}">${esc(asset ? asset.name : 'Item')}</span>
        </label>`;
      }).join('')}</div>` : ''}
    </div>`
    : '<div style="margin-top:5px;font-size:11px;color:#6E7681">No Cases &amp; Gear allocated — add them on the Assets tab.</div>';

  const _win = getInstallWindow(p);
  const _onsiteStart = _win && _win.start ? _win.start : dates.load;
  const _onsiteEnd = _win && _win.end ? _win.end : dates.deprep;
  const driveOut = rigs.map(r => taskRow('drive_out_' + r.id, 'Drive to job — ' + r.label, _onsiteStart)).join('');
  const driveBack = rigs.map(r => taskRow('drive_back_' + r.id, 'Drive back — ' + r.label, _onsiteEnd)).join('');
  const noRigsNote = '<div style="font-size:11px;color:#6E7681">No vehicles/trailers allocated — add them on the Assets tab to get drive tasks.</div>';
  const win = getInstallWindow(p);
  const onsiteStart = win && win.start ? win.start : dates.load;
  const onsiteEnd = win && win.end ? win.end : dates.deprep;

  const doneOf = keys => { const t = keys.length; const d = keys.filter(k => getLogisticsItem(p.id, k).done).length; return t ? `${d}/${t} done` : ''; };
  const driveOutKeys = rigs.map(r => 'drive_out_' + r.id);
  const driveBackKeys = rigs.map(r => 'drive_back_' + r.id);

  const section = (skey, title, bodyHTML, summary) => {
    const open = _logiSectionOpen(p.id, skey);
    return `
      <div style="border:1px solid #1C2333;border-radius:6px;margin-bottom:6px;overflow:hidden">
        <div onclick="_toggleLogiSection(${p.id},'${skey}')" style="display:flex;align-items:center;gap:8px;padding:8px 10px;cursor:pointer;user-select:none;background:#0D1117">
          <span style="display:inline-block;transform:rotate(${open ? 90 : 0}deg);transition:transform .1s;color:#8B949E">▸</span>
          <span style="flex:1;font-size:13px;font-weight:700;color:#E6EDF3">${esc(title)}</span>
          <span style="font-size:10px;color:#8B949E">${summary || ''}</span>
        </div>
        ${open ? `<div style="padding:6px 8px 8px">${bodyHTML}</div>` : ''}
      </div>`;
  };

  return `
    <div class="dashboard-card" style="margin-bottom:14px;background:#1A1509;border:1px solid #4A3A14;border-left:3px solid #C9962B">
      <div class="dashboard-card-title" style="margin-bottom:8px;color:#E6C77A;display:flex;align-items:center;gap:7px">🚛 Logistics</div>
      <div style="display:grid;grid-template-columns:repeat(2,1fr);gap:8px;margin-bottom:10px">
        ${dateInput('Prep day', 'prep')}
        ${dateInput('Load day', 'load')}
        ${dateInput('Unload day', 'unload')}
        ${dateInput('De-prep day', 'deprep')}
      </div>
      ${section('prep_load', 'Prep & Load', taskRow('prep', 'Prep', dates.prep, picklistHTML) + taskRow('load', 'Load', dates.load), doneOf(['prep', 'load']))}
      ${section('drive_out', 'Drive to job', rigs.length ? driveOut : noRigsNote, doneOf(driveOutKeys))}
      ${section('loadinout', 'Load in & Load out', taskRow('load_in', 'Load in', onsiteStart) + taskRow('load_out', 'Load out', onsiteEnd), doneOf(['load_in', 'load_out']))}
      ${section('drive_back', 'Drive back', rigs.length ? driveBack : noRigsNote, doneOf(driveBackKeys))}
      ${section('unload_deprep', 'Unload & De-prep', taskRow('unload', 'Unload', dates.unload) + taskRow('deprep', 'De-prep', dates.deprep), doneOf(['unload', 'deprep']))}
    </div>`;
}

